/* ===== WEEK 1 ===== */
const week1={
Monday:g("Naming Words & My First Word Upgrade","Writing — Vocabulary & Sentence Structure, NZC Phase 1 (Yrs 0–3): students name objects and begin selecting a more precise word in place of an overused one.",
{title:"I Do — Naming Words, and a Better Word",instruction:"First, watch me find naming words for things in our classroom. Then watch me upgrade a boring word to a more interesting one.",example:"The **book** is **good**. → The **book** is **exciting**.",demonstration:'"Book" is a naming word — it names a thing. Now look at "good" — it is boring. I can swap it: **happy**, **excited**, **fantastic**. "The book is exciting" tells the reader so much more!',tip:'Ask: does this naming word tell us what it is? Does this describing word tell us something interesting, or is it boring like "good"?'},
{title:"We Do — Name It & Upgrade It",instruction:"Let's find the naming words in these sentences together, then upgrade the boring word.",sentences:["The **dog** is **good** at running.","My **friend** is **nice** to everyone.","The **day** was **good** for playing outside."],prompt:'What is the naming word? What could replace "good" or "nice" to make it more interesting?'},
{title:"You Do — Your Turn",instruction:"Find the naming word in each sentence, then upgrade the boring describing word.",tasks:["The **cake** was **good**.","My **teacher** is **nice**.","The **game** was **good** fun.","✦ Bonus: Write one sentence with a naming word AND an upgraded describing word — no \"good\" or \"nice\" allowed!"]},
[{code:"Writing — Vocabulary (Knowledge)",label:"Upgrading overused words",detail:"NZC Phase 1: students begin to recognise overused words (good, nice) and select a more precise alternative, as an early step toward Tier 2 vocabulary work in Phase 2."},{code:"Writing — Sentence Structure (Knowledge)",label:"Identifying naming words",detail:"NZC Phase 1: students identify nouns as naming words, consolidating Phase 1 knowledge before Phase 2 grammar work begins."}],
{context:ctx("Word Choice Foundations","1 of 40","Years 3–4 (ages 7–9)","25–30 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:["Vocabulary: begin recognising and replacing overused words (good, nice, big).","Sentence Structure: consolidate naming words (nouns).","Communication: offer word-upgrade suggestions aloud.","Metacognition: notice when a word choice feels boring versus interesting."],walt:["We are learning to spot naming words for things we can see.","We are learning to notice when a word like 'good' or 'nice' is boring.","We are learning to upgrade a boring word to a more interesting one."],successCriteria:["I can point to and name objects in the classroom.","I can spot an overused word like 'good' in a sentence.","I can suggest a more interesting word to replace it."],timing:[{time:"0–7m",title:"Naming Game + First Upgrade",phase:"I Do",description:"Teacher names classroom objects, then demonstrates upgrading 'good'. Word bank poster displayed."},{time:"7–14m",title:"Point, Name & Upgrade",phase:"We Do",description:"Whole class works through 3 sentences. Sentence frame and buddy pairing."},{time:"14–22m",title:"My Upgrades",phase:"You Do",description:"Students complete 3 upgrade sentences. Image word bank for emerging writers."},{time:"22–28m",title:"Share & Celebrate",phase:"Reflect",description:"Students share their best upgraded word. Close with a line of thanks using an upgraded word."}],resources:["5–6 real classroom objects","Word-upgrade bank poster","Picture + word cards for ESOL","Worksheet with 3 sentences"],assessment:["Formative: accuracy of naming and quality of upgrade suggestions","Work sample: 3 completed upgrade sentences"],differentiation:[{label:"ESOL learners",note:"Object + picture + printed word together; image word bank; buddy pairing."},{label:"Emerging writers",note:"Sentence frame and image-supported word bank; dictation option."},{label:"Confident writers",note:"No-word-bank bonus sentence; compare two upgrade options."},{label:"Diverse learners",note:"Movement built into the naming game; option to point/show a word card."}],valuesIntegration:{heading:"Aroha & Mōhio",notes:["Naming and appreciating the things around us reflects Aroha (love for God's world) and Mōhio (knowing what God has given us).","Close with a shared line of thanks using one of the upgraded words."]},reflectionPrompts:["Could most students name objects AND suggest a real word upgrade?","Which upgrade words are worth adding to the class word wall?"]},"Aroha"),
Tuesday:g("Capital Letters for \"I\" and Names","Writing — Punctuation (Knowledge & Practice), NZC Phase 1 (Yrs 0–3): capital letters for the word \"I\" and for names of specific people.",
{title:'I Do — The Letter That\'s Always Big',instruction:'The word "I" is always written as a big capital letter. Names of people always have capital letters too.',example:'**i** went to the park with mum and **Jake**.',demonstration:'"i" — that\'s me, always a capital **I**. "Jake" — a person\'s name, capital **J**. Fixed: "**I** went to the park with mum and **Jake**."',tip:'Whenever you write about yourself, "I" is always BIG — even in the middle of a sentence.'},
{title:"We Do — Find the Capitals",instruction:"Let's find every word that needs a capital letter in these sentences.",sentences:["**i** play with my friend **lily** at school.","my dog **ben** likes to chase me and **sam**.","**i** went to **nana's** house with dad."],prompt:'Which words are names? Where is the word "I"? Do they have capitals?'},
{title:"You Do — Your Turn",instruction:"Rewrite each sentence, fixing every missing capital letter.",tasks:["**i** like to play with **mia** at lunchtime.","my brother **noah** helped me find my shoe.","**i** went to the shop with **grandpa**.","✦ Bonus: Write one sentence about you and a friend. Remember capitals for \"I\" and their name!"]},
[{code:"Writing — Punctuation (Knowledge)",label:"Capital I & proper nouns",detail:'NZC Phase 1: students learn that the pronoun "I" is always capitalised and names of specific people require a capital letter.'},{code:"Writing — Punctuation (Practice)",label:"Applying capitals consistently",detail:'NZC Phase 1: students apply capitalisation to "I" and to names with increasing independence.'}],
{context:ctx("Word Choice Foundations","2 of 40","Years 3–4 (ages 7–9)","25–30 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:['Punctuation: "I" and names of specific people always begin with a capital letter.',"Distinguish names (proper nouns) from other naming words.","Metacognition: begin self-checking own writing for this convention."],walt:['We are learning that the word "I" is always a capital letter.',"We are learning that people's names always start with a capital letter.","We are learning to find and fix missing capitals in a sentence."],successCriteria:['I can write "I" as a capital letter every time.',"I can spot a person's name and give it a capital letter.","I can find a missing capital letter in a sentence."],timing:[{time:"0–7m",title:"Capital I Hunt",phase:"I Do",description:'Teacher writes sentences with lower-case "i"; students spot mistakes.'},{time:"7–14m",title:"Fix the Sentence",phase:"We Do",description:"Whole class calls out which words need capitals. Visual cue card: 'I' standing tall."},{time:"14–22m",title:"My Fix-It Sentences",phase:"You Do",description:"Students complete worksheet of 3 sentences."},{time:"22–28m",title:"Share & Reflect",phase:"Reflect",description:"Share a fixed sentence. Tie-in: every person is known and named by God."}],resources:["Whiteboard sentences with errors","Capital-I visual cue card","Fix-it worksheet"],assessment:["Formative: accuracy during whole-class capital hunt","Work sample: completed fix-it worksheet"],differentiation:[{label:"ESOL learners",note:'Visual cue card; oral rehearsal; buddy pairing.'},{label:"Emerging writers",note:"Tracing/copy support; dictation option."},{label:"Confident writers",note:'Write 2 original sentences using "I" and a friend\'s name.'},{label:"Diverse learners",note:'Physical "stand tall" movement cue when saying "I".'}],valuesIntegration:{heading:"Mōhio — Know",notes:["Capitalising our own name and 'I' reminds us each person is known and named individually.","Every name in the room is worth a capital letter, because every person matters."]},reflectionPrompts:["Could most students apply the capital-I rule confidently?","Which names should join the class word wall?"]},"Mōhio"),
Wednesday:g("What Makes a Sentence: Who + Did What","Writing — Sentence Structure (Knowledge & Practice), NZC Phase 1 (Yrs 0–3): a sentence names someone or something and tells what they did.",
{title:"I Do — A Sentence Needs Two Jobs",instruction:"A sentence needs two jobs done: it tells us WHO or WHAT, and it tells us what they DID. Watch me build one piece by piece.",example:"**The dog** | **ran**.",demonstration:'"The dog" tells us **WHO**. "ran" tells us **what it did**. Together: "The dog ran." — it makes sense all by itself!',tip:"Ask: does it tell me WHO or WHAT, AND does it tell me what they DID? If both — it's a sentence!"},
{title:"We Do — Build It Together",instruction:"Let's build sentences together by matching a WHO with a DID WHAT.",sentences:["WHO: **The cat** | DID WHAT: **jumped**","WHO: **My friend** | DID WHAT: **laughed**","WHO: **The ball** | DID WHAT: **bounced**"],prompt:"Can you say the whole sentence out loud? Does it make sense on its own?"},
{title:"You Do — Your Turn",instruction:"Match a WHO with a DID WHAT to build 3 complete sentences. Capital letter and full stop!",tasks:["Build a sentence about a **bird**.","Build a sentence about your **friend**.","Build a sentence about the **sun**.","✦ Bonus: Write a sentence about something you did this morning."]},
[{code:"Writing — Sentence Structure (Knowledge)",label:"Sentences need a subject and a verb",detail:"NZC Phase 1: students learn that a complete sentence names someone or something (subject) and tells what they did (verb)."},{code:"Writing — Sentence Structure (Practice)",label:"Constructing simple sentences",detail:"NZC Phase 1: students construct grammatically complete simple sentences orally and in writing."}],
{context:ctx("Word Choice Foundations","3 of 40","Years 3–4 (ages 7–9)","25–30 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:["Sentence Structure: a sentence needs a subject and a verb.","Grammar: pair naming words with action words.","Orally rehearse sentences before writing."],walt:["We are learning that a sentence tells us who or what, and what they did.","We are learning to build a complete sentence from two parts.","We are learning to check if a sentence is finished."],successCriteria:["I can point to the WHO part of a sentence.","I can point to the DID WHAT part of a sentence.","I can build my own complete sentence with both parts."],timing:[{time:"0–7m",title:"Two-Job Sentences",phase:"I Do",description:"Teacher separates a sentence into WHO and DID WHAT cards, then slides them together."},{time:"7–14m",title:"Match & Build",phase:"We Do",description:"Whole class matches WHO cards to DID WHAT cards, reading aloud each time."},{time:"14–22m",title:"My Own Sentences",phase:"You Do",description:"Students build 3 sentences from word banks."},{time:"22–28m",title:"Read & Check",phase:"Reflect",description:"Students read one sentence to a partner who checks for WHO + DID WHAT."}],resources:["WHO and DID WHAT word/picture cards","Sentence frame display","Worksheet with word banks"],assessment:["Formative: accuracy of card-matching","Work sample: 3 self-built sentences"],differentiation:[{label:"ESOL learners",note:"Picture + word cards; oral rehearsal; buddy support."},{label:"Emerging writers",note:"Physically arrange cards before copying; tracing strips."},{label:"Confident writers",note:"Build a 4th sentence independently, no word bank."},{label:"Diverse learners",note:"Physical card-sliding movement."}],valuesIntegration:{heading:"Mōhio — Know",notes:["Saying something true and complete about the world is a step in knowing what God has made.","Every sentence built today is a true statement about the world."]},reflectionPrompts:["Could most students explain why a sentence needs both parts?","Is the class ready to add WHERE next week?"]},"Mōhio"),
Thursday:g("Reading My Sentence Aloud — Does It Sound Finished?","Writing — Writing Process (Knowledge & Practice), NZC Phase 1 (Yrs 0–3): students reread their own writing aloud to check it makes sense.",
{title:"I Do — Listen to Your Own Writing",instruction:"The best way to check a sentence is to read it out loud and listen. Watch me check this sentence.",example:"**the** bird flew away",demonstration:'I read it aloud: "the bird flew away." Sounds finished? Yes! But no **capital**, no **full stop**. Fix: "**The** bird flew away."',tip:"Read your sentence out loud. If it sounds finished, check: capital at the start, full stop at the end?"},
{title:"We Do — Check Together",instruction:"Let's read these sentences aloud together and check them for capitals and full stops.",sentences:["**my** dog likes to play","We went to the park","**the** sun was shining today"],prompt:"Does it sound finished when we read it aloud? What's missing?"},
{title:"You Do — Your Turn",instruction:"Read each sentence aloud to yourself, then fix any missing capitals or full stops.",tasks:["**i** like to read books","**the** cat sat on the mat","My friend came to play","✦ Bonus: Read your Wednesday sentences aloud again — are they all fixed and finished?"]},
[{code:"Writing — Writing Process (Knowledge)",label:"Reading aloud to check writing",detail:"NZC Phase 1: reading their own writing aloud is a reliable way to check a sentence is complete."},{code:"Writing — Writing Process (Practice)",label:"Self-checking capitals and full stops",detail:"NZC Phase 1: students reread and check their own writing for correct capitalisation and end punctuation."}],
{context:ctx("Word Choice Foundations","4 of 40","Years 3–4 (ages 7–9)","25–30 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:["Writing Process: reread writing aloud to check it makes sense.","Punctuation: check for capital letters and full stops.","Read own writing aloud to a partner."],walt:["We are learning to read our own writing out loud.","We are learning to listen for whether a sentence sounds finished.","We are learning to check for a capital letter and a full stop."],successCriteria:["I can read my sentence aloud clearly.","I can say whether my sentence sounds finished.","I can check and fix a missing capital or full stop."],timing:[{time:"0–7m",title:"Listen to Me Check",phase:"I Do",description:"Teacher reads a sentence aloud, modelling the listening pause. Hand-to-ear gesture."},{time:"7–14m",title:"Read & Fix Together",phase:"We Do",description:"Whole class reads chorally, then fixes missing punctuation. Buddy reading."},{time:"14–22m",title:"My Checking Turn",phase:"You Do",description:"Students read 3 sentences aloud and fix punctuation."},{time:"22–28m",title:"Partner Read & Praise",phase:"Reflect",description:"Students read a fixed sentence to a partner who gives kind, specific feedback."}],resources:["Hand-to-ear listening-check cue card","Worksheet with 3 sentences"],assessment:["Formative: participation and accuracy in choral reading","Work sample: 3 corrected sentences"],differentiation:[{label:"ESOL learners",note:"Buddy reading; large dyslexia-friendly font; visual listening cue."},{label:"Emerging writers",note:"Partner/teacher reads alongside."},{label:"Confident writers",note:"Apply the check to their own earlier writing."},{label:"Diverse learners",note:"Hand-to-ear gesture supports movement-paired learning."}],valuesIntegration:{heading:"Manaaki — Serve",notes:["Giving a partner kind, specific feedback is a small act of serving one another with our words.",'Model the stem: "I liked how you…" before students try it.']},reflectionPrompts:["Were students able to 'hear' whether a sentence sounded finished?","How did partner feedback go?"]},"Manaaki"),
Friday:g("Quiz Day — Week 1 Review","Writing — Vocabulary, Punctuation & Sentence Structure (Practice), NZC Phase 1 (Yrs 0–3): consolidation through a team quiz.",
{title:"I Do — What We Learned This Week",instruction:"Before the quiz, let's quickly remind ourselves of the four big things we worked on this week.",example:"**Naming words** · **Word upgrades** · **Capital I and Names** · **Who + Did What**",demonstration:"Every good sentence this week needed: a naming word, an interesting describing word, capital letters in the right places, and both WHO and WHAT they did.",tip:"Remember the checklist: Capital I? Capital names? WHO + did what? Full stop? Interesting word?"},
{title:"We Do — Quick Review Together",instruction:"Let's build one brilliant sentence together using everything from this week.",sentences:["**I** saw a **tiny** bird **hop** across the mat.","**She** ran **quickly** to find her **friend** Aroha.","The **enormous** dog **leaped** over the **puddle**."],prompt:"Can you find the naming word, the upgraded describing word, the capital I or name, and the WHO + did what?"},
{title:"You Do — Quiz Time!",instruction:"Time to put it all together! Good luck Team Tui and Team Kiwi!",tasks:["Listen carefully to each question.","Your team earns a point for each correct answer.","Be kind and cheer for great answers — from both teams!","✦ Remember: it's not about winning, it's about showing what you know!"]},
[{code:"Writing — Vocabulary (Practice)",label:"Applying word upgrades",detail:"NZC Phase 1: students demonstrate recognition and replacement of overused words in a quiz context."},{code:"Writing — Punctuation (Practice)",label:"Capitals in context",detail:"NZC Phase 1: students apply capitalisation rules."},{code:"Writing — Sentence Structure (Practice)",label:"Complete sentence recognition",detail:"NZC Phase 1: students identify and construct complete sentences."}],
{context:ctx("Word Choice Foundations","5 of 40","Years 3–4 (ages 7–9)","30–35 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:["Vocabulary: demonstrate recognition and replacement of overused words.","Punctuation: apply capitalisation rules.","Sentence Structure: identify and construct complete sentences.","Communication: team quiz with good sportsmanship."],walt:["We are learning to show what we know from the whole week.","We are learning to support our team with encouragement."],successCriteria:["I can identify naming words, capitals, and complete sentences.","I can be a kind and encouraging team member."],timing:[{time:"0–5m",title:"Week Review",phase:"I Do",description:"Quick recap of the four skills."},{time:"5–10m",title:"Quick Practice",phase:"We Do",description:"One example question as a class."},{time:"10–30m",title:"Team Quiz",phase:"You Do",description:"16 questions alternating between Team Tui and Team Kiwi."},{time:"30–35m",title:"Celebrate & Reflect",phase:"Reflect",description:"Final scores, applause for both teams."}],resources:["Quiz questions on screen","Scoreboard"],assessment:["Formative: observe which question types the class finds hardest"],differentiation:[{label:"ESOL learners",note:"Questions read aloud clearly; team conferral time."},{label:"All learners",note:"Team format; all contribute at their level."}],valuesIntegration:{heading:"All Four Values",notes:["Aroha: cheering kindly for both teams.","Mōhio: showing what we've learned.","Manaaki: being a generous, encouraging team member.","Pānga: good sportsmanship — our words impact how others feel."]},reflectionPrompts:["Which questions did the class find hardest?","How was the team dynamic?"]},"Aroha")
};

const quiz1=[
{q:"Which word in 'The dog ran fast.' is a NAMING WORD?",opts:["ran","fast","dog","The"],ans:2,explanation:"'Dog' is the naming word — it names the animal. Naming words tell us WHO or WHAT something is."},
{q:"Which is the BEST upgrade for 'The cake was good.'?",opts:["okay","great","nice","big"],ans:1,explanation:"'Great' is more interesting than 'good' — it tells us much more about how the cake was!"},
{q:"Which sentence has CORRECT capital letters?",opts:["i went to the park.","I went to the park.","i Went To The Park.","I went to the Park."],ans:1,explanation:"'I' is always a capital letter, and only the first word gets a capital. 'Park' is not a proper name so it stays lower case."},
{q:"A complete sentence needs TWO things. What are they?",opts:["A capital letter and a full stop","A naming word and a describing word","A WHO or WHAT, and a DID WHAT","A noun and an adjective"],ans:2,explanation:"Every sentence needs to tell us WHO or WHAT, and what they DID. Without both parts, it isn't a complete sentence!"},
{q:"Which of these is NOT a naming word?",opts:["book","teacher","jumped","classroom"],ans:2,explanation:"'Jumped' is an action word (verb), not a naming word. Naming words name a thing, person, or place."},
{q:"Fix 'my friend lily lives near me.' Which is correct?",opts:["My friend Lily lives near me.","My Friend Lily lives near me.","my friend lily lives near me.","My friend lily lives near me."],ans:0,explanation:"'My' gets a capital because it starts the sentence. 'Lily' gets a capital because it is a person's name (a proper noun)."},
{q:"What is the BEST word to replace 'nice' in 'Our school is nice.'?",opts:["good","okay","wonderful","fine"],ans:2,explanation:"'Wonderful' is vivid and interesting — it paints a much clearer picture than 'nice' or 'good' do."},
{q:"Which of these is a COMPLETE sentence?",opts:["The big blue","Ran to the park quickly","My cat jumped.","Under the table"],ans:2,explanation:"'My cat jumped.' tells us WHO (my cat) and what they DID (jumped). The others are missing one of the two jobs!"},
{q:"In 'I saw jake at the shops.' which word needs a capital?",opts:["saw","shops","jake","the"],ans:2,explanation:"'Jake' is a person's name — a proper noun — so it always starts with a capital letter."},
{q:"What is a naming word also called in grammar?",opts:["Verb","Adjective","Noun","Adverb"],ans:2,explanation:"A naming word is called a NOUN. Nouns name people, places, animals, and things."},
{q:"Which is the MOST interesting upgrade for 'good' in 'The weather was good.'?",opts:["not bad","okay","average","brilliant"],ans:3,explanation:"'Brilliant' is vivid and specific. 'Not bad' and 'okay' are actually more boring than 'good'!"},
{q:"How do you check whether a sentence is finished?",opts:["Count the words","Read it aloud and listen","Check if it has five words","See if it has a describing word"],ans:1,explanation:"Reading your sentence aloud is the best way to hear whether it sounds complete — your ears catch things your eyes can miss!"},
{q:"Which sentence uses 'I' correctly?",opts:["Me and jack went to school.","i went to school with Jack.","Jack and I went to school.","Jack and me went to school."],ans:2,explanation:"'I' is always a capital letter, and 'Jack' gets a capital because it is a proper noun."},
{q:"Which TWO words are naming words in 'The bird sat on a branch.'?",opts:["sat and on","bird and branch","the and a","sat and branch"],ans:1,explanation:"'Bird' and 'branch' are both naming words — they name the animal and the thing it sat on."},
{q:"What should ALWAYS be at the END of a complete sentence?",opts:["A comma","A capital letter","A full stop (or ? or !)","A naming word"],ans:2,explanation:"Every sentence needs end punctuation — a full stop, question mark, or exclamation mark — to tell the reader it is finished."},
{q:"Which sentence uses EVERYTHING from this week correctly?",opts:["i saw a good dog","The enormous dog leaped over the puddle.","the bird is nice","My Friend is good"],ans:1,explanation:"'The enormous dog leaped over the puddle.' has a capital, full stop, naming words, an upgraded describing word, and complete WHO + DID WHAT structure."}
];

/* ===== WEEK 2 ===== */
const week2={
Monday:g("Describing Words — Colour, Size & Feeling","Writing — Vocabulary (Knowledge & Practice), NZC Phase 1 (Yrs 0–3): students identify and use adjectives to add colour, size, and feeling detail.",
{title:"I Do — Describing Words Paint a Picture",instruction:"Describing words (adjectives) tell us more about a naming word. They answer: What colour? How big? How does it feel? Watch me add them.",example:"A **dog**. → A **tiny**, **golden** dog. → A **tiny**, **golden** dog that felt **warm** and **soft**.",demonstration:"Without describing words: 'a dog' — we can't picture it at all. With them: 'a **tiny**, **golden** dog' — now I can see it! Adjectives sit right next to the naming word and dress it up.",tip:"Ask: what colour is it? How big is it? What does it feel like? Each answer is a describing word!"},
{title:"We Do — Add a Describing Word",instruction:"Let's add at least one describing word to each naming word to make it more vivid.",sentences:["a **cat** → a ___ **cat** (what colour or size?)","the **ball** → the ___ **ball** (how big or what colour?)","a **day** → a ___ **day** (what kind of feeling?)"],prompt:"What word would help us picture it better? Could we add a colour AND a size word?"},
{title:"You Do — Your Turn",instruction:"Add at least one describing word to each naming word. Try to use colour, size, AND feeling words.",tasks:["a ___ **cloud** (add a colour or size word)","the ___ **tree** (add a size or feeling word)","a ___ **friend** (add a feeling or character word)","✦ Bonus: Write a whole sentence using TWO describing words before a naming word."]},
[{code:"Writing — Vocabulary (Knowledge)",label:"Adjectives: colour, size, feeling",detail:"NZC Phase 1: students learn that adjectives add descriptive detail to naming words, introducing colour, size, and feeling vocabulary as concrete, accessible starting categories."},{code:"Writing — Vocabulary (Practice)",label:"Using adjectives in writing",detail:"NZC Phase 1: students apply adjectives to naming words in their own writing, building the habit of adding descriptive detail from the earliest stages."}],
{context:ctx("Word Choice Foundations","6 of 40","Years 3–4 (ages 7–9)","25–30 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:["Vocabulary: identify adjectives as words that describe naming words — colour, size, and feeling.","Sentence Structure: adjectives sit next to or near the naming word they describe.","Communication: share descriptive choices aloud, building a shared describing-word bank.","Metacognition: ask 'what colour? how big? what does it feel like?' as a self-prompting strategy."],walt:["We are learning that describing words (adjectives) tell us more about naming words.","We are learning to use colour, size, and feeling words.","We are learning to add describing words to make our writing more vivid."],successCriteria:["I can point to a describing word in a sentence.","I can add a colour, size, or feeling word to a naming word.","I can use two describing words together before a naming word."],timing:[{time:"0–7m",title:"Describing Word Categories",phase:"I Do",description:"Teacher holds up real objects and asks: what colour? how big? how does it feel? — building three columns on the board."},{time:"7–14m",title:"Add a Word Together",phase:"We Do",description:"Whole class adds describing words to 3 naming words. Picture support and buddy pairing."},{time:"14–22m",title:"My Describing Words",phase:"You Do",description:"Students add describing words to 3 naming words. Word bank with Colour/Size/Feeling columns; bonus 2-adjective sentence."},{time:"22–28m",title:"Share & Appreciate",phase:"Reflect",description:"Students share their best describing word. Connect to Aroha: noticing what makes something beautiful is a way of appreciating what God has made."}],resources:["Real classroom objects","Three-column display: Colour / Size / Feeling","Adjective word bank","Lined paper or worksheet"],assessment:["Formative: quality and variety of describing words","Work sample: sentences with adjectives added","Focus: correct placement before noun; variety across colour, size, and feeling"],differentiation:[{label:"ESOL learners",note:"Real objects + colour swatches + size comparison cards; word bank with images."},{label:"Emerging writers",note:"Three-column word bank (Colour / Size / Feeling); sentence frame: 'a ___ ___'."},{label:"Confident writers",note:"Two-adjective bonus sentence; use a feeling AND a colour in the same sentence."},{label:"Diverse learners",note:"Physical texture/size comparison of real objects before writing."}],valuesIntegration:{heading:"Aroha — Love",notes:["Noticing what makes things beautiful or special connects to Aroha — love for God's world and the things He has made.","When you choose a good describing word, you are paying real attention to the world around you."]},reflectionPrompts:["Were students choosing real describing words or repeating 'big'?","Did the three-category approach help students vary their word choices?","Which students are ready to stack two adjectives in the same sentence?"]},"Aroha"),
Tuesday:g("Verbs — Action Words","Writing — Grammar (Knowledge & Practice), NZC Phase 1 (Yrs 0–3): students identify and use verbs as the action or doing words that complete a sentence.",
{title:"I Do — Every Sentence Has an Action",instruction:"Every sentence has an action word — it tells us what someone or something is DOING. These are called verbs. Without a verb, you don't have a sentence.",example:"The **cat** **leaped**. The **children** **laughed**. The **rain** **fell**.",demonstration:'"Leaped", "laughed", "fell" — these are all verbs. They tell us what the cat, the children, and the rain are DOING. If I said "The cat…" and stopped — it isn\'t a sentence yet.',tip:"Find the verb by asking: what is the naming word DOING? The answer is always the verb."},
{title:"We Do — Find the Verb",instruction:"Let's find the verb in each sentence together. Then let's swap it for a more interesting action word.",sentences:["The **bird** **flew** over the roof.","My **brother** **ran** to the gate.","The **sun** **shone** all afternoon."],prompt:"Which word is the action word? Could we swap it? (flew → swooped / ran → sprinted / shone → blazed)"},
{title:"You Do — Your Turn",instruction:"Find the verb in each sentence, then write an upgraded version with a more interesting action word.",tasks:["The **dog** **went** across the field.","The **children** **said** hello to the teacher.","The **rain** **came** down hard.","✦ Bonus: Write your own sentence with the most vivid, interesting verb you can think of — surprise us!"]},
[{code:"Writing — Grammar (Knowledge)",label:"Verbs as action words",detail:"NZC Phase 1: students learn that verbs are the action or doing words in a sentence and that every complete sentence must contain one."},{code:"Writing — Vocabulary (Practice)",label:"Upgrading verbs for precision",detail:"NZC Phase 1: students begin replacing plain verbs (went, said, came) with more precise and vivid alternatives."}],
{context:ctx("Word Choice Foundations","7 of 40","Years 3–4 (ages 7–9)","25–30 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:["Grammar: verbs are action/doing words; every complete sentence must contain one.","Vocabulary: begin replacing plain verbs (went, said, came) with more precise alternatives.","Sentence Structure: reinforce the WHO + DID WHAT structure by naming the 'DID WHAT' part as a verb.","Metacognition: find the verb by asking 'what is the subject DOING?'"],walt:["We are learning that action words (verbs) tell us what someone or something is doing.","We are learning to find the verb in a sentence.","We are learning to upgrade a plain verb to a more interesting one."],successCriteria:["I can point to the verb (action word) in a sentence.","I can find the verb by asking 'what is it doing?'","I can suggest a more interesting verb to replace a plain one."],timing:[{time:"0–7m",title:"Action Mime Game",phase:"I Do",description:"Teacher mimes an action (leap, sprint, whisper) and students guess the verb. Then teacher shows how the verb completes a sentence."},{time:"7–14m",title:"Find & Upgrade the Verb",phase:"We Do",description:"Whole class finds the verb in 3 sentences and suggests upgraded alternatives. Verb upgrade bank on board."},{time:"14–22m",title:"My Verb Upgrades",phase:"You Do",description:"Students find the verb in 3 sentences and rewrite with an upgraded version."},{time:"22–28m",title:"Share the Best Verb",phase:"Reflect",description:"Students share their most interesting verb. Close: every action in the world was made by God and is worth naming well."}],resources:["Verb upgrade bank poster (went→sprinted, said→whispered, came→tumbled)","Sentences on board or worksheet","Large lined paper"],assessment:["Formative: accuracy of verb identification and quality of upgrades","Work sample: 3 sentences with upgraded verbs"],differentiation:[{label:"ESOL learners",note:"Physical mime; verb + picture pairing on the word bank; oral rehearsal."},{label:"Emerging writers",note:"Verb upgrade bank with images; sentence frame."},{label:"Confident writers",note:"Bonus: write a sentence where the verb is the most surprising word in the whole sentence."},{label:"Diverse learners",note:"Mime game and physical movement built into the I Do stage."}],valuesIntegration:{heading:"Mōhio — Know",notes:["Every action in God's world is worth noticing and naming well — choosing a precise verb is a small act of paying careful attention.","Connect to Mōhio: knowing the right name for what something does is part of knowing the world."]},reflectionPrompts:["Were students able to find verbs confidently?","Did the mime game make the concept concrete?","Which verb upgrades were most creative?"]},"Mōhio"),
Wednesday:g("Adding One Adjective to a Sentence","Writing — Sentence Structure & Vocabulary (Practice), NZC Phase 1 (Yrs 0–3): students expand simple sentences by inserting one adjective before a naming word.",
{title:"I Do — Growing a Sentence",instruction:"This week we've learned adjectives (Monday) and verbs (Tuesday). Now let's put them together — watch me take a plain sentence and grow it by adding one describing word.",example:"The **dog** ran. → The **fluffy** dog ran. → The **fluffy** dog **dashed**.",demonstration:"Step 1: find the naming word — **dog**. Step 2: ask 'what is it like?' — **fluffy**. Slot it in right before the naming word. Step 3 (bonus!): also upgrade the verb — **dashed** instead of ran.",tip:"Find the naming word. Ask: what is it like? Put the describing word right in front of it."},
{title:"We Do — Grow These Sentences",instruction:"Let's add one adjective to each sentence together — find the naming word first, then add a describing word before it.",sentences:["The **cat** sat by the door.","A **bird** sang in the tree.","The **children** played in the sun."],prompt:"Which is the naming word? What describing word could we add right in front of it?"},
{title:"You Do — Your Turn",instruction:"Add one adjective to each sentence by finding the naming word and slipping a describing word in front of it.",tasks:["The **cloud** drifted past.","A **dog** barked at the gate.","The **sun** warmed my face.","✦ Bonus: Can you add an adjective AND upgrade the verb in the same sentence?"]},
[{code:"Writing — Sentence Structure (Practice)",label:"Expanding sentences with adjectives",detail:"NZC Phase 1: students expand simple sentences by inserting adjectives before naming words, building the habit of adding descriptive detail into sentence construction."},{code:"Writing — Vocabulary (Practice)",label:"Adjective placement and selection",detail:"NZC Phase 1: students practise selecting and correctly placing adjectives in a sentence, consolidating Monday's knowledge within real sentence contexts."}],
{context:ctx("Word Choice Foundations","8 of 40","Years 3–4 (ages 7–9)","25–30 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:["Sentence Structure: expand simple sentences by inserting adjectives before naming words.","Vocabulary: select adjectives that really add meaning.","Writing Process: use a grow-a-sentence technique to revise and improve a plain sentence.","Metacognition: locate the naming word first, then ask what it is like."],walt:["We are learning to make a plain sentence better by adding one describing word.","We are learning to place a describing word right in front of the naming word.","We are learning to check that our describing word really adds meaning."],successCriteria:["I can find the naming word in a sentence.","I can add one describing word right in front of it.","My describing word tells the reader something interesting, not just 'nice' or 'big'."],timing:[{time:"0–7m",title:"Grow a Sentence — Step by Step",phase:"I Do",description:"Teacher builds a sentence in two visible steps: plain first, then inserts adjective. Uses a bracket/arrow to show where the adjective slots in."},{time:"7–14m",title:"Grow Together",phase:"We Do",description:"Whole class grows 3 plain sentences, voting on the best adjective each time. Monday's word bank re-used."},{time:"14–22m",title:"My Grown Sentences",phase:"You Do",description:"Students grow 3 sentences by adding an adjective. Sentence frames with a blank for emerging writers."},{time:"22–28m",title:"Before & After",phase:"Reflect",description:"Read the plain sentence, then the grown version — students say which is better and why."}],resources:["Plain sentences on board or worksheet","Monday's adjective word bank re-displayed","Sentence frame: 'The ___ [naming word] [verb].'","Large lined paper"],assessment:["Formative: accuracy of adjective placement","Work sample: 3 sentences with adjectives correctly inserted","Focus: adjective placed before the noun; real descriptive value"],differentiation:[{label:"ESOL learners",note:"Visual slot diagram [ADJ]+[NOUN]; Monday's word bank with images."},{label:"Emerging writers",note:"Sentence frame with a visible blank slot before the naming word."},{label:"Confident writers",note:"Bonus: grow the sentence with BOTH an adjective AND an upgraded verb."},{label:"Diverse learners",note:"Before-and-after reading aloud in the reflect stage supports auditory learners."}],valuesIntegration:{heading:"Aroha — Love",notes:["Noticing and naming what something looks like is a form of appreciation — connecting to Aroha and our love for the world God made.","The 'before and after' moment models humility: we can always make our writing better, and that's a gift."]},reflectionPrompts:["Are students placing adjectives before (not after) the naming word?","Are the adjectives adding real descriptive value?","Are any students ready to use two adjectives together?"]},"Aroha"),
Thursday:g("Fix-It — Capitals & Full Stops Together","Writing — Punctuation (Practice), NZC Phase 1 (Yrs 0–3): students apply capital letters and full stops together in a complete check of short passages.",
{title:"I Do — The Two Punctuation Partners",instruction:"Capital letters and full stops always work as a pair — one starts the sentence, one finishes it. You can't have one without the other. Watch me find every pair in this passage.",example:"**the** dog ran across the field it jumped over the fence then it sat down**.**",demonstration:"I read it aloud. I can hear three separate ideas. Each one needs a **capital** at the start and a **full stop** at the end. Fixed: '**The** dog ran across the field. **It** jumped over the fence. **Then** it sat down.'",tip:"Read aloud and listen for where you naturally pause or take a breath — that's often where a full stop goes and the next capital begins."},
{title:"We Do — Fix This Passage",instruction:"Let's read this passage aloud together and fix every missing capital and full stop as a team.",sentences:["the children ran outside it was a sunny day they played on the grass","a bird flew down and sat on the fence everyone watched it fly away","mia found a leaf she gave it to her friend noah they both smiled"],prompt:"How many sentences are in each line? Where do you hear a pause?"},
{title:"You Do — Your Turn",instruction:"Fix each passage by adding the missing capital letters and full stops. Read it aloud first.",tasks:["the sun was warm the flowers were bright a bee buzzed past","tom ran to school he was late his friend waited for him","we went to the beach it was fun the waves were huge","✦ Bonus: Write your own 3-sentence passage, then swap with a partner — can they spot all your capitals and full stops?"]},
[{code:"Writing — Punctuation (Practice)",label:"Capitals and full stops as a system",detail:"NZC Phase 1: students apply capital letters and full stops together as a paired punctuation system, moving beyond single-sentence checking to short-passage editing."},{code:"Writing — Writing Process (Practice)",label:"Editing a short passage",detail:"NZC Phase 1: students begin applying editing skills to a short passage (3 sentences), extending the read-aloud checking strategy from Week 1 to multi-sentence text."}],
{context:ctx("Word Choice Foundations","9 of 40","Years 3–4 (ages 7–9)","25–30 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:["Punctuation: capital letters and full stops as a paired system — one starts, one ends each sentence.","Writing Process: editing a short passage using read-aloud checking.","Metacognition: listen for natural pauses to locate full stop positions."],walt:["We are learning that capital letters and full stops work together as a pair.","We are learning to fix a short passage by adding missing capitals and full stops.","We are learning to read aloud to hear where sentences end."],successCriteria:["I can find where a sentence ends by reading aloud and listening.","I can add a full stop at the end and a capital at the start of the next sentence.","I can check a 3-sentence passage for correct punctuation."],timing:[{time:"0–7m",title:"The Punctuation Pair",phase:"I Do",description:"Teacher reads a passage without punctuation, marks each pause point and adds full stop + capital. Students count the sentences."},{time:"7–14m",title:"Fix the Passage Together",phase:"We Do",description:"Whole class reads 3 unpunctuated lines, calling out where each sentence ends."},{time:"14–22m",title:"My Fix-It Passages",phase:"You Do",description:"Students fix 3 short passages independently. Line-by-line chunks for emerging writers."},{time:"22–28m",title:"Read Back & Confirm",phase:"Reflect",description:"Students read corrected passage to a partner, who confirms the fixes sound right."}],resources:["Unpunctuated passages on board or worksheet","Two-colour marker: red for full stops, blue for capitals"],assessment:["Formative: accuracy of punctuation placement","Work sample: 3 corrected passages","Focus: correct pairing of full stop + capital across all sentences"],differentiation:[{label:"ESOL learners",note:"Passage read aloud by teacher first; colour-coded markers; line-by-line approach."},{label:"Emerging writers",note:"Passage pre-divided at sentence boundaries; students add punctuation only."},{label:"Confident writers",note:"Write own 3-sentence passage and swap with a partner for a fix-it challenge."},{label:"Diverse learners",note:"Read-aloud strategy benefits auditory learners."}],valuesIntegration:{heading:"Manaaki — Serve",notes:["Taking care with punctuation is a way of serving our reader — making our writing easy and clear to read is a gift to whoever will read it.","The partner check at the end is a small, practical act of Manaaki."]},reflectionPrompts:["Were students able to use the read-aloud strategy to find sentence boundaries independently?","Is anyone still placing capitals randomly?","Are students starting to apply this automatically in their own free writing?"]},"Manaaki"),
Friday:g("Quiz Day — Week 2 Review","Writing — Vocabulary, Grammar, Sentence Structure & Punctuation (Practice), NZC Phase 1 (Yrs 0–3): consolidate adjectives, verbs, sentence expansion, and punctuation.",
{title:"I Do — What We Learned This Week",instruction:"Before the quiz, let's quickly remind ourselves of the four things we worked on this week.",example:"**Describing words (adjectives)** · **Action words (verbs)** · **Growing a sentence** · **Capitals & full stops together**",demonstration:"A great sentence this week: 'The **fluffy** dog **dashed** across the field.' — adjective (fluffy), vivid verb (dashed), capital at the start, full stop at the end.",tip:"Think: ADJECTIVE in front of the naming word. VERB showing the action. CAPITAL starts. FULL STOP ends."},
{title:"We Do — Quick Review Together",instruction:"Let's build one brilliant sentence that uses everything from this week.",sentences:["The **enormous** wave **crashed** onto the beach.","A **tiny** bird **darted** between the **golden** branches.","The **kind** teacher **smiled** as the **excited** children ran in."],prompt:"Can you find the adjective, the verb, the capital, and the full stop in each sentence?"},
{title:"You Do — Quiz Time!",instruction:"Time to show what you know! Good luck Team Tui and Team Kiwi!",tasks:["Listen carefully to each question.","Your team earns a point for each correct answer.","Be encouraging — cheer for great answers from both teams!","✦ Remember: this is a celebration of your learning!"]},
[{code:"Writing — Vocabulary (Practice)",label:"Adjectives and verb upgrades",detail:"NZC Phase 1: students demonstrate knowledge of adjectives and precise verb selection in a quiz context."},{code:"Writing — Grammar (Practice)",label:"Identifying verbs and adjectives",detail:"NZC Phase 1: students identify verbs and adjectives in sentences."},{code:"Writing — Punctuation (Practice)",label:"Capitals and full stops as a system",detail:"NZC Phase 1: students apply knowledge of capital letters and full stops as a paired system."}],
{context:ctx("Word Choice Foundations","10 of 40","Years 3–4 (ages 7–9)","30–35 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:["Vocabulary: adjectives and precise verb selection.","Grammar: identify verbs and adjectives in sentences.","Punctuation: capitals and full stops as a paired system.","Communication: team quiz with good sportsmanship."],walt:["We are learning to show what we know from the whole week.","We are learning to identify adjectives and verbs.","We are learning to be kind, encouraging team members."],successCriteria:["I can identify adjectives and verbs in a sentence.","I can fix punctuation errors in short passages.","I can be an encouraging and kind team member."],timing:[{time:"0–5m",title:"Week 2 Review",phase:"I Do",description:"Quick recap of this week's four skills."},{time:"5–10m",title:"Quick Practice",phase:"We Do",description:"One example question as a class."},{time:"10–30m",title:"Team Quiz",phase:"You Do",description:"16 questions on adjectives, verbs, sentence expansion, and punctuation."},{time:"30–35m",title:"Celebrate & Reflect",phase:"Reflect",description:"Final scores, applause for both teams."}],resources:["Quiz questions on screen","Scoreboard"],assessment:["Formative: observe which question types the class finds hardest"],differentiation:[{label:"ESOL learners",note:"Questions read aloud clearly; team conferral time."},{label:"All learners",note:"Team format; all contribute at their level."}],valuesIntegration:{heading:"All Four Values",notes:["Aroha: noticing and appreciating the describing words we used this week.","Mōhio: knowing the names of word types (adjective, verb).","Manaaki: being a generous team member.","Pānga: a vivid verb or perfect adjective can change how a reader feels."]},reflectionPrompts:["Which question types did the class find hardest?","Are there misconceptions to address in Week 3?","How was the team spirit?"]},"Aroha")
};

const quiz2=[
{q:"What is a DESCRIBING WORD (adjective)?",opts:["A word that names something","A word that shows action","A word that tells us more about a naming word","A word that connects two ideas"],ans:2,explanation:"An adjective is a describing word — it tells us more about a naming word, like its colour, size, or how it feels."},
{q:"Which word in 'The enormous dog leaped over the fence.' is an ADJECTIVE?",opts:["dog","leaped","enormous","fence"],ans:2,explanation:"'Enormous' is the adjective — it describes the dog. Adjectives answer: what colour? how big? what kind?"},
{q:"Which word is the VERB in 'The children dashed across the field.'?",opts:["children","dashed","field","across"],ans:1,explanation:"'Dashed' is the verb — it's the action word telling us what the children are DOING."},
{q:"Where does an adjective go in a sentence?",opts:["At the very end","After the full stop","Right in front of the naming word it describes","At the start of every sentence"],ans:2,explanation:"An adjective goes right in front of the naming word it describes — for example, 'the FLUFFY cat' or 'a TINY bird'."},
{q:"Which sentence uses an adjective CORRECTLY?",opts:["The cat fluffy sat down.","The fluffy sat cat down.","The fluffy cat sat down.","Fluffy the cat sat down."],ans:2,explanation:"'The fluffy cat sat down.' is correct — 'fluffy' sits right in front of the naming word 'cat'."},
{q:"Which is the most VIVID verb to replace 'went' in 'The bird went across the sky.'?",opts:["moved","soared","did go","walked"],ans:1,explanation:"'Soared' is the most vivid and precise verb — it tells us exactly how the bird moved."},
{q:"How many sentences in 'the dog barked a cat ran up the tree the bird flew away'?",opts:["One sentence","Two sentences","Three sentences","Four sentences"],ans:2,explanation:"There are THREE sentences: 1) The dog barked. 2) A cat ran up the tree. 3) The bird flew away. Listen for the natural pauses."},
{q:"Which passage has CORRECT capital letters and full stops?",opts:["the dog ran. The cat hid. the bird flew.","The dog ran. The cat hid. The bird flew.","The dog ran the cat hid the bird flew.","The dog ran. the cat hid. the bird flew."],ans:1,explanation:"Every sentence needs a capital at the START and a full stop at the END. Only option B has all three sentences correctly punctuated."},
{q:"Which TWO words are adjectives in 'The tiny, golden bird sang sweetly.'?",opts:["bird and sang","tiny and golden","sang and sweetly","golden and sang"],ans:1,explanation:"'Tiny' and 'golden' are both adjectives — they both describe the naming word 'bird'."},
{q:"What's a good way to find where a sentence ends?",opts:["Count to ten","Read it aloud and listen for a natural pause","Look for the longest word","Find the adjective"],ans:1,explanation:"Reading aloud and listening for natural pauses is the best way to do it — your ear hears where a sentence ends before your eye spots it."},
{q:"Which sentence is EXPANDED with the BEST adjective?",opts:["The nice dog ran.","The good, big dog ran.","The enormous dog ran.","The dog ran nicely."],ans:2,explanation:"'The enormous dog ran.' uses the most vivid and specific adjective. 'Nice' and 'good' are overused boring words."},
{q:"Which word is the verb in 'A golden leaf drifted to the ground.'?",opts:["golden","leaf","drifted","ground"],ans:2,explanation:"'Drifted' is the verb — it's the action word, telling us what the leaf is DOING."},
{q:"How do you GROW a plain sentence like 'The cat sat.'?",opts:["Add a full stop after it","Add a describing word in front of the naming word","Add another full stop","Change the capital letter"],ans:1,explanation:"You grow a sentence by adding a describing word (adjective) in front of the naming word: 'The FLUFFY cat sat.'"},
{q:"Which sentence has an adjective AND an upgraded verb?",opts:["The dog went.","The big dog went quickly.","The enormous dog leaped.","The dog leaped nicely."],ans:2,explanation:"'The enormous dog leaped.' has both: 'enormous' is a vivid adjective and 'leaped' is a precise, upgraded verb."},
{q:"Which of these is a VERB (action word)?",opts:["fluffy","enormous","dashed","golden"],ans:2,explanation:"'Dashed' is the verb — it shows what someone IS DOING. 'Fluffy', 'enormous', and 'golden' are all adjectives."},
{q:"Which sentence uses EVERYTHING from Week 2 correctly?",opts:["the tiny bird flew","The tiny bird soared over the hill.","tiny bird soared.","The bird is tiny and soared"],ans:1,explanation:"'The tiny bird soared over the hill.' has it all: 'tiny' (adjective), 'soared' (vivid verb), capital T, and a full stop."}
];

/* ===== WEEK 3 ===== */
const week3={
Monday:g("Family & People Words — and Upgrading 'Said'","Writing — Vocabulary (Knowledge & Practice), NZC Phase 1 (Yrs 0–3): students build vocabulary around family and people, and begin upgrading the overused word 'said'.",
{title:"I Do — Words for People We Love, and Better Ways to Say 'Said'",instruction:"Today we have two connected jobs: building words for the people in our lives, AND upgrading the most overused word in writing — 'said'. Watch me do both.",example:"People words: **whanau**, **mother**, **grandfather**, **neighbour**, **friend**. Upgrading said: **said** → **whispered** / **called** / **announced** / **laughed**.",demonstration:'"Said" appears in almost every story ever written — but it tells us almost nothing. "She whispered" tells us she was quiet and secret. "He announced" tells us he spoke loudly and proudly. The word we choose tells HOW something was said.',tip:"When you write who said something, ask: HOW did they say it? That answer is your upgrade word."},
{title:"We Do — People Words & Said Upgrades",instruction:"Let's build our people-word bank together, then upgrade 'said' in each sentence.",sentences:["**Mia** **said** she was tired. → Mia ___ she was tired. (quietly? happily? sadly?)","My **brother** **said** it was time to go. → My brother ___ it was time to go.","The **teacher** **said** well done. → The teacher ___ well done."],prompt:"What word tells us HOW they spoke? Whispered? Cheered? Sighed? Announced?"},
{title:"You Do — Your Turn",instruction:"Upgrade 'said' in each sentence. Choose a word that tells us exactly HOW they spoke.",tasks:["My **grandma** **said** the food was delicious.","My little **sister** **said** she was scared.","**Dad** **said** he was proud of me.","✦ Bonus: Write your own sentence about someone in your whanau, using an upgraded 'said' word — no plain 'said' allowed!"]},
[{code:"Writing — Vocabulary (Knowledge)",label:"People words and said upgrades",detail:"NZC Phase 1: students build vocabulary around family and relationships while beginning to upgrade the high-frequency word 'said' with more expressive speech verbs."},{code:"Writing — Vocabulary (Practice)",label:"Applying speech verb upgrades",detail:"NZC Phase 1: students replace 'said' with specific speech verbs (whispered, announced, sighed, cheered) that convey both the content and the manner of speech."}],
{context:ctx("Word Choice Foundations","11 of 40","Years 3–4 (ages 7–9)","25–30 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:["Vocabulary: build a bank of people/relationship words (whanau, neighbour, friend, grandparent).","Vocabulary: replace 'said' with expressive speech verbs that show HOW something was said.","Communication: orally rehearse the upgraded sentence before writing.","Metacognition: ask 'HOW did they say it?' as a self-prompting strategy."],walt:["We are learning words for people and whanau.","We are learning that 'said' is often a boring word choice.","We are learning to replace 'said' with a word that shows HOW someone spoke."],successCriteria:["I can name at least 3 people words (family/community).","I can spot the word 'said' in a sentence.","I can replace 'said' with a more expressive word."],timing:[{time:"0–7m",title:"People Word Bank + Said Upgrade",phase:"I Do",description:"Teacher builds a people-word bank on the board, then demonstrates upgrading 'said' in two example sentences."},{time:"7–14m",title:"Upgrade Together",phase:"We Do",description:"Whole class works through 3 sentences, suggesting upgrades for 'said' and discussing HOW meaning."},{time:"14–22m",title:"My Upgrades",phase:"You Do",description:"Students upgrade 'said' in 3 sentences about family members. Said-upgrade bank available."},{time:"22–28m",title:"Share & Connect",phase:"Reflect",description:"Students share a sentence about their whanau using an upgraded said word. Connect to Aroha: the people we love deserve our best words."}],resources:["Said-upgrade bank poster (whispered, cheered, sighed, announced, murmured, called, laughed)","People/whanau word bank","Worksheet with 3 sentences"],assessment:["Formative: quality and variety of said upgrades","Work sample: 3 sentences with upgraded said words","Focus: real HOW meaning conveyed; correct sentence structure maintained"],differentiation:[{label:"ESOL learners",note:"Said-upgrade bank with facial expression images; oral rehearsal; buddy pairing."},{label:"Emerging writers",note:"Upgrade bank with 4-5 clearly pictured options; sentence frame."},{label:"Confident writers",note:"Bonus sentence must use an upgrade word AND an adjective — combining Week 2 and Week 3 skills."},{label:"Diverse learners",note:"Mime the HOW of each said upgrade (whisper, cheer, sigh) as a class before writing."}],valuesIntegration:{heading:"Aroha — Love",notes:["Writing about the people we love — our whanau and friends — is a direct expression of Aroha. The more specific our words, the more we honour those people.","Choosing the right word for HOW someone spoke is a small act of care for both our reader and the person we are writing about."]},reflectionPrompts:["Were students able to articulate what HOW information the upgrade word adds?","Did mime activity help students connect the upgrade word to a real manner of speaking?","Are students applying said upgrades spontaneously in their own free writing?","Which said upgrade words were most popular — worth adding to the class word wall?"]},"Aroha"),
Tuesday:g("Proper Nouns — Names and Places Need Capitals","Writing — Punctuation (Knowledge & Practice), NZC Phase 1 (Yrs 0–3): students extend capitalisation to include all proper nouns.",
{title:"I Do — Special Names Always Stand Tall",instruction:"Last week we learned that the word 'I' and people's names need capitals. This week we go further — ALL specific names of places and things also need capitals.",example:"I live in **Christchurch** in **New Zealand**. My school is called **Parkview Primary**.",demonstration:'"Christchurch" is a specific place — capital C. "New Zealand" is our country — capital N and Z. "Parkview Primary" is the name of a specific school — capital P. If I said "a school" or "a city" — no capital, because those are not specific names.',tip:"Ask: is this the SPECIFIC name of something? If yes — it gets a capital. If it's just a type of thing (a school, a city, a dog) — no capital."},
{title:"We Do — Find the Proper Nouns",instruction:"Let's find every word that needs a capital letter because it is a specific name.",sentences:["my friend lives in **auckland** near the **sky tower**.","we go to church at **grace church** every **sunday**.","our class read a book called **charlotte's web** by **e.b. white**."],prompt:"Is this the specific name of a person, place, day, or thing? If yes — capital!"},
{title:"You Do — Your Turn",instruction:"Rewrite each sentence, adding capitals to all proper nouns (specific names of people, places, or things).",tasks:["my family visited **rotorua** in the holidays.","i read a book about **matariki** with my **nana**.","our teacher is called **mrs patel** and she is very kind.","✦ Bonus: Write 2 sentences about your town or school, using at least 3 proper nouns with correct capitals."]},
[{code:"Writing — Punctuation (Knowledge)",label:"Proper nouns: names and places",detail:"NZC Phase 1: students extend capitalisation from personal names to include all proper nouns — specific names of places, buildings, books, days, and institutions."},{code:"Writing — Punctuation (Practice)",label:"Applying proper noun capitals consistently",detail:"NZC Phase 1: students apply capital letters to proper nouns with increasing consistency, distinguishing between common nouns (a school) and proper nouns (Parkview Primary)."}],
{context:ctx("Word Choice Foundations","12 of 40","Years 3–4 (ages 7–9)","25–30 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:["Punctuation: all proper nouns (specific names of people, places, titles, days) require a capital letter.","Grammar: distinguish between common nouns (a school) and proper nouns (specific named entities).","Communication: explain WHY a word needs a capital.","Metacognition: ask 'is this a specific name?' as a self-checking strategy."],walt:["We are learning that specific names of places and things always start with a capital letter.","We are learning to spot the difference between a common noun and a proper noun.","We are learning to check our own writing for proper noun capitals."],successCriteria:["I can explain what a proper noun is (a specific name).","I can give a capital letter to names of places, schools, books, and days.","I can tell the difference between 'a school' (no capital) and a named school (capital)."],timing:[{time:"0–7m",title:"Specific Names Stand Tall",phase:"I Do",description:"Teacher writes common and proper noun pairs on the board (a city / Christchurch; a school / Parkview Primary). Include te reo Maori place names."},{time:"7–14m",title:"Find the Proper Nouns",phase:"We Do",description:"Whole class reads 3 sentences, identifying proper nouns and explaining why each needs a capital."},{time:"14–22m",title:"My Proper Noun Capitals",phase:"You Do",description:"Students rewrite 3 sentences, adding proper noun capitals. Proper nouns pre-underlined for emerging writers."},{time:"22–28m",title:"Our Names Matter",phase:"Reflect",description:"Students share one proper noun from their own life. Close: our names and places have capital letters because specific, particular things matter — God knows each one by name."}],resources:["Common-vs-proper noun pairs on board","Sentences with mixed capitalisation","Worksheet for You Do task"],assessment:["Formative: accuracy of proper noun identification","Work sample: 3 sentences with proper noun capitals","Focus: capitalising proper nouns; NOT capitalising common nouns"],differentiation:[{label:"ESOL learners",note:"Include culturally relevant proper nouns (te reo Maori place names); underline-first approach."},{label:"Emerging writers",note:"Proper nouns pre-underlined; students add capitals only."},{label:"Confident writers",note:"Bonus: write 2 sentences about their own town using at least 3 proper nouns."},{label:"Diverse learners",note:"Physical stand-and-say: stand when hearing a proper noun, sit for a common noun."}],valuesIntegration:{heading:"Mohio — Know",notes:["Our own names, our whanau's names, and the names of the places we live are worth capitalising — specific, particular things matter. God knows each of us by name.","This connects to Mohio: knowing who we are and where we belong is part of knowing our place in God's story."]},reflectionPrompts:["Could students explain WHY a proper noun needs a capital?","Were students incorrectly capitalising common nouns?","Are students applying proper noun capitals in their own free writing?"]},"Mohio"),
Wednesday:g("Adding 'Where' to a Sentence","Writing — Sentence Structure (Knowledge & Practice), NZC Phase 1 (Yrs 0–3): students expand sentences by adding a prepositional phrase answering 'where?'",
{title:"I Do — Sentences Can Tell Us Where",instruction:"We know a sentence needs WHO and DID WHAT. Now we can make it even better by adding WHERE it happened. Watch me grow a sentence with a WHERE phrase.",example:"The **dog** **ran**. → The **dog** ran **across the field**. → The **fluffy** dog **dashed** **across the sunlit field**.",demonstration:"Step 1: I have my sentence — 'The dog ran.' Step 2: I ask WHERE? — across the field. I add that right after the verb: 'The dog ran **across the field**.' Step 3: I can also add an adjective AND a WHERE phrase together!",tip:"Ask: WHERE did it happen? The answer is usually a small phrase starting with a word like: across, through, under, over, into, beside, along, past."},
{title:"We Do — Add a Where Phrase",instruction:"Let's grow these sentences by adding a WHERE phrase after the verb.",sentences:["The **bird** **flew** → The bird flew ___ (where?)","My **friend** **ran** → My friend ran ___ (where?)","The **children** **played** → The children played ___ (where?)"],prompt:"Can you start your WHERE phrase with a place word like: across, through, under, beside, into, past, along?"},
{title:"You Do — Your Turn",instruction:"Add a WHERE phrase to each sentence. Try to use a different place word each time.",tasks:["The **cat** **sat** → The cat sat ___ .","A **leaf** **drifted** → A leaf drifted ___ .","The **children** **laughed** → The children laughed ___ .","✦ Bonus: Write a full sentence using an adjective, a vivid verb, AND a WHERE phrase — all three at once!"]},
[{code:"Writing — Sentence Structure (Practice)",label:"Adding where phrases (prepositional phrases)",detail:"NZC Phase 1: students expand sentences by adding prepositional phrases that answer 'where?', building on the two-part sentence from Week 1 with a third element."},{code:"Writing — Vocabulary (Knowledge)",label:"Place/position words (prepositions)",detail:"NZC Phase 1: students develop a bank of place and position words (across, through, under, beside, into, past, along) as the foundation vocabulary for prepositional phrase building."}],
{context:ctx("Word Choice Foundations","13 of 40","Years 3–4 (ages 7–9)","25–30 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:["Sentence Structure: expand sentences with a prepositional phrase answering 'where?'.","Vocabulary: develop a bank of position/place words.","Writing Process: revise a two-part sentence into a three-part sentence.","Metacognition: ask 'where did it happen?' as a self-prompting strategy."],walt:["We are learning to make a sentence more interesting by adding where it happened.","We are learning to use place words like across, through, and beside.","We are learning to write a sentence with three parts: WHO + DID WHAT + WHERE."],successCriteria:["I can find the verb (DID WHAT) in a sentence.","I can add a WHERE phrase after the verb.","My WHERE phrase starts with a place word and tells the reader exactly where."],timing:[{time:"0–7m",title:"Grow with WHERE",phase:"I Do",description:"Teacher builds a sentence in three visible steps on the board: WHO, then DID WHAT, then WHERE. Arrow diagram shows WHERE phrase added after the verb."},{time:"7–14m",title:"Add a WHERE Together",phase:"We Do",description:"Whole class adds WHERE phrases to 3 sentences, voting on the most vivid option. Place word bank on display."},{time:"14–22m",title:"My WHERE Sentences",phase:"You Do",description:"Students grow 3 sentences by adding a WHERE phrase. Place word bank for emerging writers."},{time:"22–28m",title:"Read & Picture It",phase:"Reflect",description:"Students read their full sentence aloud to a partner. Close: adding WHERE helps our reader picture exactly what is happening."}],resources:["Three-part sentence diagram (WHO + DID WHAT + WHERE)","Place word bank poster (across, through, under, beside, into, past, along, over)","Worksheet with 3 sentences"],assessment:["Formative: quality and accuracy of WHERE phrases","Work sample: 3 sentences with WHERE phrases added","Focus: WHERE phrase starts with a place word; adds real locational meaning"],differentiation:[{label:"ESOL learners",note:"Place word bank with simple location illustrations; oral rehearsal."},{label:"Emerging writers",note:"Sentence frames: 'The ___ [verb] ___ the ___.'; place word bank for reference."},{label:"Confident writers",note:"Bonus: write a sentence with adjective + vivid verb + WHERE phrase — all three elements combined."},{label:"Diverse learners",note:"Physical placement game: stand beside, across from, under the table — connecting WHERE words to real physical experience."}],valuesIntegration:{heading:"Aroha — Love",notes:["Adding WHERE is a gift to our reader — it helps them picture exactly where something beautiful happened.","Noticing WHERE things happen — under the pohutukawa, beside the sea — is a way of paying attention to the beautiful, specific details of God's creation."]},reflectionPrompts:["Were students generating vivid WHERE phrases or defaulting to generic options?","Are WHERE phrases adding real locational detail?","Are any students ready to write three-part sentences without scaffolding?"]},"Aroha"),
Thursday:g("Checking Proper Noun Capitals in Our Own Writing","Writing — Punctuation (Practice) & Writing Process (Practice), NZC Phase 1 (Yrs 0–3): students apply a targeted check for proper noun capitals across a short passage.",
{title:"I Do — The Proper Noun Capital Check",instruction:"Today we practise checking for proper noun capitals in a passage — looking for every proper noun, not just names of people.",example:"my family went to **auckland** for christmas. we visited **sky tower** and ate at a cafe called **little bird**.",demonstration:"Is 'auckland' a specific name? Yes — capital A. Is 'christmas' a specific day? Yes — capital C. Is 'sky tower' a specific name? Yes — capital S and T. Is 'little bird' the name of a cafe? Yes — capital L and B.",tip:"Read slowly through your writing. For every noun, ask: is this the SPECIFIC name of someone or something? If yes — give it a capital."},
{title:"We Do — Check This Passage Together",instruction:"Let's read this passage together and find every proper noun that needs a capital letter.",sentences:["we went to easter camp near taupo with our church, grace community church.","my cousin aroha lives in wellington near the beehive.","on saturday i read a book called the magic faraway tree by enid blyton."],prompt:"Is this the specific name of a person, place, day, celebration, or title? If yes — it gets a capital!"},
{title:"You Do — Your Turn",instruction:"Fix each passage by adding capitals to ALL proper nouns. Read slowly and ask: is this a specific name?",tasks:["last sunday we had dinner at nana's house in hamilton. she made her famous hangi.","my teacher mrs chen read us a story about matariki and the seven stars.","my brother levi goes to rangitoto college in auckland.","✦ Bonus: Write 3 sentences about your own week — then swap with a partner and check each other's proper noun capitals."]},
[{code:"Writing — Punctuation (Practice)",label:"Proper noun capital check",detail:"NZC Phase 1: students apply a specific check for proper noun capitalisation across a short passage, moving beyond single-sentence editing to multi-sentence consistency."},{code:"Writing — Writing Process (Practice)",label:"Targeted editing: proper nouns",detail:"NZC Phase 1: students use the 'is it a specific name?' strategy as a targeted editing lens, developing the habit of reading back over their writing with a specific question in mind."}],
{context:ctx("Word Choice Foundations","14 of 40","Years 3–4 (ages 7–9)","25–30 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:["Punctuation: apply proper noun capitals consistently across a short passage.","Writing Process: use a targeted 'is it a specific name?' editing strategy.","Metacognition: read slowly and question each noun independently as a checking habit."],walt:["We are learning to check a passage for proper noun capitals.","We are learning to ask 'is this a specific name?' when we check our own writing.","We are learning that proper nouns include people's names, places, days, and titles."],successCriteria:["I can find proper nouns in a passage (people, places, days, titles).","I can add a capital letter to each proper noun.","I can check my own writing using the 'is it a specific name?' question."],timing:[{time:"0–7m",title:"The Proper Noun Check",phase:"I Do",description:"Teacher reads a passage slowly, pausing at every noun and asking aloud: 'Is this a specific name? — capital!' or 'Is this just a type of thing? — no capital.' Colour-code: proper nouns in blue."},{time:"7–14m",title:"Check Together",phase:"We Do",description:"Whole class reads 3 passages, identifying and fixing proper noun capitals. Buddy conferral; underline-first approach."},{time:"14–22m",title:"My Checking Turn",phase:"You Do",description:"Students fix 3 passages independently. Proper nouns pre-underlined for emerging writers."},{time:"22–28m",title:"Partner Swap Check",phase:"Reflect",description:"Students swap their work with a partner and give one specific piece of feedback."}],resources:["Passages with mixed proper/common noun capitalisation","Colour-coding: blue for proper nouns"],assessment:["Formative: accuracy of proper noun identification in shared passage","Work sample: 3 corrected passages","Focus: all categories of proper noun found; common nouns not incorrectly capitalised"],differentiation:[{label:"ESOL learners",note:"Proper nouns pre-underlined; focus on people's names and places first."},{label:"Emerging writers",note:"Proper nouns pre-underlined; students add capitals only."},{label:"Confident writers",note:"Bonus: swap own 3-sentence writing with a partner for a mutual proper-noun check."},{label:"Diverse learners",note:"Read aloud slowly, pausing at each noun — auditory processing supports the identification step."}],valuesIntegration:{heading:"Mohio & Aroha",notes:["Getting names right — of people, places, and things that matter — is a form of care. It connects to Aroha (honouring people with accurate words) and Mohio (knowing who and what things are).","The partner swap is a Manaaki act: helping someone else get their proper nouns right is a quiet, kind service."]},reflectionPrompts:["Were students able to find ALL categories of proper noun, or only people's names?","Was the 'is it a specific name?' question a useful strategy?","Are students catching their own proper noun capitals during first-draft writing?"]},"Mohio"),
Friday:g("Quiz Day — Week 3 Review","Writing — Vocabulary, Punctuation & Sentence Structure (Practice), NZC Phase 1 (Yrs 0–3): students consolidate said upgrades, proper noun capitals, and WHERE phrases through a team quiz.",
{title:"I Do — What We Learned This Week",instruction:"Before the quiz, let's quickly remind ourselves of the four things we worked on this week.",example:"**People & whanau words** · **Said upgrades** · **Proper noun capitals** · **Adding WHERE**",demonstration:"A great sentence using everything: 'My **grandmother** **whispered** a prayer **in the garden**.' — people word (grandmother), said upgrade (whispered), AND a WHERE phrase (in the garden).",tip:"This week: WHO + HOW they said it + WHERE it happened + capital for every specific name."},
{title:"We Do — Quick Review Together",instruction:"Let's build one brilliant sentence that uses everything from this week.",sentences:["My **nana** **whispered** a blessing **over the kai**.","**Aroha** **announced** excitedly that she'd won, **in front of the whole class**.","My **brother** **laughed** loudly **across the room** and everyone smiled."],prompt:"Can you find the people word, the said upgrade, the WHERE phrase, and any proper nouns?"},
{title:"You Do — Quiz Time!",instruction:"Time to show what you know! Good luck Team Tui and Team Kiwi!",tasks:["Listen carefully to each question.","Your team earns a point for each correct answer.","Be encouraging — cheer for great answers from both teams!","✦ Remember: every question you get right shows how much you've grown as a writer this week!"]},
[{code:"Writing — Vocabulary (Practice)",label:"Said upgrades and people words",detail:"NZC Phase 1: students demonstrate knowledge of speech verb upgrades and people/whanau vocabulary."},{code:"Writing — Punctuation (Practice)",label:"Proper noun capitals",detail:"NZC Phase 1: students apply proper noun capitalisation across people, places, days, and titles."},{code:"Writing — Sentence Structure (Practice)",label:"WHERE phrases in sentences",detail:"NZC Phase 1: students identify and construct WHERE phrases as a sentence expansion strategy."}],
{context:ctx("Word Choice Foundations","15 of 40","Years 3–4 (ages 7–9)","30–35 minutes","~24 students","Christian school, mixed-level, incl. ESOL"),curriculumAlignment:["Vocabulary: said upgrades and people/whanau words.","Punctuation: proper noun capitals for people, places, days, and titles.","Sentence Structure: WHERE phrases as sentence expansion.","Communication: team quiz with sportsmanship and care."],walt:["We are learning to show what we know from the whole week.","We are learning to identify said upgrades, proper nouns, and WHERE phrases.","We are learning to be kind, encouraging team members."],successCriteria:["I can identify a said upgrade, a proper noun, and a WHERE phrase in a sentence.","I can fix proper noun capitals in a short sentence.","I can be an encouraging and kind team member."],timing:[{time:"0–5m",title:"Week 3 Review",phase:"I Do",description:"Quick recap of this week's four skills."},{time:"5–10m",title:"Quick Practice",phase:"We Do",description:"One example question as a class."},{time:"10–30m",title:"Team Quiz",phase:"You Do",description:"16 questions on said upgrades, proper noun capitals, WHERE phrases, and people words."},{time:"30–35m",title:"Celebrate & Reflect",phase:"Reflect",description:"Final scores, applause for both teams. Quick share: which skill was hardest?"}],resources:["Quiz questions on screen","Scoreboard"],assessment:["Formative: observe which question types the class finds hardest"],differentiation:[{label:"ESOL learners",note:"Questions read aloud clearly; team conferral time."},{label:"All learners",note:"Team format; all contribute at their level."}],valuesIntegration:{heading:"All Four Values",notes:["Aroha: writing about and honouring the people we love — our whanau and friends.","Mohio: knowing specific names of people and places, and knowing HOW people speak.","Manaaki: being a generous team member and cheering for both teams.","Panga: our words about people can build them up or let them down — choosing well has real impact."]},reflectionPrompts:["Which question types did the class find hardest?","Are there misconceptions to address in Week 4?","How was team spirit this week?"]},"Aroha")
};

const quiz3=[
{q:"Which is the BEST upgrade for 'said' in 'She said the news quietly so no one else would hear.'?",opts:["announced","whispered","shouted","replied"],ans:1,explanation:"'Whispered' is the best upgrade — it matches speaking quietly so no one would hear. 'Announced' and 'shouted' are the complete opposite!"},
{q:"Which sentence uses a PROPER NOUN correctly?",opts:["I went to a School called parkview primary.","I went to a school called Parkview Primary.","I went to A School called parkview primary.","i went to a school called parkview primary."],ans:1,explanation:"'Parkview Primary' is a specific name — a proper noun — so both words get a capital. 'School' stays lower case because it's just a common noun."},
{q:"Which is the WHERE phrase in 'The bird flew over the hill.'?",opts:["The bird","flew","over the hill","The"],ans:2,explanation:"'Over the hill' is the WHERE phrase — it tells us WHERE the bird flew. WHERE phrases usually start with a place word like over, under, across, through, beside, or into."},
{q:"Which sentence has a said upgrade showing the character was ANGRY?",opts:["She said the words happily.","She whispered the words.","She snapped the words at him.","She announced the words quietly."],ans:2,explanation:"'Snapped' shows anger — it tells us HOW she spoke, and the HOW matches feeling angry. 'Whispered' and 'announced quietly' don't show anger at all."},
{q:"Which word in 'We visited Auckland last Christmas.' is a PROPER NOUN?",opts:["visited","last","Auckland","city"],ans:2,explanation:"'Auckland' is a proper noun — it's the specific name of a city in New Zealand. Proper nouns are always the specific, named version."},
{q:"Which sentence has a WHERE phrase added to make it better?",opts:["The dog ran.","The dog ran and barked.","The dog ran across the field.","The dog, big and fluffy, ran."],ans:2,explanation:"'The dog ran across the field.' has a WHERE phrase — 'across the field' tells us exactly where the dog ran, making the sentence much more vivid."},
{q:"In 'my cousin lives in wellington', which words need capital letters?",opts:["Only 'my'","My and wellington","My and cousin","Only 'wellington'"],ans:1,explanation:"'My' needs a capital because it starts the sentence. 'Wellington' needs a capital because it is a proper noun — the specific name of a city in New Zealand."},
{q:"Which said upgrade best shows a character is EXCITED?",opts:["murmured","sighed","exclaimed","whispered"],ans:2,explanation:"'Exclaimed' shows excitement — it means to say something with energy and enthusiasm. 'Murmured' and 'whispered' are quiet, and 'sighed' shows tiredness or sadness."},
{q:"Which of these is a PROPER NOUN?",opts:["a school","a dog","a city","New Zealand"],ans:3,explanation:"'New Zealand' is a proper noun — it is the specific name of our country. 'A school', 'a dog', and 'a city' are all common nouns — they name types of things, not specific named things."},
{q:"How do you GROW a sentence by adding WHERE?",opts:["Add a describing word before the naming word","Add a place phrase after the verb","Add a full stop at the end","Change the capital letter"],ans:1,explanation:"You grow a sentence with WHERE by adding a place phrase after the verb: 'The cat sat beside the fire.' The WHERE phrase starts with a place word (beside, across, under, through, over)."},
{q:"Which sentence has BOTH a said upgrade AND a proper noun capitalised correctly?",opts:["mia whispered to her friend.","Mia whispered to her friend.","Mia said to her friend.","mia said to her Friend."],ans:1,explanation:"'Mia whispered to her friend.' is correct — 'Mia' is a proper noun (capital M), and 'whispered' is a great said upgrade showing she spoke quietly."},
{q:"Which WHERE phrase would make this sentence MOST vivid? 'The children played ___.'",opts:["somewhere","in a place","across the golden sand dunes","outside"],ans:2,explanation:"'Across the golden sand dunes' is the most vivid WHERE phrase — it gives the reader a clear, detailed picture of exactly where the children played. 'Somewhere' and 'in a place' tell us almost nothing!"},
{q:"Which word would be used as a said upgrade to show someone speaking SADLY?",opts:["shouted","announced","sighed","exclaimed"],ans:2,explanation:"'Sighed' suggests sadness or heaviness in the way someone speaks. 'Shouted' and 'announced' are used for loud or important speech, and 'exclaimed' shows excitement."},
{q:"In 'We go to church every sunday.', which day needs a capital?",opts:["We","church","every","sunday"],ans:3,explanation:"'Sunday' is a proper noun — it's the specific name of a day of the week. All days of the week are proper nouns and need a capital letter."},
{q:"Which sentence uses EVERYTHING from Week 3 — a people word, a said upgrade, and a WHERE phrase?",opts:["The dog ran.","My nana whispered a prayer in the garden.","she said it was good.","My Friend Said hello."],ans:1,explanation:"'My nana whispered a prayer in the garden.' has it all: 'nana' is a people/whanau word, 'whispered' is a said upgrade, and 'in the garden' is a WHERE phrase. A brilliant Week 3 sentence!"},
{q:"Which sentence has a WHERE phrase that STARTS with a place word correctly?",opts:["The bird sang beautiful and loud.","The bird sang, which was nice.","The bird sang above the treetops.","The bird sang a song."],ans:2,explanation:"'Above the treetops' is a WHERE phrase — it starts with the place word 'above' and tells us exactly where the bird sang, helping the reader picture the scene."}
];


/* ===== WEEK 4 ===== */
const week4={
Monday:g("Feeling & Gratitude Words","Writing — Vocabulary (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students build a bank of precise feeling and gratitude words, moving beyond 'happy' and 'sad' to more nuanced emotional vocabulary.",
{title:"I Do — Words That Tell Us How We Feel",instruction:"We can describe feelings with much more detail than just 'happy' or 'sad'. Watch me build a feeling word scale — and then add some special gratitude words too.",example:"happy → **joyful** → **overjoyed** → **grateful** → **blessed**. sad → **disappointed** → **heartbroken** → **lonely**.",demonstration:"'I felt happy' — the reader knows a tiny bit. 'I felt **overjoyed**' — now they really know! And 'I felt **grateful**' tells them something even more specific — that someone did something kind for me. Feeling words let readers step inside our hearts.",tip:"Ask: is this feeling strong or gentle? What caused it? There is almost always a more specific word than happy or sad."},
{title:"We Do — Find a Better Feeling Word",instruction:"Let's upgrade the feeling word in each sentence together. Think about HOW strong the feeling is and WHAT caused it.",sentences:["I felt **happy** when Nana came to visit. → I felt ___ when Nana came to visit.","She was **sad** that the holidays were over. → She was ___ that the holidays were over.","He felt **good** when he helped his little brother. → He felt ___ when he helped his little brother."],prompt:"How strong is the feeling? What would be a more specific or vivid word to describe it?"},
{title:"You Do — Your Turn",instruction:"Upgrade the feeling word in each sentence. Choose a word that tells the reader exactly how the person felt.",tasks:["I felt **happy** at my birthday party.","She felt **sad** when her friend moved away.","He was **glad** that God made the beautiful world.","✦ Bonus: Write your own sentence about a time you felt truly grateful — use the most specific feeling word you can!"]},
[{code:"Writing — Vocabulary (Knowledge)",label:"Feeling and gratitude words",detail:"NZC Phase 1: students build a bank of feeling and gratitude vocabulary, moving beyond high-frequency but low-precision words (happy, sad, good) to more nuanced and expressive alternatives."},{code:"Writing — Vocabulary (Practice)",label:"Applying feeling words in context",detail:"NZC Phase 1: students replace vague feeling words with more precise emotional vocabulary in sentence contexts, building the habit of selecting words that convey specific emotional meaning."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"16 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Vocabulary: build a bank of precise feeling and gratitude words beyond happy, sad, and good.","Vocabulary: match feeling words to their intensity and context (joyful vs content vs grateful).","Communication: share personal experiences using specific emotional vocabulary aloud.","Metacognition: ask 'how strong is this feeling?' and 'what caused it?' as self-prompting strategies."],walt:["We are learning that there are many more interesting words than happy or sad.","We are learning to choose a feeling word that tells the reader exactly how someone felt.","We are learning to use gratitude words to describe thankful feelings."],successCriteria:["I can suggest a more specific word than happy or sad for a given feeling.","I can match a feeling word to its strength (e.g. content vs overjoyed).","I can use a gratitude word like thankful or blessed in a sentence."],timing:[{time:"0-7m",title:"Feeling Word Scale",phase:"I Do",description:"Teacher builds a feeling word scale on the board from gentle to strong (content / pleased / joyful / overjoyed / grateful / blessed). Discusses what causes each. Differentiation: visual scale with simple facial expression icons for ESOL learners."},{time:"7-14m",title:"Upgrade the Feeling",phase:"We Do",description:"Whole class upgrades feeling words in 3 sentences, discussing HOW strong the feeling is and WHAT caused it. Feeling word bank on display; buddy pairing."},{time:"14-22m",title:"My Feeling Words",phase:"You Do",description:"Students upgrade feeling words in 3 sentences. Word bank available for emerging writers; bonus original sentence for confident writers."},{time:"22-28m",title:"Share & Give Thanks",phase:"Reflect",description:"Students share a sentence using a gratitude word. Close: noticing and naming what we are grateful for is a way of acknowledging God's goodness in our lives — connecting to Mohio."}],resources:["Feeling word scale poster (content / pleased / joyful / overjoyed / grateful / blessed / disappointed / heartbroken)","Worksheet with 3 sentences for upgrading","Large lined paper for bonus task"],assessment:["Formative: quality and precision of feeling word upgrades during shared activity","Work sample: 3 sentences with upgraded feeling words","Focus: real improvement in specificity; word matched to the intensity and context of the feeling"],differentiation:[{label:"ESOL learners",note:"Visual feeling word scale with facial expression icons; oral rehearsal before writing; buddy pairing."},{label:"Emerging writers",note:"Feeling word bank sorted by strength; sentence frame: 'I felt ___ when ___'."},{label:"Confident writers",note:"Bonus: write a sentence using a gratitude word AND an upgraded said word — combining Week 3 and Week 4 skills."},{label:"Diverse learners",note:"Physical intensity scale: students place themselves on a line from 'a little' to 'a lot' to feel the difference in emotional intensity before choosing a word."}],valuesIntegration:{heading:"Mohio & Aroha",notes:["Naming our feelings with precision is a form of self-knowledge — connecting to Mohio (knowing who we are) and Aroha (loving self and others well enough to be honest about how we feel).","Gratitude words in particular connect to the Christian practice of giving thanks — noticing and naming the good things God has placed in our lives."]},reflectionPrompts:["Were students choosing really more specific feeling words, or just different common ones?","Did the feeling word scale help students understand emotional intensity?","Are students beginning to use feeling words spontaneously in their own writing?","Which gratitude words resonated most with students — worth keeping on the word wall?"]},"Mohio"),

Tuesday:g("Question Words & Question Marks","Writing — Grammar & Punctuation (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students learn to construct questions using question words (who, what, where, when, why, how) and apply question marks correctly.",
{title:"I Do — Questions Have a Special Shape",instruction:"Questions are sentences too — but they have a special job: asking for information. Questions always end with a question mark, and most start with a question word. Watch me build some.",example:"**Who** is your best friend? **What** did you have for lunch? **Where** do you live? **When** is your birthday? **Why** do you love reading? **How** did you get here?",demonstration:"The six question words are: **who** (a person), **what** (a thing or action), **where** (a place), **when** (a time), **why** (a reason), **how** (a way). Every question ends with a **?** not a full stop. If I accidentally put a full stop, the sentence looks finished — but it's actually asking something!",tip:"Remember the six question words: Who? What? Where? When? Why? How? And always end a question with a ? not a full stop."},
{title:"We Do — Build and Fix Questions",instruction:"Let's build questions together using question words, and fix any that have the wrong punctuation.",sentences:["___ made the beautiful world we live in? (use Who or What)","___ do we go to school? (use Where or When or Why)","___ did the bird fly so high? (use How or Why)"],prompt:"Which question word fits? Does it end with a question mark?"},
{title:"You Do — Your Turn",instruction:"Fix the punctuation in each sentence, and add the right question word to each blank.",tasks:["___ is your favourite book.","___ did you feel when you helped someone today.","___ lives in our classroom as a class pet.","✦ Bonus: Write two questions you would ask God if you could — use two different question words!"]},
[{code:"Writing — Grammar (Knowledge)",label:"Question words: who, what, where, when, why, how",detail:"NZC Phase 1: students learn the six question words as a set and understand that each one asks for a different type of information (person, thing, place, time, reason, manner)."},{code:"Writing — Punctuation (Knowledge & Practice)",label:"Question marks",detail:"NZC Phase 1: students learn that questions must end with a question mark rather than a full stop, and begin applying this consistently in their own writing."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"17 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Grammar: the six question words (who, what, where, when, why, how) each ask for different types of information.","Punctuation: questions end with a question mark, not a full stop.","Sentence Structure: questions are a distinct sentence type with their own structure.","Metacognition: check — is this asking something? If yes, it needs a ?"],walt:["We are learning the six question words: who, what, where, when, why, how.","We are learning that questions always end with a question mark.","We are learning to write a question correctly."],successCriteria:["I can name the six question words.","I can write a question starting with a question word.","I can put a question mark at the end of a question (not a full stop)."],timing:[{time:"0-7m",title:"The Six Question Words",phase:"I Do",description:"Teacher introduces the six question words with a visual poster. Each is demonstrated in a sentence. Differentiation: question word poster stays on display all lesson; ESOL learners match question word to answer type (who = person, where = place)."},{time:"7-14m",title:"Build & Fix Questions",phase:"We Do",description:"Whole class builds questions from sentence starters, selecting the right question word and adding a question mark. Fix three incorrectly punctuated questions together."},{time:"14-22m",title:"My Questions",phase:"You Do",description:"Students add question words and fix punctuation in 3 sentences. Question word poster visible; bonus two-questions task for confident writers."},{time:"22-28m",title:"The Best Question",phase:"Reflect",description:"Students share one question they would ask. Bonus tie-in: what questions do we ask God? Connect to Mohio — asking good questions is a way of seeking to know."}],resources:["Question word poster (Who / What / Where / When / Why / How) with answer-type icons","Worksheet with 3 sentences for question word + punctuation fix","Large lined paper for bonus task"],assessment:["Formative: accuracy of question word selection and question mark placement","Work sample: 3 corrected question sentences","Focus: correct question word choice; question mark at end; capital at start"],differentiation:[{label:"ESOL learners",note:"Question word poster with answer-type icons (person/place/time/reason/thing/manner) kept on display; oral rehearsal; buddy pairing."},{label:"Emerging writers",note:"Question word starter cards (who, what, where, when, why, how) to physically select before writing."},{label:"Confident writers",note:"Bonus: write two questions you would ask God using two different question words."},{label:"Diverse learners",note:"Question word hand gestures (point up for who, open hands for what, etc.) as physical memory cues."}],valuesIntegration:{heading:"Mohio — Know",notes:["Asking good questions is one of the most important ways we learn and grow — it connects directly to Mohio (knowing God, His story, and our place in it).","The bonus question 'What would you ask God?' is a beautiful, low-pressure way to open up conversations about faith, wonder, and seeking to know."]},reflectionPrompts:["Could students consistently identify which question word was needed?","Were students remembering to use ? rather than . at the end of questions?","What questions did students come up with for the bonus task — anything worth exploring further in class?"]},"Mohio"),

Wednesday:g("Adding 'When' to a Sentence","Writing — Sentence Structure (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students expand sentences by adding a time phrase that answers the question 'when?', building on the WHERE phrases from Week 3.",
{title:"I Do — Sentences Can Tell Us When",instruction:"Last week we added WHERE to a sentence. This week we add WHEN — a time phrase that tells the reader exactly when something happened. Watch me grow a sentence with a WHEN phrase.",example:"The **bird** **sang**. → The **bird** sang **in the morning**. → **At sunrise**, the **tiny** bird **sang** **above the treetops**.",demonstration:"Step 1: 'The bird sang.' Step 2: I ask WHEN? — in the morning. I can add the WHEN phrase at the start or at the end: 'The bird sang **in the morning**.' or '**In the morning**, the bird sang.' Both work! Step 3: I can add WHERE and WHEN in the same sentence for a really vivid picture.",tip:"Ask: WHEN did it happen? The answer is usually a time phrase: in the morning, after school, on Saturday, at sunset, during lunch, last summer."},
{title:"We Do — Add a When Phrase",instruction:"Let's grow these sentences by adding a WHEN phrase. Try it at the start AND at the end of a sentence!",sentences:["The **children** **played** → The children played ___ . (when?) OR ___, the children played.","My **dog** **barked** → My dog barked ___ . (when?) OR ___, my dog barked.","We **prayed** **together** → We prayed together ___ . (when?) OR ___, we prayed together."],prompt:"What time phrase could you use? Could you put it at the start OR the end?"},
{title:"You Do — Your Turn",instruction:"Add a WHEN phrase to each sentence. Try using a different position each time — start, end, or both!",tasks:["The **sun** **rose** → add a WHEN phrase.","My **family** **laughed** → add a WHEN phrase.","**God** **made** the world → add a WHEN phrase.","✦ Bonus: Write a sentence that has BOTH a WHERE phrase AND a WHEN phrase — can you fit them both in?"]},
[{code:"Writing — Sentence Structure (Practice)",label:"Adding when phrases (time adverbials)",detail:"NZC Phase 1: students expand sentences by adding time phrases answering 'when?', and discover that time phrases can be placed at the start or end of a sentence — introducing flexible sentence structure."},{code:"Writing — Vocabulary (Knowledge)",label:"Time and sequence words",detail:"NZC Phase 1: students develop a bank of time and sequence phrases (in the morning, at sunset, after school, last summer, on Saturday) as tools for sentence expansion."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"18 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Sentence Structure: expand sentences with a time phrase answering 'when?'.","Sentence Structure: discover that time phrases can be placed at the start or end of a sentence.","Vocabulary: develop a bank of time phrases (in the morning, at sunset, after school, last summer).","Writing Process: use a grow-a-sentence technique to revise two-part sentences into richer three-part sentences."],walt:["We are learning to make a sentence richer by adding when it happened.","We are learning that a WHEN phrase can go at the start OR the end of a sentence.","We are learning to write a sentence with WHO + DID WHAT + WHEN (or WHEN + WHO + DID WHAT)."],successCriteria:["I can add a WHEN phrase to a sentence.","I can put the WHEN phrase at the start or at the end of a sentence.","My WHEN phrase tells the reader exactly when something happened."],timing:[{time:"0-7m",title:"Grow with WHEN",phase:"I Do",description:"Teacher grows a sentence in two ways on the board: WHEN phrase at the end, then at the start. Shows that both work. Arrow diagram highlights where the WHEN phrase slots in. Differentiation: time phrase bank displayed; ESOL learners given a clock/calendar visual alongside the time phrases."},{time:"7-14m",title:"Add a WHEN Together",phase:"We Do",description:"Whole class adds WHEN phrases to 3 sentences, experimenting with start and end positions. Vote on which sounds best. Time phrase bank on display."},{time:"14-22m",title:"My WHEN Sentences",phase:"You Do",description:"Students grow 3 sentences by adding a WHEN phrase. Time phrase bank for emerging writers; bonus WHERE + WHEN sentence for confident writers."},{time:"22-28m",title:"Read & Compare",phase:"Reflect",description:"Students read their sentence with WHEN at the start vs. the end — which sounds better? Close: noticing WHEN things happen helps us tell the story of God's world more clearly."}],resources:["Grow-a-sentence diagram (WHO + DID WHAT + WHEN / WHEN + WHO + DID WHAT)","Time phrase bank (in the morning, at sunset, after school, last summer, on Saturday, during breakfast)","Worksheet with 3 sentences"],assessment:["Formative: quality and variety of WHEN phrases during shared practice","Work sample: 3 sentences with WHEN phrases added","Focus: WHEN phrase at start or end (not stuck in middle); real time meaning conveyed"],differentiation:[{label:"ESOL learners",note:"Time phrase bank with clock/calendar visual; oral rehearsal; buddy pairing."},{label:"Emerging writers",note:"Sentence frames: 'The ___ [verb] ___ .' and '___, the ___ [verb].'; time phrase bank."},{label:"Confident writers",note:"Bonus: write a sentence with BOTH a WHERE phrase AND a WHEN phrase."},{label:"Diverse learners",note:"Physical timeline on the floor — students stand at different points (morning, afternoon, night) and say their WHEN phrase aloud before writing."}],valuesIntegration:{heading:"Mohio — Know",notes:["Noticing WHEN things happen — at sunrise, after church, during our meal together — is a way of paying attention to the rhythm God built into our days and seasons.","The sentence 'God made the world' + a WHEN phrase gives students a beautiful opportunity to engage with creation language."]},reflectionPrompts:["Were students confidently placing the WHEN phrase at both the start and end of a sentence?","Were the WHEN phrases adding real time detail or defaulting to 'in the day'?","Are any students starting to use both WHERE and WHEN phrases in the same sentence without prompting?","Is the class ready to begin combining all three parts (WHO + WHERE + WHEN) next week?"]},"Mohio"),

Thursday:g("Read-Aloud Check — Full Sentence Flow","Writing — Writing Process (Practice), NZC Phase 1 (Yrs 0-3): students apply a comprehensive read-aloud check across a short passage, listening for capitals, full stops, proper nouns, question marks, and sentence flow.",
{title:"I Do — The Full Check",instruction:"By now we know lots of things to check in our writing: capitals, full stops, proper noun capitals, and question marks. Today we listen for all of them at once using our read-aloud checking strategy.",example:"on saturday my friend lily asked me a question. she said what is your favourite animal. i told her i loved dogs. then lily said she loved cats.",demonstration:"I read it aloud slowly. I hear: 'on saturday' — capital O for start, capital S for Saturday (it's a day). 'lily' — capital L, it's a name. 'what is your favourite animal' — this is a question, needs a question mark! 'i told her' — capital I. Let me fix it all: 'On **Saturday** my friend **Lily** asked me a question. She said, \"**W**hat is your favourite animal?\" **I** told her I loved dogs. Then **Lily** said she loved cats.'",tip:"Check one thing at a time: (1) Capital at the start of each sentence? (2) Full stop or ? at the end? (3) Capital for any proper nouns? (4) Does every sentence make sense when read aloud?"},
{title:"We Do — Full Check Together",instruction:"Let's read this passage aloud together and fix everything we can find — capitals, full stops, proper nouns, and question marks.",sentences:["last sunday we went to see mrs brown at the hospital. she asked how are you feeling. we told her we missed her at church.","in the holidays my cousin jake came to visit. mum asked him what would you like to do today. we went to lake taupo.","my teacher asked us to write about our favourite day. i wrote about the day nana came from hamilton."],prompt:"Read slowly! What is missing — a capital, a full stop, a proper noun capital, or a question mark?"},
{title:"You Do — Your Turn",instruction:"Apply the full check to each passage. Read aloud, then fix: capital at the start, full stop or ? at the end, proper noun capitals, question marks for questions.",tasks:["yesterday my friend aroha said can you help me. i said yes of course. we worked together for a long time.","last week mrs jones read us a story about matariki. she asked us what do you know about the stars. i knew lots.","on friday we went to wellington. dad asked do you want to see the beehive. it was amazing.","✦ Bonus: Swap your fixed passage with a partner — can they find anything you missed?"]},
[{code:"Writing — Writing Process (Practice)",label:"Comprehensive read-aloud checking",detail:"NZC Phase 1: students apply a multi-item read-aloud check across a short passage, integrating knowledge of sentence capitals, full stops, proper noun capitals, and question marks in a single editing pass."},{code:"Writing — Punctuation (Practice)",label:"Integrating multiple punctuation rules",detail:"NZC Phase 1: students apply capitals, full stops, proper noun capitals, and question marks in combination, moving toward the integrated punctuation checking expected in Phase 2."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"19 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Writing Process: apply a comprehensive read-aloud check covering all punctuation learned so far.","Punctuation: integrate capitals, full stops, proper noun capitals, and question marks in a single editing pass.","Metacognition: work through a mental checklist item by item, rather than checking everything at once."],walt:["We are learning to check a passage for all the punctuation rules we have learned.","We are learning to read aloud slowly and fix one type of punctuation at a time.","We are learning to check for: capitals, full stops, proper noun capitals, and question marks."],successCriteria:["I can read a passage aloud and hear where corrections are needed.","I can fix capitals, full stops, proper noun capitals, and question marks in a short passage.","I can check my partner's writing using the full checklist."],timing:[{time:"0-7m",title:"The Full Check Routine",phase:"I Do",description:"Teacher displays the four-item checklist on the board: (1) Capital at the start, (2) Full stop or ? at the end, (3) Proper noun capitals, (4) Question mark for questions. Models the full check on one passage."},{time:"7-14m",title:"Check Together",phase:"We Do",description:"Whole class reads 3 passages together, working through the checklist item by item. Students call out fixes one at a time."},{time:"14-22m",title:"My Full Check",phase:"You Do",description:"Students fix 3 passages independently using the four-item checklist. Checklist card provided for all students; pre-underlined proper nouns for emerging writers."},{time:"22-28m",title:"Partner Swap",phase:"Reflect",description:"Students swap passages with a partner and check each other's work using the checklist. Celebrate: our writing gets better every time we take care to check it."}],resources:["Four-item checklist card (1. Capital at start, 2. Full stop or ? at end, 3. Proper noun capitals, 4. Question marks for questions)","Passages with multiple errors","Students' earlier week writing (optional for bonus task)"],assessment:["Formative: accuracy of multi-item check during shared activity","Work sample: 3 corrected passages","Focus: all four items consistently applied; no items missed"],differentiation:[{label:"ESOL learners",note:"Checklist card with visual icons for each rule; line-by-line approach; buddy support."},{label:"Emerging writers",note:"Proper nouns pre-underlined; students focus on 2 items at a time rather than all 4 at once."},{label:"Confident writers",note:"Bonus: apply the full check to their own earlier writing from this week."},{label:"Diverse learners",note:"Read aloud to a partner — auditory and oral processing makes errors easier to hear."}],valuesIntegration:{heading:"Manaaki — Serve",notes:["Taking time to check our writing carefully — and to check a partner's writing kindly — is a form of Manaaki. We are giving our reader the gift of clear, well-crafted writing.","The partner swap reflects the idea that we can serve each other with our attention and care, not just our actions."]},reflectionPrompts:["Were students able to apply all four checklist items independently?","Which checklist item was missed most often — worth extra practice in Week 5?","Did the partner swap produce kind, specific feedback?","Are students beginning to integrate these checks into their first-draft writing?"]},"Manaaki"),

Friday:g("Quiz Day — Week 4 Review","Writing — Vocabulary, Grammar, Sentence Structure & Punctuation (Practice), NZC Phase 1 (Yrs 0-3): consolidate feeling words, question words, WHEN phrases, and the full read-aloud check through a team quiz.",
{title:"I Do — What We Learned This Week",instruction:"Before the quiz, let's quickly remind ourselves of the four things we worked on this week.",example:"**Feeling & gratitude words** · **Question words & marks** · **Adding WHEN** · **Full read-aloud check**",demonstration:"A great sentence using this week's learning: 'At sunrise, I felt **overjoyed** as the tiny bird sang above the treetops.' — WHEN phrase (at sunrise), precise feeling word (overjoyed), and it would pass our full check: capital, full stop, no proper noun errors.",tip:"This week: WHEN did it happen? HOW exactly did they feel? Is this a question? Did I check all four things?"},
{title:"We Do — Quick Review Together",instruction:"Let's build one brilliant sentence or question that uses everything from this week.",sentences:["**After church**, I felt **grateful** for my whole **whanau**.","**At sunset on Saturday**, the **tiny** bird **soared** above **Queenstown**.","She **whispered**, '**W**hy is the world so beautiful?'"],prompt:"Can you find the WHEN phrase, the feeling word, the proper noun, and the question mark?"},
{title:"You Do — Quiz Time!",instruction:"Time to show what you know! Good luck Team Tui and Team Kiwi!",tasks:["Listen carefully to each question.","Your team earns a point for each correct answer.","Be encouraging — cheer for great answers from both teams!","✦ Remember: every correct answer is proof of how much you've grown as a writer this term!"]},
[{code:"Writing — Vocabulary (Practice)",label:"Feeling and gratitude words in context",detail:"NZC Phase 1: students demonstrate knowledge of precise feeling and gratitude vocabulary in a quiz context."},{code:"Writing — Grammar & Punctuation (Practice)",label:"Question words and question marks",detail:"NZC Phase 1: students apply knowledge of the six question words and correct question mark usage."},{code:"Writing — Sentence Structure (Practice)",label:"WHEN phrases in sentences",detail:"NZC Phase 1: students identify and construct WHEN phrases (time adverbials) as a sentence expansion strategy."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"20 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"30-35 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Vocabulary: precise feeling and gratitude words.","Grammar: six question words and question mark usage.","Sentence Structure: WHEN phrases as sentence expansion.","Writing Process: comprehensive four-item punctuation check.","Communication: team quiz with encouragement and sportsmanship."],walt:["We are learning to show what we know from the whole week.","We are learning to identify feeling words, question words, and WHEN phrases.","We are learning to be kind, encouraging team members."],successCriteria:["I can identify feeling words, question words, and WHEN phrases.","I can fix punctuation errors including question marks.","I can be an encouraging and kind team member."],timing:[{time:"0-5m",title:"Week 4 Review",phase:"I Do",description:"Quick recap of this week's four skills."},{time:"5-10m",title:"Quick Practice",phase:"We Do",description:"One example question as a class."},{time:"10-30m",title:"Team Quiz",phase:"You Do",description:"16 questions on feeling words, question words, WHEN phrases, and full punctuation check."},{time:"30-35m",title:"Celebrate & Reflect",phase:"Reflect",description:"Final scores, applause for both teams. Quick share: what was the most interesting thing you learned this week?"}],resources:["Quiz questions on screen","Scoreboard"],assessment:["Formative: observe which question types the class finds hardest","Note: are question marks and feeling word precision still weak? Plan spiral revisit in coming weeks."],differentiation:[{label:"ESOL learners",note:"Questions read aloud clearly; team conferral time."},{label:"All learners",note:"Team format; all contribute at their level."}],valuesIntegration:{heading:"All Four Values",notes:["Aroha: feeling words help us love others better — when we name how we feel, we help people understand us.","Mohio: question words are tools for seeking to know God, His story, and our world.","Manaaki: being a generous team member; checking our writing carefully is a gift to our reader.","Panga: our words — how precisely we describe feelings — have real impact on whether others understand us."]},reflectionPrompts:["Which question types did the class find hardest?","Are there misconceptions to address in Week 5?","How was team spirit? Any students to encourage especially?"]},"Mohio")
};

const quiz4=[
{q:"Which is the MOST precise upgrade for 'happy' in 'I felt happy when Nana came to visit.'?",opts:["quite happy","good","overjoyed","fine"],ans:2,explanation:"'Overjoyed' is the most precise and vivid upgrade — it tells the reader this was a very strong, joyful feeling. 'Quite happy' and 'fine' are actually less vivid than 'happy'!"},
{q:"Which of these is a GRATITUDE word?",opts:["annoyed","grateful","excited","lonely"],ans:1,explanation:"'Grateful' is a gratitude word — it describes a feeling of thankfulness for something someone has done or given. It is much more specific than just 'happy'."},
{q:"Which question word asks about a PLACE?",opts:["Who","What","Where","When"],ans:2,explanation:"'Where' asks about a place — for example, 'Where do you live?' or 'Where did you go?' Each question word asks for a different type of information."},
{q:"Which sentence uses a question mark CORRECTLY?",opts:["Where do you live.","Where do you live!","Where do you live?","where do you live?"],ans:2,explanation:"'Where do you live?' is correct — it starts with a capital letter and ends with a question mark. Questions always end with ? not . or !, and they start with a capital."},
{q:"Which is the WHEN phrase in 'At sunrise, the bird began to sing.'?",opts:["At sunrise","the bird","began to sing","to sing"],ans:0,explanation:"'At sunrise' is the WHEN phrase — it tells us exactly WHEN the bird began to sing. WHEN phrases can be placed at the start or end of a sentence."},
{q:"Which feeling word shows the STRONGEST sadness?",opts:["a bit sad","disappointed","heartbroken","not happy"],ans:2,explanation:"'Heartbroken' shows the strongest and most specific sadness — it tells the reader this was a very deep, painful feeling. 'Disappointed' is less intense, and 'a bit sad' is the least intense of all."},
{q:"Which question word asks about a REASON?",opts:["Who","Where","Why","What"],ans:2,explanation:"'Why' asks for a reason — for example, 'Why did you do that?' or 'Why do birds sing?' Each of the six question words (who, what, where, when, why, how) asks for a different type of information."},
{q:"Where can a WHEN phrase be placed in a sentence?",opts:["Only at the very end","Only at the very start","At the start OR at the end","Only in the middle"],ans:2,explanation:"A WHEN phrase can go at the START: 'In the morning, the bird sang.' OR at the END: 'The bird sang in the morning.' Both are correct! This gives writers flexible choices about how to begin their sentences."},
{q:"Which sentence has BOTH a WHEN phrase AND a correct capital letter for a proper noun?",opts:["on saturday, aroha sang.","On Saturday, Aroha sang.","On Saturday, aroha sang.","on Saturday, Aroha sang."],ans:1,explanation:"'On Saturday, Aroha sang.' is correct — 'On' has a capital because it starts the sentence, 'Saturday' has a capital because it is a proper noun (a specific day), and 'Aroha' has a capital because it is a person's name."},
{q:"Which sentence has a QUESTION that is punctuated correctly?",opts:["She asked what time it was.","She asked, What time is it?","She asked, \"What time is it?\"","she asked what time it was?"],ans:2,explanation:"'She asked, \"What time is it?\"' is the best-punctuated option — the question has a capital W and ends with a question mark inside the speech marks. A question needs its own ? mark."},
{q:"Which is the MOST specific feeling word for 'I felt glad that God made the beautiful world'?",opts:["okay","glad","grateful and blessed","fine"],ans:2,explanation:"'Grateful and blessed' is the most specific — it tells the reader this is a deep feeling of thankfulness connected to a sense of God's goodness. 'Okay' and 'fine' actually reduce the meaning!"},
{q:"Which question word asks HOW something was done?",opts:["Who","When","Where","How"],ans:3,explanation:"'How' asks about the way something was done — for example, 'How did you get here?' or 'How does a bird fly?' It's asking for the manner or method, not a person, place, or time."},
{q:"Which sentence CORRECTLY has a WHEN phrase at the START?",opts:["The bird sang at sunrise.","At sunrise the bird, sang.","At sunrise, the bird sang.","The bird, at sunrise, sang."],ans:2,explanation:"'At sunrise, the bird sang.' is correct — the WHEN phrase ('At sunrise') is at the start, followed by a comma, then the rest of the sentence. The comma after a fronted time phrase is an important convention."},
{q:"In this passage, which sentence needs a question mark? 'My friend asked if I wanted to play. I said yes. She asked what game we should choose.'",opts:["My friend asked if I wanted to play.","I said yes.","She asked what game we should choose.","All three sentences need question marks."],ans:2,explanation:"'She asked what game we should choose' is the indirect question that most clearly needs a question mark — 'what game we should choose' is a question being asked. The third sentence ends with a question that needs a ?."},
{q:"Which WHEN phrase adds the MOST vivid time detail to 'The children played'?",opts:["one day","then","just before the sun dipped below the hills","outside"],ans:2,explanation:"'Just before the sun dipped below the hills' is the most vivid and specific WHEN phrase — it gives the reader a beautiful, precise picture of exactly when the children played. 'One day' and 'then' are almost meaningless!"},
{q:"Which sentence uses EVERYTHING from Week 4 — a feeling word, a WHEN phrase, and correct punctuation?",opts:["i was happy at saturday","At sunrise on Saturday, I felt overjoyed.","She asked where are we going","on friday mia felt sad"],ans:1,explanation:"'At sunrise on Saturday, I felt overjoyed.' has it all: 'At sunrise on Saturday' is a vivid WHEN phrase, 'overjoyed' is a precise feeling word, and the sentence has a capital at the start and a full stop at the end. A perfect Week 4 sentence!"}
];


/* ===== WEEK 5 ===== */
const week5={
Monday:g("Movement Words — Plain to Precise","Writing — Vocabulary (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students replace plain, all-purpose movement verbs (went, moved, ran) with precise, vivid alternatives that paint a clearer picture of exactly how something moved.",
{title:"I Do — How Did They Move? The Precise Word Matters",instruction:"This week we take verb upgrades to the next level. Plain movement words like 'went', 'moved', and 'ran' don't tell us much at all. Watch me upgrade them to words that actually show HOW something moved.",example:"went → **strolled** / **sprinted** / **crept** / **trudged** / **bounded**. ran → **dashed** / **bolted** / **skipped** / **stumbled** / **charged**.",demonstration:"'The dog went across the field' — we know the dog moved, but HOW? Slowly? Fast? Happily? 'The dog **bounded** across the field' — now I can picture it! 'Bounded' tells me the dog was leaping joyfully. The right movement word makes the reader see the action.",tip:"Ask: was it fast or slow? Smooth or clumsy? Happy or scared? Sneaky or bold? Your answer points to the right movement word."},
{title:"We Do — Upgrade the Movement Word",instruction:"Let's upgrade the plain movement word in each sentence together. Think about HOW they were moving — fast, slow, happy, scared, tired?",sentences:["The **children** **went** to the playground. (happily? quickly? reluctantly?)","The **cat** **moved** across the roof. (quietly? carefully? boldly?)","My **grandmother** **walked** to the letterbox. (slowly? happily? painfully?)"],prompt:"HOW did they move? Was it fast, slow, happy, sneaky, careful, joyful, heavy? Find the word that shows exactly that!"},
{title:"You Do — Your Turn",instruction:"Replace the plain movement word with a precise, vivid alternative. Think about HOW the movement happened.",tasks:["The **bird** **went** from branch to branch.","The **boy** **ran** when he heard the bell.","She **walked** into the room full of people.","✦ Bonus: Write your own sentence using the most vivid movement word you can find — try to surprise us with your choice!"]},
[{code:"Writing — Vocabulary (Knowledge)",label:"Precise movement verbs",detail:"NZC Phase 1: students develop a rich bank of movement verbs as a subset of verb upgrading, learning that different movement words convey both speed and manner of movement simultaneously."},{code:"Writing — Vocabulary (Practice)",label:"Applying precise movement words",detail:"NZC Phase 1: students replace plain movement verbs (went, moved, ran, walked) with precise alternatives that convey how the movement happened, building on the verb upgrade work from Week 2."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"21 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Vocabulary: develop a rich bank of movement verbs that encode both speed and manner.","Vocabulary: replace plain movement words (went, moved, ran) with precise alternatives.","Communication: discuss HOW something moved — connecting physical experience to word choice.","Metacognition: ask 'fast or slow? smooth or clumsy? happy or scared?' as a self-prompting strategy before selecting a movement word."],walt:["We are learning that movement words can tell us HOW something moved, not just that it moved.","We are learning to replace plain words like 'went' and 'ran' with more vivid movement words.","We are learning to think about HOW something moved before choosing a word."],successCriteria:["I can identify a plain movement word in a sentence.","I can suggest a more precise movement word that shows HOW the movement happened.","My movement word tells the reader something about the speed, manner, or feeling of the movement."],timing:[{time:"0-7m",title:"Movement Word Scale",phase:"I Do",description:"Teacher mimes different types of movement (creep, bound, trudge, sprint, saunter) and students guess the word. Then teacher places them on a scale from slow to fast and sneaky to bold. Differentiation: physical mime makes the nuance concrete for ESOL learners and kinaesthetic learners."},{time:"7-14m",title:"Upgrade Together",phase:"We Do",description:"Whole class upgrades movement words in 3 sentences, discussing HOW the character was moving. Movement word bank on display; buddy pairing for discussion before writing."},{time:"14-22m",title:"My Movement Words",phase:"You Do",description:"Students upgrade plain movement words in 3 sentences. Movement word bank available for emerging writers; bonus original sentence for confident writers."},{time:"22-28m",title:"Share & Act It Out",phase:"Reflect",description:"Students share their upgraded sentence — the class mimes the movement. If the class can act it out correctly, the word was precise enough! Close: choosing precise movement words is a way of paying careful attention to the world God made."}],resources:["Movement word poster sorted by manner: creep/slink/tiptoe / stroll/wander/saunter / stride/march / dash/sprint/bolt / bound/leap/skip / trudge/shuffle/limp","Worksheet with 3 sentences","Large lined paper for bonus task"],assessment:["Formative: quality and precision of movement word upgrades; mime check in the reflect stage","Work sample: 3 sentences with upgraded movement words","Focus: movement word encodes HOW as well as the basic act of moving"],differentiation:[{label:"ESOL learners",note:"Physical mime of each movement word before writing; movement word poster with simple action drawings."},{label:"Emerging writers",note:"Movement word bank with 4-5 clearly illustrated options per sentence."},{label:"Confident writers",note:"Bonus sentence must use a movement word AND a WHERE phrase or WHEN phrase — combining Week 3/4 and Week 5 skills."},{label:"Diverse learners",note:"Mime check in the reflect stage is inclusive — all students can participate regardless of writing ability."}],valuesIntegration:{heading:"Aroha — Love",notes:["Paying careful attention to HOW things move — joyfully, painfully, nervously — is a form of noticing and caring about the world and the people in it. This connects to Aroha.","The mime activity builds empathy: when we embody how someone else moves, we understand them better."]},reflectionPrompts:["Were students choosing movement words that encode HOW, or just replacing 'went' with 'walked'?","Did the mime check reveal any mismatches between the word chosen and the actual manner of movement?","Which movement words were most creative? Worth adding to the class word wall?","Are students applying movement word upgrades spontaneously in their own writing?"]},"Aroha"),

Tuesday:g("Plural Nouns & Punctuation Recap","Writing — Grammar (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students learn how to form plural nouns (adding -s and -es), and revisit the full punctuation toolkit learned so far in a quick-fire recap.",
{title:"I Do — One or More Than One: Making Plural Nouns",instruction:"When we want to talk about more than one thing, we use a plural noun. Most nouns just add -s, but some need -es. Watch me show the difference.",example:"One **dog** → two **dogs**. One **cat** → three **cats**. One **bush** → two **bushes**. One **box** → four **boxes**. One **church** → many **churches**.",demonstration:"Most naming words just add **-s**: dog → dogs, bird → birds, tree → trees. But naming words that end in -s, -sh, -ch, or -x need **-es**: bush → bushes, church → churches, box → boxes, glass → glasses. Try saying 'boxs' — it sounds wrong! Your ear tells you it needs -es.",tip:"Say the plural word aloud. If it sounds natural, it's probably right. If it sounds wrong, try adding -es instead of -s."},
{title:"We Do — Make Them Plural",instruction:"Let's make each naming word plural together — decide if it needs -s or -es.",sentences:["One **wish** → two ___ (wish + ?)","One **bird** → many ___ (bird + ?)","One **bench** → three ___ (bench + ?)"],prompt:"Does it need -s or -es? Say it aloud and listen — which sounds right?"},
{title:"You Do — Your Turn",instruction:"Write the plural form of each naming word. Then write a short sentence using the plural word.",tasks:["**box** → ___ (write the plural, then use it in a sentence)","**church** → ___ (write the plural, then use it in a sentence)","**star** → ___ (write the plural, then use it in a sentence)","✦ Bonus: Write a sentence that uses TWO different plural nouns and a vivid verb. Can you include a WHERE or WHEN phrase too?"]},
[{code:"Writing — Grammar (Knowledge)",label:"Plural nouns: -s and -es",detail:"NZC Phase 1: students learn the two most common patterns for forming plural nouns — adding -s (default) and adding -es after words ending in -s, -sh, -ch, or -x — using oral rehearsal as a checking strategy."},{code:"Writing — Punctuation (Practice)",label:"Punctuation recap: capitals, full stops, proper nouns, question marks",detail:"NZC Phase 1: students consolidate all punctuation learned in Weeks 1-4 in a fast-paced recap activity, reinforcing the four-item checklist from Week 4 Thursday."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"22 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Grammar: form plural nouns by adding -s (default) or -es (after -s, -sh, -ch, -x endings).","Grammar: use oral rehearsal ('say it aloud') as a checking strategy for plural form.","Punctuation: rapid recap of the four punctuation rules learned in Weeks 1-4.","Metacognition: use oral rehearsal to check plural form; use the four-item checklist to check punctuation."],walt:["We are learning to make naming words plural by adding -s or -es.","We are learning that our ear can help us choose the right plural ending.","We are reviewing all the punctuation rules we have learned so far."],successCriteria:["I can add -s or -es to make a naming word plural.","I can say a plural word aloud to check if it sounds right.","I can identify and fix at least three types of punctuation error."],timing:[{time:"0-7m",title:"Plural Patterns",phase:"I Do",description:"Teacher builds a two-column board: -s words and -es words. Demonstrates the 'say it aloud' rule — 'boxs' vs 'boxes'. Differentiation: say-aloud rule is particularly accessible for students with strong oral English."},{time:"7-14m",title:"Make Them Plural Together",phase:"We Do",description:"Whole class makes 3 naming words plural, voting on -s or -es and justifying with the 'say it aloud' check. Then quick-fire punctuation recap: teacher reads a sentence with an error, students call out the fix."},{time:"14-22m",title:"My Plurals & Punctuation",phase:"You Do",description:"Students complete plural task (make 3 words plural and use in a sentence). Differentiation: -s/-es category cards for emerging writers; bonus complex sentence for confident writers."},{time:"22-28m",title:"Quick-Fire Recap",phase:"Reflect",description:"Fast-paced whole-class punctuation recap — teacher displays sentences with single errors, students write or call out the fix. Close: every rule we've learned makes our writing clearer and more respectful of our reader."}],resources:["-s and -es word pattern chart","Worksheet with 3 naming words for plural practice","Quick-fire punctuation recap sentences (on board)"],assessment:["Formative: accuracy of -s vs -es plural selection; oral check used correctly","Work sample: 3 plural words used correctly in sentences","Focus: correct plural ending; punctuation recap accuracy"],differentiation:[{label:"ESOL learners",note:"-s/-es category cards; say-aloud rule is very accessible for strong oral learners; buddy pairing."},{label:"Emerging writers",note:"Focus on -s plurals first; -es introduced as an extension."},{label:"Confident writers",note:"Bonus: write a sentence using two plurals, a vivid movement verb, and a WHERE or WHEN phrase."},{label:"Diverse learners",note:"Say-aloud check is multi-sensory and benefits auditory and kinaesthetic learners."}],valuesIntegration:{heading:"Manaaki — Serve",notes:["Using correct grammar — including plural forms — is a way of serving our reader. When we get plurals right, our meaning is clear and our reader doesn't have to work hard to understand us.","The quick-fire recap connects to Manaaki too: we are reinforcing the habits that help us give our reader the clearest, most considerate writing we can."]},reflectionPrompts:["Were students correctly distinguishing -s from -es? Did the say-aloud rule help?","Which punctuation rules still showed weaknesses in the quick-fire recap?","Are there any rules that need a dedicated spiral revisit in Week 10?"]},"Manaaki"),

Wednesday:g("Joining Two Short Sentences with 'And'","Writing — Sentence Structure (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students learn to join two short, related sentences into one longer compound-style sentence using the conjunction 'and', as the first step toward compound sentences.",
{title:"I Do — Two Sentences Can Become One",instruction:"Sometimes two short sentences are about the same thing and can be joined together. The simplest way to join them is with the word 'and'. Watch me try it.",example:"The **dog** barked. The **cat** ran away. → The **dog** barked **and** the **cat** ran away.",demonstration:"I have two short sentences: 'The dog barked.' and 'The cat ran away.' They are connected — the dog's barking caused the cat to run. I can join them with 'and': 'The dog barked **and** the cat ran away.' Now it is one sentence with two connected ideas. Notice: no full stop between them — just 'and'. The full stop goes at the very end.",tip:"Before you join two sentences with 'and', ask: are these two ideas connected? If yes, 'and' can join them into one longer sentence."},
{title:"We Do — Join These Sentences",instruction:"Let's join each pair of short sentences together using 'and'. Remember — one full stop at the very end!",sentences:["The **sun** shone. The **birds** sang. → ___","My **friend** laughed. **I** smiled too. → ___","The **rain** fell. The **flowers** grew. → ___"],prompt:"Are these two ideas connected? Can we use 'and' to join them? Where does the full stop go?"},
{title:"You Do — Your Turn",instruction:"Join each pair of short sentences into one sentence using 'and'. Make sure there is only ONE full stop — at the very end!",tasks:["The **wind** blew. The **leaves** danced.","**Aroha** sang a song. **Levi** played the guitar.","God made the **mountains**. God made the **sea**.","✦ Bonus: Write your own pair of short sentences about things you love, then join them with 'and'. Try to include an adjective or a vivid verb!"]},
[{code:"Writing — Sentence Structure (Knowledge)",label:"Joining sentences with 'and' (coordination)",detail:"NZC Phase 1: students learn to join two short, related sentences using the conjunction 'and', as an introduction to compound sentence structure and the first step toward the compound sentence work expected in Phase 2."},{code:"Writing — Sentence Structure (Practice)",label:"Constructing compound-style sentences",detail:"NZC Phase 1: students produce joined sentences using 'and', ensuring only one capital at the start and one full stop at the end of the combined sentence."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"23 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Sentence Structure: join two short, related sentences using the conjunction 'and'.","Punctuation: a joined sentence has one capital at the start and one full stop at the end — not two full stops.","Grammar: introduce 'and' as a conjunction (a joining word).","Writing Process: use joining as a revision strategy — short choppy sentences can be smoothed and enriched."],walt:["We are learning to join two short sentences using the word 'and'.","We are learning that a joined sentence has only ONE full stop at the very end.","We are learning to check that the two ideas are connected before joining them."],successCriteria:["I can join two short sentences using 'and'.","I can make sure there is only one full stop at the end of the joined sentence.","I can check that the two ideas are connected before I join them."],timing:[{time:"0-7m",title:"Two Into One",phase:"I Do",description:"Teacher writes two short sentences on the board, then physically slides them together with 'and' on a card. Shows where the full stop moves to. Differentiation: physical card manipulation is concrete for visual and kinaesthetic learners."},{time:"7-14m",title:"Join Together",phase:"We Do",description:"Whole class joins 3 sentence pairs, sliding cards together and deciding where the full stop goes. Differentiation: sentence cards for physical manipulation; buddy pairing."},{time:"14-22m",title:"My Joined Sentences",phase:"You Do",description:"Students join 3 sentence pairs using 'and'. Emerging writers use sentence cards; confident writers write their own pairs then join them."},{time:"22-28m",title:"Read & Check",phase:"Reflect",description:"Students read their joined sentence to a partner, who checks: one full stop? Does 'and' connect two related ideas? Close: joining sentences is like building bridges — connecting two things makes both stronger."}],resources:["Sentence card pairs (two short sentences on separate cards that can be physically joined)","Conjunction card: 'and'","Worksheet with 3 sentence pairs","Large lined paper for bonus task"],assessment:["Formative: accuracy of joining (one full stop; correct use of 'and')","Work sample: 3 joined sentences","Focus: single full stop at end; two related ideas joined; no double full stop in the middle"],differentiation:[{label:"ESOL learners",note:"Physical card manipulation; sentence pairs provided (not generated); buddy support."},{label:"Emerging writers",note:"Sentence cards for physical sliding before writing; focus on single full stop placement."},{label:"Confident writers",note:"Write their own sentence pairs then join them; try adding an adjective or vivid verb to one of the parts."},{label:"Diverse learners",note:"Physical card-sliding is inclusive and kinaesthetic; bridging metaphor in the reflect stage is visual and memorable."}],valuesIntegration:{heading:"Panga — Impact",notes:["Joining two ideas together with 'and' is a small picture of how connection and relationship make things stronger and more complete.","The sentence 'God made the mountains and God made the sea' gives a beautiful opportunity to reflect on the completeness and generosity of creation — connecting to Panga (bringing God's kingdom) and Aroha (love for the world)."]},reflectionPrompts:["Were students correctly placing only one full stop at the end of the joined sentence?","Did students check that the two ideas were connected before joining?","Are any students ready to use 'but' or 'so' as joining words — a natural next step for confident writers?","Is the class ready to explore 'but' as a contrasting joining word in Week 6?"]},"Panga"),

Thursday:g("Fix-It — Full Checking Routine","Writing — Writing Process (Practice), NZC Phase 1 (Yrs 0-3): students apply the comprehensive four-item checking routine from Week 4 to passages that now also include plural nouns and joined sentences.",
{title:"I Do — The Full Check, With New Skills Added",instruction:"This week we have two new skills to add to our full check: plural nouns and joined sentences. Watch me apply the complete routine to this passage.",example:"The childrens ran to the churchs. they found two boxs of books and a bag of pencil. my friend aroha said can we keep them",demonstration:"I check through the passage: 'childrens' — wrong plural, should be 'children' (irregular). 'churchs' — wrong, should be 'churches' (-es ending). 'they' — capital T needed (new sentence). 'boxs' — wrong, should be 'boxes'. 'pencil' — should be 'pencils' (plural). 'aroha' — capital A (proper noun). 'can we keep them' — this is a question, needs a question mark. Fixed: 'The children ran to the churches. They found two boxes of books and a bag of pencils. My friend Aroha said, \"Can we keep them?\"'",tip:"Work through the checklist one item at a time: (1) Capitals at sentence starts, (2) Full stops or question marks at ends, (3) Proper noun capitals, (4) Question marks for questions, (5) Correct plural endings."},
{title:"We Do — Fix These Passages",instruction:"Let's read each passage aloud together and fix everything — capitals, full stops, proper nouns, question marks, plurals, and joined sentences.",sentences:["the dog ran across three field and the cat hid under the bench. my friend lily asked where did they go","last sunday we put the boxs of book away at grace church. mrs lee asked did anyone help you","the bird sang on two branch and the leafs fell slowly. aroha asked why does that always happen in autumn"],prompt:"What's wrong — a plural, a capital, a question mark, or a joining issue? Work through the checklist!"},
{title:"You Do — Your Turn",instruction:"Fix each passage using the complete five-item checklist. Read aloud first, then fix one item at a time.",tasks:["the childrens went to three park and they played for hours. jake asked are we staying for lunch","my two brother helped me carry the boxs. mum asked did you say thank you to them","on saturday the bird flew over the church and the bees buzzed over the flower. i felt overjoyed","✦ Bonus: Write your own 3-sentence passage — include a plural noun, a joined sentence, and a question. Then swap with a partner for the full check!"]},
[{code:"Writing — Writing Process (Practice)",label:"Comprehensive five-item check",detail:"NZC Phase 1: students apply an extended comprehensive check that now includes plural noun accuracy alongside the four punctuation items from Week 4, building a robust multi-item editing habit."},{code:"Writing — Grammar (Practice)",label:"Plural noun accuracy in context",detail:"NZC Phase 1: students identify and correct incorrect plural forms (-s/-es confusion) within a passage editing context, consolidating Tuesday's plural noun learning in an applied setting."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"24 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Writing Process: comprehensive five-item check: capitals, full stops, proper nouns, question marks, correct plurals.","Grammar: identify and correct incorrect plural forms in a passage editing context.","Punctuation: apply all punctuation rules learned so far in combination.","Metacognition: work through a mental checklist one item at a time rather than trying to catch everything simultaneously."],walt:["We are learning to check a passage for all five things: capitals, full stops, proper noun capitals, question marks, and correct plurals.","We are learning to fix plural errors (-s vs -es) when we find them.","We are learning to read aloud slowly to hear where corrections are needed."],successCriteria:["I can find and fix all five types of error in a short passage.","I can correct a plural noun that uses the wrong ending.","I can work through my checklist one item at a time."],timing:[{time:"0-7m",title:"The Extended Checklist",phase:"I Do",description:"Teacher adds Item 5 (Correct plurals) to the four-item checklist from Week 4. Models the full five-item check on one passage with think-aloud."},{time:"7-14m",title:"Check Together",phase:"We Do",description:"Whole class reads 3 passages, working through the five-item checklist together. Students call out items one at a time."},{time:"14-22m",title:"My Full Check",phase:"You Do",description:"Students fix 3 passages independently using the five-item checklist card. Proper nouns pre-underlined for emerging writers; bonus writing + swap for confident writers."},{time:"22-28m",title:"Partner Swap",phase:"Reflect",description:"Students swap passages and check each other's corrections using the checklist. Close: every check we do is a gift to our future reader."}],resources:["Five-item checklist card (capitals / full stops or ? / proper noun capitals / question marks / correct plurals)","Passages with multiple error types","Large lined paper for bonus task"],assessment:["Formative: accuracy of the five-item check across all error types","Work sample: 3 corrected passages","Focus: plural corrections applied correctly; all five checklist items addressed"],differentiation:[{label:"ESOL learners",note:"Five-item checklist with visual icons; line-by-line approach; buddy support."},{label:"Emerging writers",note:"Proper nouns pre-underlined; focus on 3 checklist items at a time rather than all 5."},{label:"Confident writers",note:"Write own passage with all five error types deliberately included, then swap with a partner to find them."},{label:"Diverse learners",note:"Read-aloud and partner-read strategies support auditory learners."}],valuesIntegration:{heading:"Manaaki — Serve",notes:["Checking our writing carefully — especially with a partner — is an act of Manaaki: we are giving our reader the gift of clear, considerate, correct writing.","The partner swap is a concrete act of serving one another: taking time to help someone else's writing be the best it can be."]},reflectionPrompts:["Were students applying all five checklist items, or still missing some?","Were plural errors caught and corrected correctly?","Did the partner swap generate helpful, specific feedback?","Are any students beginning to apply the full checklist in their first-draft writing without being prompted?"]},"Manaaki"),

Friday:g("Quiz Day — Week 5 Review","Writing — Vocabulary, Grammar, Sentence Structure & Punctuation (Practice), NZC Phase 1 (Yrs 0-3): consolidate movement words, plural nouns, joining sentences with 'and', and the full checking routine through a team quiz.",
{title:"I Do — What We Learned This Week",instruction:"Before the quiz, let's quickly remind ourselves of the four things we worked on this week.",example:"**Movement words** (plain to precise) · **Plural nouns** (-s and -es) · **Joining sentences with 'and'** · **Full checking routine**",demonstration:"A great sentence using this week: 'At sunrise, the **children** **bounded** across the **churches** courtyard and the **birds** **soared** above them.' — movement word (bounded, soared), plurals (children, churches, birds), joined with 'and', full check passed.",tip:"This week: HOW did they move? Is this plural right? Are these two ideas joined correctly? Did the checklist catch everything?"},
{title:"We Do — Quick Review Together",instruction:"Let's build one brilliant sentence using everything from this week.",sentences:["The **children** **dashed** across the field **and** the **birds** **scattered** into the trees.","**After lunch**, the **boxes** of books were carried carefully **and** the **benches** were tidied away.","The **dog** **bounded** through the **bushes** **and** the **cat** **crept** under the **church** steps."],prompt:"Can you find the movement word, the plural noun, the joining word 'and', and check the punctuation?"},
{title:"You Do — Quiz Time!",instruction:"Time to show what you know! Good luck Team Tui and Team Kiwi!",tasks:["Listen carefully to each question.","Your team earns a point for each correct answer.","Be encouraging — cheer for great answers from both teams!","✦ Remember: this quiz tests four whole weeks of brilliant learning — you should all feel proud!"]},
[{code:"Writing — Vocabulary (Practice)",label:"Precise movement words in context",detail:"NZC Phase 1: students demonstrate knowledge of precise movement verbs in a quiz context."},{code:"Writing — Grammar (Practice)",label:"Plural noun accuracy",detail:"NZC Phase 1: students identify and apply correct plural endings (-s and -es) in quiz questions."},{code:"Writing — Sentence Structure (Practice)",label:"Joining sentences with 'and'",detail:"NZC Phase 1: students identify and construct correctly joined sentences using 'and' as a conjunction."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"25 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"30-35 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Vocabulary: precise movement words.","Grammar: plural nouns with correct -s/-es endings.","Sentence Structure: joining sentences with 'and'.","Writing Process: five-item comprehensive checking routine.","Communication: team quiz with sportsmanship and encouragement."],walt:["We are learning to show what we know from the whole week.","We are learning to identify movement words, plurals, and joined sentences.","We are learning to be kind, encouraging team members."],successCriteria:["I can identify and upgrade a plain movement word.","I can write the correct plural form of a noun.","I can identify a correctly joined sentence using 'and'.","I can be an encouraging and kind team member."],timing:[{time:"0-5m",title:"Week 5 Review",phase:"I Do",description:"Quick recap of this week's four skills."},{time:"5-10m",title:"Quick Practice",phase:"We Do",description:"One example question as a class."},{time:"10-30m",title:"Team Quiz",phase:"You Do",description:"16 questions on movement words, plural nouns, joining with 'and', and the full check."},{time:"30-35m",title:"Celebrate & Reflect",phase:"Reflect",description:"Final scores, applause for both teams. Pause to acknowledge how much the class has learned since Week 1!"}],resources:["Quiz questions on screen","Scoreboard"],assessment:["Formative: observe which question types the class finds hardest","Note: is plural -s/-es still a challenge? Is joining with 'and' secure? Plan for Week 10 spiral review."],differentiation:[{label:"ESOL learners",note:"Questions read aloud clearly; team conferral time."},{label:"All learners",note:"Team format; all contribute at their level."}],valuesIntegration:{heading:"All Four Values",notes:["Aroha: movement words help us love our reader — we paint them a picture rather than leaving them to imagine.","Mohio: knowing how language works (plurals, conjunctions) helps us tell God's story and our own more precisely.","Manaaki: checking our writing and supporting our teammates both serve others with our gifts.","Panga: every precise word and correct sentence we write makes an impact — on our reader and on the world we describe."]},reflectionPrompts:["Which question types did the class find hardest?","Are plural nouns or joining sentences the weaker area — plan accordingly for Week 10 spiral?","How was team spirit? End of five weeks — how far has the class come?"]},"Manaaki")
};

const quiz5=[
{q:"Which is the MOST precise movement word to replace 'went' in 'The excited dog went across the field'?",opts:["moved","travelled","bounded","walked"],ans:2,explanation:"'Bounded' is the most precise and vivid choice — it tells us the dog was leaping with energy and joy. 'Moved' and 'travelled' are just as vague as 'went', and 'walked' doesn't capture the excitement."},
{q:"Which movement word best shows someone moving SLOWLY and TIREDLY?",opts:["sprinted","trudged","dashed","bounded"],ans:1,explanation:"'Trudged' shows slow, heavy, tired movement — it's perfect for someone who is exhausted or reluctant. 'Sprinted' and 'dashed' are fast, and 'bounded' is energetic and joyful."},
{q:"What is the correct PLURAL of 'church'?",opts:["churchs","churchies","churches","churche"],ans:2,explanation:"'Churches' is correct — when a word ends in -ch, -sh, -s, or -x, you add -es to make the plural. Say 'churchs' aloud and it sounds wrong! 'Churches' sounds right."},
{q:"What is the correct PLURAL of 'bird'?",opts:["birdes","birdes","birds","birdies"],ans:2,explanation:"'Birds' is correct — most nouns just add -s to make the plural. 'Bird' ends in a regular consonant, so it just needs -s. Say it aloud: 'birds' sounds natural and right."},
{q:"Which sentence correctly JOINS two short sentences with 'and'?",opts:["The dog barked. And the cat ran away.","The dog barked and. The cat ran away.","The dog barked and the cat ran away.","The dog barked. The cat ran away and."],ans:2,explanation:"'The dog barked and the cat ran away.' is correct — two ideas joined with 'and' into one sentence, with only ONE full stop at the very end. No full stop before 'and'!"},
{q:"Which movement word best shows someone moving QUIETLY and SECRETLY?",opts:["thundered","charged","crept","bolted"],ans:2,explanation:"'Crept' shows quiet, secretive movement — it's perfect for sneaking or tiptoeing. 'Thundered' and 'charged' are loud and forceful, and 'bolted' means running away fast."},
{q:"What is the correct PLURAL of 'box'?",opts:["boxs","boxes","box's","boxies"],ans:1,explanation:"'Boxes' is correct — 'box' ends in -x, so it needs -es to make the plural. Say 'boxs' aloud — it sounds wrong! 'Boxes' sounds right."},
{q:"Which sentence has an INCORRECT plural?",opts:["The birds sang all morning.","The children played in the field.","The churchs were very old.","The boxes were heavy."],ans:2,explanation:"'Churchs' is wrong — 'church' ends in -ch so it needs -es, making 'churches'. The other sentences all use correct plurals: birds (+s), children (irregular), boxes (+es)."},
{q:"Which joined sentence is punctuated CORRECTLY?",opts:["The sun shone. And the flowers grew.","The sun shone and the flowers grew.","The sun shone. And. The flowers grew.","The sun shone, and, the flowers grew."],ans:1,explanation:"'The sun shone and the flowers grew.' is correct — one capital at the start, 'and' joins the two ideas, and one full stop at the very end. No full stop before 'and'!"},
{q:"Which movement word BEST shows fast, sudden movement?",opts:["sauntered","strolled","trudged","bolted"],ans:3,explanation:"'Bolted' shows fast, sudden movement — like a horse or person who suddenly runs away at high speed. 'Sauntered' and 'strolled' are slow and relaxed, and 'trudged' is slow and heavy."},
{q:"Which sentence uses a precise movement word AND a correct plural?",opts:["The bird went over the churchs.","The birds soared over the churches.","The birds went over the church's.","The bird soared over the churchies."],ans:1,explanation:"'The birds soared over the churches.' is correct — 'soared' is a precise and vivid movement word, 'birds' and 'churches' are both correct plurals."},
{q:"What does the joining word 'and' do in a sentence?",opts:["Makes it a question","Joins two related ideas into one sentence","Adds a describing word","Tells us where something happened"],ans:1,explanation:"'And' is a conjunction — its job is to join two related ideas into one longer sentence. 'The dog barked AND the cat ran away' — two connected ideas, one sentence."},
{q:"Which movement word best shows HAPPY, JOYFUL movement?",opts:["limped","skipped","trudged","crept"],ans:1,explanation:"'Skipped' shows happy, light, joyful movement — the kind you do when you're excited or carefree. 'Limped' and 'trudged' are heavy and painful, and 'crept' is quiet and secretive."},
{q:"Which sentence is INCORRECTLY joined?",opts:["The wind blew and the leaves danced.","God made the mountains and God made the sea.","The rain fell. And the flowers grew.","Aroha sang and Levi played the guitar."],ans:2,explanation:"'The rain fell. And the flowers grew.' is incorrectly joined — you cannot start a new sentence with 'And' after a full stop. The correct joined version is: 'The rain fell and the flowers grew.'"},
{q:"What is the correct PLURAL of 'wish'?",opts:["wishs","wishies","wishes","wish's"],ans:2,explanation:"'Wishes' is correct — 'wish' ends in -sh, so it needs -es to make the plural. Say 'wishs' aloud — it doesn't sound right. 'Wishes' sounds natural."},
{q:"Which sentence uses EVERYTHING from Week 5 — a precise movement word, a correct plural, and 'and' to join two ideas?",opts:["The dogs went to the park.","The children dashed across the fields and the birds scattered above them.","She ran and the box fell.","The bird moved and the cats went away."],ans:1,explanation:"'The children dashed across the fields and the birds scattered above them.' has it all: 'dashed' and 'scattered' are precise movement words, 'children', 'fields', and 'birds' are correct plurals, and 'and' joins two connected ideas correctly."}
];


/* ===== WEEK 6 ===== */
const week6={
Monday:g("Sequencing & Time Words — First, Next, Then, Finally","Writing — Vocabulary & Text Structure (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students learn sequencing words (first, next, then, after that, finally) as connective tools that signal the order of events in a sequence or recount.",
{title:"I Do — Words That Tell Us the Order",instruction:"When we write instructions or recount events, we need to show the reader what happened FIRST, what happened NEXT, and what happened LAST. Sequencing words do that job. Watch me use them to order a set of events.",example:"**First**, I got out my pencil. **Next**, I opened my book. **Then**, I wrote the date. **After that**, I began my work. **Finally**, I read it back aloud.",demonstration:"Without sequencing words: 'I got out my pencil. I opened my book. I wrote the date.' — this is fine, but we don't know the order matters. With sequencing words: '**First** I got out my pencil. **Next** I opened my book.' — now the reader knows this is a sequence and follows the steps with us.",tip:"Use: FIRST to start. NEXT or THEN for the middle steps. AFTER THAT for a step near the end. FINALLY for the very last thing."},
{title:"We Do — Add a Sequencing Word",instruction:"Let's add the right sequencing word to each sentence to show the order of events.",sentences:["___ , I put on my shoes. (this is the first thing)","___ , I walked to the door. (this is the next thing)","___ , I went outside to play. (this is the last thing)"],prompt:"Which sequencing word fits? FIRST / NEXT / THEN / AFTER THAT / FINALLY?"},
{title:"You Do — Your Turn",instruction:"Add the correct sequencing word to each sentence so the reader can follow the order.",tasks:["___ , God made the light.","___ , God made the sky and the water.","___ , God made the land and the plants.","✦ Bonus: Write 3 sentences about something you did today, using FIRST, THEN, and FINALLY to show the order."]},
[{code:"Writing — Vocabulary (Knowledge)",label:"Sequencing words as connectives",detail:"NZC Phase 1: students learn first, next, then, after that, and finally as temporal connectives that signal the order of events, as a foundation for recount and instruction writing."},{code:"Writing — Text Structure (Knowledge)",label:"Sequential text structure",detail:"NZC Phase 1: students learn that instructions and recounts follow a time-ordered structure, and that sequencing words make that structure visible to the reader."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"26 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Vocabulary: first, next, then, after that, finally as temporal connectives.","Text Structure: sequential text (instructions and recounts) follows a time-ordered structure.","Sentence Structure: sequencing words typically appear at the start of a sentence, followed by a comma.","Metacognition: ask 'is this the first, middle, or last step?' before choosing a sequencing word."],walt:["We are learning that sequencing words (first, next, then, finally) show the ORDER of events.","We are learning to use sequencing words at the start of a sentence.","We are learning to put events in the right order when we write."],successCriteria:["I can use 'first' to start a sequence.","I can use 'next', 'then', or 'after that' for middle steps.","I can use 'finally' for the very last thing."],timing:[{time:"0-7m",title:"Sequence Scramble",phase:"I Do",description:"Teacher shows 4 events written on cards in the wrong order, then uses sequencing words to sort them into the right order on the board. Differentiation: physical card sorting is concrete for visual and kinaesthetic learners; ESOL learners can sort picture cards alongside word cards."},{time:"7-14m",title:"Add the Sequence Word",phase:"We Do",description:"Whole class adds sequencing words to 3 sentences about a simple daily routine. Discuss: which word tells us it is first? Which tells us it is last?"},{time:"14-22m",title:"My Sequence",phase:"You Do",description:"Students add sequencing words to 3 events from the creation story. Sequencing word bank visible; bonus 3-sentence sequence for confident writers."},{time:"22-28m",title:"Share in Order",phase:"Reflect",description:"Students read their 3 sentences aloud in order. Close: God's creation unfolded in a beautiful sequence — sequencing words help us tell that story in the right order, connecting to Mohio."}],resources:["Sequencing word bank: FIRST / NEXT / THEN / AFTER THAT / FINALLY","Event cards for the opening scramble activity","Worksheet with 3 events to sequence","Large lined paper for bonus task"],assessment:["Formative: accuracy of sequencing word selection and placement","Work sample: 3 correctly sequenced sentences","Focus: correct sequencing word matched to position; comma after fronted sequencing word"],differentiation:[{label:"ESOL learners",note:"Picture card sorting before writing; sequencing word bank on display; buddy pairing."},{label:"Emerging writers",note:"Sequencing word choices given (circle the right one); focus on FIRST, THEN, FINALLY as a simpler three-word set."},{label:"Confident writers",note:"Bonus: write 3 sentences about something they did today using FIRST, THEN, and FINALLY, including a vivid verb in each."},{label:"Diverse learners",note:"Physical card-sorting activity is kinaesthetic and inclusive; oral rehearsal of the sequence before writing."}],valuesIntegration:{heading:"Mohio — Know",notes:["The creation story is told in a beautiful, ordered sequence — and sequencing words help us tell that story with the same care and order God used to create it.","Knowing the order of events — and being able to communicate that order clearly — is a form of Mohio: understanding the story we are part of."]},reflectionPrompts:["Were students correctly matching sequencing words to position (first for the start, finally for the end)?","Are students remembering to use a comma after a fronted sequencing word?","Did the creation story context connect meaningfully for students?","Are students starting to use sequencing words in their own independent writing?"]},"Mohio"),

Tuesday:g("Verbs — Past Tense with -ed","Writing — Grammar (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students learn that most verbs describing past actions are formed by adding -ed, and begin applying this pattern in their own writing.",
{title:"I Do — Writing About What Already Happened",instruction:"When we write about something that already happened — yesterday, last week, in the past — we change the verb to the past tense. For most verbs, we simply add -ed. Watch me change these verbs.",example:"Today I **walk** to school. Yesterday I **walked** to school. Today she **jumps**. Yesterday she **jumped**. Today they **play**. Yesterday they **played**.",demonstration:"'Walk' becomes '**walked**' — just add -ed. 'Jump' becomes '**jumped**' — just add -ed. 'Play' becomes '**played**' — just add -ed. This is the most common pattern in English: verb + -ed = past tense. When we write a recount or a story that already happened, ALL the verbs should be past tense.",tip:"Ask: did this happen in the past? If yes, most action words need -ed added to them. Listen: does 'walked' sound right? Does 'played' sound right? Your ear will usually tell you."},
{title:"We Do — Change to Past Tense",instruction:"Let's change each verb from present to past tense together. Add -ed and check that it sounds right.",sentences:["Today the bird **sings** in the tree. → Yesterday the bird ___ in the tree.","Today I **help** my friend. → Last week I ___ my friend.","Today we **thank** God for our food. → This morning we ___ God for our food."],prompt:"Add -ed to each verb. Does it sound right when you say it aloud?"},
{title:"You Do — Your Turn",instruction:"Rewrite each sentence in the past tense by changing the verb. Add -ed to make it past tense.",tasks:["Today the children **play** in the park. → Yesterday the children ___.","Today she **help** her little brother. → Last week she ___.","Today I **walk** to the library. → Yesterday I ___.","✦ Bonus: Write 2 sentences about something kind you did LAST WEEK — use past tense -ed verbs throughout!"]},
[{code:"Writing — Grammar (Knowledge)",label:"Past tense with -ed",detail:"NZC Phase 1: students learn that most English verbs form the past tense by adding -ed, and that past tense is used when writing about events that have already happened — a foundational understanding for recount and narrative writing."},{code:"Writing — Grammar (Practice)",label:"Applying -ed past tense in context",detail:"NZC Phase 1: students apply the -ed past tense pattern in sentence contexts, converting present tense sentences to past tense and writing original past tense sentences."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"27 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Grammar: most English verbs form the past tense by adding -ed.","Grammar: past tense is used for events that have already happened.","Writing Process: recount and narrative writing requires consistent past tense.","Metacognition: listen to whether the -ed past tense verb sounds right aloud."],walt:["We are learning that most action words add -ed to show the past tense.","We are learning to change a verb to past tense when writing about things that already happened.","We are learning to check our past tense verbs by reading them aloud."],successCriteria:["I can add -ed to a verb to make it past tense.","I can write a sentence about the past using -ed verbs.","I can hear whether my past tense verb sounds right when I read it aloud."],timing:[{time:"0-7m",title:"Today vs Yesterday",phase:"I Do",description:"Teacher writes a simple sentence in the present tense, then changes it to past tense by adding -ed, demonstrating the pattern with 3 different verbs. Builds a 'today/yesterday' table on the board. Differentiation: today/yesterday table gives ESOL learners a clear visual anchor for the tense concept."},{time:"7-14m",title:"Change the Verb",phase:"We Do",description:"Whole class converts 3 present tense sentences to past tense, adding -ed and checking by reading aloud. Discuss: does it sound right? Differentiation: sentence pairs on display (today / yesterday); buddy check aloud."},{time:"14-22m",title:"My Past Tense Sentences",phase:"You Do",description:"Students rewrite 3 sentences in the past tense. Today/yesterday sentence pairs available for emerging writers; bonus original past tense sentences for confident writers."},{time:"22-28m",title:"Share & Check",phase:"Reflect",description:"Students read one past tense sentence to a partner, who checks: does the verb end in -ed? Does it sound right? Close: when we write about what has happened, we are keeping a record of our story."}],resources:["Today/yesterday comparison table on board","Worksheet with 3 present tense sentences for conversion","Large lined paper for bonus task"],assessment:["Formative: accuracy of -ed past tense application during shared practice","Work sample: 3 correctly converted past tense sentences","Focus: -ed added correctly; sentence makes sense in past tense context"],differentiation:[{label:"ESOL learners",note:"Today/yesterday table as visual anchor; oral rehearsal of past tense sentence before writing; buddy pairing."},{label:"Emerging writers",note:"Verb with -ed ending already shown; students copy the past tense form and complete the sentence."},{label:"Confident writers",note:"Bonus: write 2 original sentences about something kind they did last week using vivid -ed verbs."},{label:"Diverse learners",note:"Read-aloud check is multi-sensory; today/yesterday table is a clear visual support."}],valuesIntegration:{heading:"Manaaki — Serve",notes:["Writing about acts of kindness we have done in the past (helping, thanking, serving) is a natural application of Manaaki — and using the past tense correctly honours those stories by telling them with care.","The bonus task — writing about something kind done last week — is a gentle reflection on how we have served others."]},reflectionPrompts:["Were students applying the -ed pattern consistently?","Did the read-aloud check help students catch errors?","Are any students over-applying -ed to irregular verbs (went, came, said)? Flag these for next week's spiral touch.","Are students using past tense consistently in their own recount writing?"]},"Manaaki"),

Wednesday:g("Sequencing 3 Sentences in Order","Writing — Text Structure & Sentence Structure (Practice), NZC Phase 1 (Yrs 0-3): students write a three-sentence sequence using sequencing words and past tense -ed verbs, connecting this week's Monday and Tuesday learning into a short coherent text.",
{title:"I Do — Putting It All Together: Sequence + Past Tense",instruction:"This week we have learned sequencing words (Monday) and past tense -ed verbs (Tuesday). Now we combine them: watch me write 3 sentences in order, using sequencing words and past tense verbs.",example:"**First**, I **walked** to school with my friend. **Then**, we **talked** about our favourite books. **Finally**, we **arrived** just as the bell **rang**.",demonstration:"Each sentence uses a sequencing word at the start AND a past tense verb (walked, talked, arrived, rang). The three sentences tell a mini-story in the right order. A reader can follow exactly what happened and when.",tip:"Check: does each sentence start with a sequencing word? Does each verb tell us something that ALREADY happened (past tense -ed)?"},
{title:"We Do — Build a Sequence Together",instruction:"Let's build a 3-sentence sequence together using sequencing words and past tense verbs. These sentences tell what happened during morning worship.",sentences:["**First**, we ___ (sat down / knelt / gathered) and ___ (prayed / sang / listened). (past tense)","**Then**, our teacher ___ (read / shared / opened) a story from the Bible. (past tense)","**Finally**, we ___ (thanked / praised / reflected) God for ___ . (past tense)"],prompt:"Which past tense verb fits? Remember: most need -ed. Which sequencing word tells us first, middle, and last?"},
{title:"You Do — Your Turn",instruction:"Write 3 sentences in order about something you did to HELP someone. Use a sequencing word in each sentence AND past tense -ed verbs.",tasks:["Sentence 1: FIRST, I ___ (what did you do first?).","Sentence 2: THEN / NEXT, I ___ (what happened next?).","Sentence 3: FINALLY, I ___ (how did it end?).","✦ Bonus: Read your 3 sentences aloud. Do they flow? Can you upgrade one verb to a more vivid movement or action word?"]},
[{code:"Writing — Text Structure (Practice)",label:"Writing a 3-sentence sequence",detail:"NZC Phase 1: students produce a short three-sentence sequential text using sequencing words at sentence starts and past tense -ed verbs, combining Monday and Tuesday's learning into a coherent mini-recount."},{code:"Writing — Sentence Structure (Practice)",label:"Sequencing words + past tense integration",detail:"NZC Phase 1: students integrate sequencing connectives and past tense verb forms in a single piece of writing, as an early step toward the structured recount writing expected in Phase 2."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"28 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Text Structure: write a short sequential text (3 sentences) using sequencing words.","Grammar: use past tense -ed verbs consistently throughout a short piece of writing.","Writing Process: plan before writing (what happened first, next, last?).","Metacognition: check sequencing word at start of each sentence; check -ed verb tense."],walt:["We are learning to write 3 sentences in the right order using sequencing words.","We are learning to use past tense -ed verbs throughout a short piece of writing.","We are learning to plan our sequence before we write."],successCriteria:["I can write 3 sentences in order using FIRST, THEN, and FINALLY.","I can use a past tense -ed verb in each sentence.","My 3 sentences tell a short story that makes sense when read aloud."],timing:[{time:"0-7m",title:"Sequence + Past Tense Together",phase:"I Do",description:"Teacher models writing a 3-sentence mini-recount on the board, thinking aloud: 'First — what happened first? Past tense — add -ed.' Highlights sequencing words in one colour, -ed verbs in another."},{time:"7-14m",title:"Build Together",phase:"We Do",description:"Whole class constructs a 3-sentence sequence about morning worship, choosing sequencing words and past tense verbs together. Both displayed in colour on the board."},{time:"14-22m",title:"My 3-Sentence Sequence",phase:"You Do",description:"Students write a 3-sentence sequence about a time they helped someone. Sentence starters provided for emerging writers; bonus verb upgrade for confident writers."},{time:"22-28m",title:"Read Aloud & Check",phase:"Reflect",description:"Students read their 3 sentences to a partner. Partner checks: sequencing word at the start? Past tense verb? Makes sense in order? Close: when we write about helping others, we are also celebrating the good that happens in our community."}],resources:["Colour-coded model on board (sequencing words in one colour, -ed verbs in another)","Sentence starters: 'First, I...' / 'Then, I...' / 'Finally, I...'","Large lined paper"],assessment:["Formative: coherence of 3-sentence sequence; consistency of past tense","Work sample: 3 correctly sequenced past tense sentences","Focus: sequencing word at start of each sentence; -ed verb used correctly; logical order"],differentiation:[{label:"ESOL learners",note:"Sentence starters provided; vocabulary support for helping/service actions; buddy pairing."},{label:"Emerging writers",note:"Pre-written sentence frames with blanks: 'First, I ___ my ___.' / 'Then, I ___.' / 'Finally, I ___.'."},{label:"Confident writers",note:"Bonus: upgrade one verb to a vivid movement or action word from earlier in the term."},{label:"Diverse learners",note:"Oral planning ('tell your partner what happened first, next, last') before writing."}],valuesIntegration:{heading:"Manaaki — Serve",notes:["Writing about helping others — in correct, ordered, past-tense sentences — gives real dignity to acts of service. It says: what you did mattered enough to be written down well.","This connects directly to Manaaki: serving faithfully with our gifts and talents. Writing is one of those gifts."]},reflectionPrompts:["Were students maintaining past tense consistently across all 3 sentences?","Did the colour-coding help students track both skills at once?","Are the 3-sentence sequences coherent — do they tell a mini-story that makes sense?","Are students ready to write a 5-sentence sequence (the next step in Phase 2 recount writing)?"]},"Manaaki"),

Thursday:g("Check: Order & Punctuation","Writing — Writing Process (Practice), NZC Phase 1 (Yrs 0-3): students check a short passage for correct sequencing word usage, past tense consistency, and all five punctuation items from the full checklist.",
{title:"I Do — Checking Sequences for Order AND Punctuation",instruction:"When we check a passage with several sentences, we have some extra things to look for: are the sequencing words in the right order? Are the verbs past tense? And of course — the full five-item punctuation check. Watch me check this passage.",example:"then we walked to the hall. First i sat down next to lily. Finally the teacher ask us to listen. after that the music start.",demonstration:"Problems I can spot: 'then' at the start — but this should be FIRST or a different sequence. 'i' needs a capital. 'lily' needs a capital. 'ask' should be 'asked' (past tense). 'start' should be 'started' (past tense). The sequence words are also out of order (then before first). Let me fix: 'First, I sat next to Lily. Then we walked to the hall. After that, the teacher asked us to listen. Finally, the music started.'",tip:"For sequences, check: (1) Are sequencing words in the right order? (2) Are all verbs in the past tense (-ed)? (3) All five punctuation items: capitals, full stops, proper noun capitals, question marks, correct plurals."},
{title:"We Do — Check This Sequence Together",instruction:"Let's read this passage together and fix the order, the past tense verbs, and the punctuation.",sentences:["finally i help my friend. first we talk about the problem. then she felt much better. after that we walk to class together.","next the bird land on the branch. first it sang a song. finally it fly away. then it look for food.","after that mia thank the teacher. finally she walk home. first she pack her bag. next she say goodbye."],prompt:"Are the sequence words in the right order? Are the verbs past tense? Check all five punctuation items too!"},
{title:"You Do — Your Turn",instruction:"Fix each passage: put events in the right order, change verbs to past tense, and fix all punctuation.",tasks:["finally we pray. first we open our books. then the teacher read to us. after that we listen carefully.","next she help her brother. finally she feel proud. first she notice he was sad. then she ask what was wrong.","after that the flowers grow. first god made the soil. finally the rain fall. then the seeds are planted.","✦ Bonus: Write your own 4-sentence sequence about something that happened this week. Check it using all 7 items (5 punctuation + sequence order + past tense)."]},
[{code:"Writing — Writing Process (Practice)",label:"Checking sequence, tense, and punctuation",detail:"NZC Phase 1: students apply a comprehensive check to sequential passages that includes logical order of sequencing words, past tense verb consistency, and the five-item punctuation checklist — the most complex editing task of Term 1 so far."},{code:"Writing — Grammar (Practice)",label:"Past tense consistency check",detail:"NZC Phase 1: students identify and correct present tense verbs that should be past tense in a sequential passage, consolidating Tuesday's past tense learning in an applied editing context."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"29 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Writing Process: comprehensive 7-item check: sequencing word order + past tense consistency + 5 punctuation items.","Grammar: identify and correct present tense verbs in a sequential passage.","Text Structure: sequence words should appear in a logical order (first before then, then before finally).","Metacognition: work through a structured checklist, one item at a time."],walt:["We are learning to check that sequencing words are in a logical order.","We are learning to check that all verbs in a sequence are past tense.","We are learning to apply our full punctuation checklist to a sequential passage."],successCriteria:["I can spot when a sequencing word is in the wrong order.","I can change a present tense verb to past tense in a passage.","I can apply the full five-item punctuation check to a sequential passage."],timing:[{time:"0-7m",title:"The 7-Item Check",phase:"I Do",description:"Teacher adds 2 new items to the checklist: (6) Sequencing words in logical order and (7) All verbs in past tense. Models all 7 items on one passage with think-aloud."},{time:"7-14m",title:"Check Together",phase:"We Do",description:"Whole class reads 3 passages, working through all 7 checklist items. Students call out issues one at a time — sequence order first, then tense, then punctuation."},{time:"14-22m",title:"My Full Check",phase:"You Do",description:"Students fix 3 passages independently using the 7-item checklist card. Sequencing words pre-ordered for emerging writers; bonus writing task for confident writers."},{time:"22-28m",title:"Partner Check",phase:"Reflect",description:"Students swap passages with a partner and check using the full 7-item list. Celebrate how many skills the class now has in their checking toolkit."}],resources:["7-item checklist card (capitals / full stops-? / proper noun caps / question marks / correct plurals / sequence word order / past tense verbs)","Passages with multiple error types","Large lined paper for bonus task"],assessment:["Formative: accuracy of all 7-item check across error types","Work sample: 3 corrected passages","Focus: sequence word order corrected; -ed past tense applied; all 5 punctuation items addressed"],differentiation:[{label:"ESOL learners",note:"Sequencing words pre-ordered; focus on 5 of 7 checklist items first; buddy support."},{label:"Emerging writers",note:"Sequencing words already in order; focus on past tense and 3 punctuation items."},{label:"Confident writers",note:"Write own 4-sentence sequence and apply the full 7-item check independently."},{label:"Diverse learners",note:"Oral read-aloud of the fixed passage at the end confirms corrections and benefits auditory learners."}],valuesIntegration:{heading:"Manaaki — Serve",notes:["A 7-item check takes care and patience — it is an act of Manaaki to give our writing and our reader that much attention.","The partner check is a reminder that we learn and grow best when we help each other: 'two are better than one.'"]},reflectionPrompts:["Were students checking all 7 items or stopping at punctuation?","Was sequence word ordering the hardest item to fix?","Were past tense errors caught consistently?","Is the class ready for Week 10's spiral review, which will revisit sequencing in full?"]},"Manaaki"),

Friday:g("Quiz Day — Week 6 Review","Writing — Vocabulary, Grammar, Text Structure & Punctuation (Practice), NZC Phase 1 (Yrs 0-3): consolidate sequencing words, past tense -ed, 3-sentence sequences, and the full checking routine through a team quiz.",
{title:"I Do — What We Learned This Week",instruction:"Before the quiz, let's quickly remind ourselves of the four things we worked on this week.",example:"**Sequencing words** (first, next, then, finally) · **Past tense -ed** · **3-sentence sequences** · **Order & punctuation check**",demonstration:"A great 3-sentence sequence: 'First, I walked to school with my friend Aroha. Then, we talked and laughed all the way. Finally, we arrived just as the bell rang.' — sequencing words, past tense verbs, proper noun capital, correct punctuation.",tip:"This week: use FIRST to start, THEN/NEXT for the middle, FINALLY for the end. Make sure your verbs are past tense (-ed). Check all 7 items!"},
{title:"We Do — Quick Review Together",instruction:"Let's build one brilliant 3-sentence sequence using everything from this week.",sentences:["**First**, God **created** the light and **called** it good.","**Then**, He **made** the sky and the sea and **filled** them with life.","**Finally**, He **looked** at everything He had **made** and **smiled**."],prompt:"Can you find the sequencing words, the past tense verbs, and the proper noun capital?"},
{title:"You Do — Quiz Time!",instruction:"Time to show what you know! Good luck Team Tui and Team Kiwi!",tasks:["Listen carefully to each question.","Your team earns a point for each correct answer.","Be encouraging — cheer for great answers from both teams!","✦ Six weeks in — you know SO much more about writing than you did in Week 1. Be proud!"]},
[{code:"Writing — Vocabulary (Practice)",label:"Sequencing words in context",detail:"NZC Phase 1: students demonstrate knowledge of temporal connectives (first, next, then, after that, finally) in a quiz context."},{code:"Writing — Grammar (Practice)",label:"Past tense -ed in context",detail:"NZC Phase 1: students identify and apply the -ed past tense pattern in quiz questions."},{code:"Writing — Text Structure (Practice)",label:"Sequential text structure",detail:"NZC Phase 1: students identify correctly and incorrectly sequenced passages in a quiz context."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"30 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"30-35 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Vocabulary: temporal connectives (first, next, then, after that, finally).","Grammar: past tense -ed pattern.","Text Structure: sequential text with correct event ordering.","Writing Process: 7-item comprehensive check.","Communication: team quiz with encouragement and sportsmanship."],walt:["We are learning to show what we know from the whole week.","We are learning to identify sequencing words and past tense verbs.","We are learning to be kind, encouraging team members."],successCriteria:["I can identify and use sequencing words in the right order.","I can identify and form the -ed past tense of a verb.","I can be an encouraging and kind team member."],timing:[{time:"0-5m",title:"Week 6 Review",phase:"I Do",description:"Quick recap of this week's four skills."},{time:"5-10m",title:"Quick Practice",phase:"We Do",description:"One example question as a class."},{time:"10-30m",title:"Team Quiz",phase:"You Do",description:"16 questions on sequencing words, past tense -ed, 3-sentence sequences, and the full check."},{time:"30-35m",title:"Celebrate & Reflect",phase:"Reflect",description:"Final scores, applause for both teams. Acknowledge: 6 weeks of consistent learning — celebrate the growth!"}],resources:["Quiz questions on screen","Scoreboard"],assessment:["Formative: observe which question types the class finds hardest","Note: are sequencing words or -ed past tense the weaker area? Plan spiral touch for Week 10."],differentiation:[{label:"ESOL learners",note:"Questions read aloud clearly; team conferral time."},{label:"All learners",note:"Team format; all contribute at their level."}],valuesIntegration:{heading:"All Four Values",notes:["Aroha: the creation sequence reminds us of God's love in making the world for us.","Mohio: knowing the order of events — in stories, in history, in creation — is part of knowing our place in God's story.","Manaaki: checking writing carefully, helping teammates, and serving our reader with ordered, clear writing.","Panga: writing that is well-ordered and clear makes an impact — on our reader and on the story we are telling."]},reflectionPrompts:["Which question types did the class find hardest?","Is -ed past tense secure enough for Phase 2 recount work?","How was team spirit? Can you name students who were especially encouraging this week?"]},"Manaaki")
};

const quiz6=[
{q:"Which sequencing word tells us something is the VERY FIRST step?",opts:["Finally","Then","First","After that"],ans:2,explanation:"'First' tells the reader this is the very first thing that happened. A sequence always starts with FIRST — it signals to the reader that a series of events is about to begin."},
{q:"Which sequencing word tells us something is the VERY LAST step?",opts:["Next","First","Then","Finally"],ans:3,explanation:"'Finally' tells the reader this is the very last thing. It signals the end of the sequence. FIRST starts, NEXT/THEN fill the middle, and FINALLY ends."},
{q:"What is the PAST TENSE of 'walk'?",opts:["walks","walking","walked","will walk"],ans:2,explanation:"'Walked' is the past tense — we add -ed to most verbs to show something happened in the past. 'Walk + ed = walked.' This is the most common past tense pattern in English."},
{q:"Which sentence is written in the PAST TENSE?",opts:["I walk to school today.","I am walking to school.","I walked to school yesterday.","I will walk to school tomorrow."],ans:2,explanation:"'I walked to school yesterday' is past tense — 'walked' has -ed added, and 'yesterday' confirms it happened in the past. 'Today', 'am walking', and 'will walk' all refer to the present or future."},
{q:"Which sequencing word BEST fits the MIDDLE of a sequence?",opts:["First","Finally","Then","Start"],ans:2,explanation:"'Then' is a middle sequencing word — it comes after FIRST and before FINALLY. FIRST starts, THEN continues the sequence, and FINALLY ends it."},
{q:"Which 3-sentence sequence is in the CORRECT order?",opts:["Finally I sat down. First I walked in. Then I found my seat.","First I walked in. Then I found my seat. Finally I sat down.","Then I found my seat. Finally I sat down. First I walked in.","First I sat down. Then I walked in. Finally I found my seat."],ans:1,explanation:"'First I walked in. Then I found my seat. Finally I sat down.' is the correct order — the events happen in the right order that makes sense in real life. The others have steps in the wrong order."},
{q:"What is the PAST TENSE of 'help'?",opts:["helps","helping","help","helped"],ans:3,explanation:"'Helped' is the past tense — add -ed to 'help'. 'She helped her friend yesterday.' The -ed ending tells us this happened in the past."},
{q:"Which sentence uses a sequencing word AND a past tense verb CORRECTLY?",opts:["First, I walk to school.","Then, she helps her brother.","Finally, we arrived at the beach.","Next, they are running to the gate."],ans:2,explanation:"'Finally, we arrived at the beach.' is correct — 'Finally' is a sequencing word in the right position (end of a sequence), and 'arrived' is a past tense verb showing this happened in the past."},
{q:"Where does a sequencing word go in a sentence?",opts:["At the very end","In the middle","At the start, followed by a comma","After the full stop"],ans:2,explanation:"A sequencing word goes at the START of a sentence, followed by a comma: 'First, I walked in.' or 'Then, she helped.' The comma after the sequencing word is an important rule."},
{q:"Which passage uses sequencing words in the CORRECT order?",opts:["Finally I packed my bag. First I went to school. Then I said goodbye.","Then I went to school. First I packed my bag. Finally I said goodbye.","First I packed my bag. Then I went to school. Finally I said goodbye.","First I said goodbye. Finally I packed my bag. Then I went to school."],ans:2,explanation:"'First I packed my bag. Then I went to school. Finally I said goodbye.' is in the right order — packing comes first, then going to school, then saying goodbye. The sequence words match the logical order of events."},
{q:"What is the PAST TENSE of 'thank'?",opts:["thanks","thanking","thanked","will thank"],ans:2,explanation:"'Thanked' is the past tense — add -ed to 'thank'. 'I thanked Nana for the gift.' The -ed ending tells us this happened in the past."},
{q:"Which sentence has a sequencing word, a past tense verb, AND a correct proper noun capital?",opts:["first, i walked with lily to school.","First, I walked with lily to school.","First, I walked with Lily to school.","first, I walked with Lily to school."],ans:2,explanation:"'First, I walked with Lily to school.' is correct — 'First' is the sequencing word (with a capital because it starts the sentence), 'walked' is the past tense verb, and 'Lily' has a capital because it is a proper noun (a person's name)."},
{q:"Which of these verbs CANNOT form past tense by simply adding -ed?",opts:["walked","jumped","played","went"],ans:3,explanation:"'Went' is an irregular past tense verb — the past tense of 'go' is 'went', not 'goed'. Most verbs add -ed, but some common verbs (go/went, come/came, say/said) are irregular and need to be learned separately."},
{q:"A 3-sentence sequence should have sequencing words in this order:",opts:["Finally, Then, First","Then, First, Finally","First, Then, Finally","Finally, First, Then"],ans:2,explanation:"A 3-sentence sequence uses: FIRST for the first event, THEN (or NEXT) for the middle event, and FINALLY for the last event. This matches the natural order of time and events."},
{q:"Which passage has the CORRECT sequence order AND past tense verbs?",opts:["Finally I helped him. Then I noticed he was sad. First I asked what was wrong.","First I noticed he was sad. Finally I asked what was wrong. Then I helped him.","First I noticed he was sad. Then I asked what was wrong. Finally I helped him.","Then I helped him. First I noticed he was sad. Finally I asked what was wrong."],ans:2,explanation:"'First I noticed he was sad. Then I asked what was wrong. Finally I helped him.' is correct — the events are in the right order and all verbs (noticed, asked, helped) are in the past tense."},
{q:"Which sentence uses EVERYTHING from Week 6 — a sequencing word, a past tense -ed verb, and correct punctuation?",opts:["first i walked to school","Then, she helped her friend Aroha.","finally she help the teacher.","Next she walk to the door"],ans:1,explanation:"'Then, she helped her friend Aroha.' is correct — 'Then' is a sequencing word with a capital (it starts the sentence), 'helped' is a past tense verb with -ed, 'Aroha' has a capital as a proper noun, and the sentence ends with a full stop."}
];


/* ===== WEEK 7 ===== */
const week7={
Monday:g("Place & Setting Words","Writing — Vocabulary (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students build a bank of vivid place and setting words — describing landscapes, spaces, and environments — as a foundation for descriptive and narrative writing.",
{title:"I Do — Words That Build a Place in the Reader's Mind",instruction:"When we write about a place, our job is to help the reader SEE it in their mind. The more specific and vivid our place and setting words, the better the picture. Watch me describe two places — one with plain words, one with vivid ones.",example:"Plain: 'a nice beach'. Vivid: 'a **wide**, **golden** beach with **thundering** waves and **jagged** black rocks'.",demonstration:"'A nice beach' — the reader gets almost nothing. But 'a **wide**, **golden** beach with **thundering** waves and **jagged** black rocks' — now the reader can see it, hear it, almost feel it! Setting words include: words for landscape features (cliff, valley, ridge, cove), texture and surface words (jagged, mossy, smooth, crumbling), light and colour words (golden, shadowy, dappled, grey), and sound/weather words (thundering, still, breezy, misty).",tip:"Ask: what can you SEE? What is the LIGHT like? What TEXTURES are there? What can you HEAR? Each answer gives you a setting word."},
{title:"We Do — Build the Setting Together",instruction:"Let's add vivid setting words to each plain place description together.",sentences:["a **beach** → a ___ , ___ beach with ___ waves","a **forest** → a ___ , ___ forest with ___ trees and ___ light","a **school** → a ___ , ___ school with ___ halls and ___ grounds"],prompt:"What can you see? What is the light like? What textures are there? What can you hear?"},
{title:"You Do — Your Turn",instruction:"Add at least TWO vivid setting words to each place to help the reader picture it.",tasks:["a **garden** → describe it with two or more setting words","a **church** → describe it with two or more setting words","the **sea** at night → describe it with two or more setting words","✦ Bonus: Write 2 full sentences describing a place you love, using at least THREE vivid setting words. Try to use words for light, texture, AND sound!"]},
[{code:"Writing — Vocabulary (Knowledge)",label:"Place and setting words",detail:"NZC Phase 1: students build a bank of vivid place and setting vocabulary — landscape features, texture and surface words, light and colour words, sound and weather words — as a foundation for descriptive writing."},{code:"Writing — Vocabulary (Practice)",label:"Using setting words in description",detail:"NZC Phase 1: students apply setting vocabulary to plain place descriptions, learning to add specific sensory detail that helps the reader visualise a place."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"31 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Vocabulary: landscape features, texture, light, colour, and sound words as tools for setting description.","Vocabulary: upgrade plain place words (nice beach, big forest) with specific sensory detail.","Communication: share place descriptions aloud and discuss whether the reader can picture the place.","Metacognition: ask what can I see/hear/feel/smell? as a self-prompting strategy for setting description."],walt:["We are learning words that describe places and settings.","We are learning to use setting words that help the reader SEE a place in their mind.","We are learning to use words for light, texture, and sound when we describe a place."],successCriteria:["I can suggest at least two vivid setting words for a place.","I can use words for light, texture, or sound in a place description.","My description helps the reader picture the place without having been there."],timing:[{time:"0-7m",title:"Plain vs Vivid Setting",phase:"I Do",description:"Teacher shows two descriptions of the same place — one plain, one vivid — and asks students which one they can picture. Then categorises the setting words into four groups: landscape / texture / light / sound. Differentiation: visuals of NZ landscapes (beach, bush, mountain, harbour) used as anchor images."},{time:"7-14m",title:"Build the Setting Together",phase:"We Do",description:"Whole class adds setting words to 3 plain place descriptions. Four-category word bank on display; buddy discussion before suggesting words."},{time:"14-22m",title:"My Setting Words",phase:"You Do",description:"Students add vivid setting words to 3 plain place descriptions. Four-category word bank available; bonus 2-sentence description for confident writers."},{time:"22-28m",title:"Share & Picture It",phase:"Reflect",description:"Students read their best setting description aloud. Class closes their eyes and tries to picture the place. Close: God created every one of these places with extraordinary care — and vivid words help us honour that care."}],resources:["Four-category setting word bank (landscape / texture / light / sound)","NZ landscape anchor images (beach, bush, mountain, harbour)","Worksheet with 3 plain place descriptions","Large lined paper for bonus task"],assessment:["Formative: quality and variety of setting words chosen during shared practice","Work sample: 3 place descriptions with vivid setting words added","Focus: words from at least 2 of the 4 categories used; real sensory detail added"],differentiation:[{label:"ESOL learners",note:"NZ landscape anchor images alongside the word bank; oral rehearsal before writing; buddy pairing."},{label:"Emerging writers",note:"Four-category word bank with images; sentence frame: 'a ___, ___ [place] with ___ [feature]'."},{label:"Confident writers",note:"Bonus 2-sentence description using words from at least 3 of the 4 categories."},{label:"Diverse learners",note:"Eyes-closed listening in the reflect stage is inclusive and evocative; physical gesture for each sense category (point to eye for light, ear for sound, hand for texture)."}],valuesIntegration:{heading:"Mohio & Aroha",notes:["Describing the places God made with vivid, specific words is both a form of knowing (Mohio) and a form of love (Aroha). We honour what we describe carefully.","The eyes-closed listening in the reflect stage is a small act of wonder — pausing to appreciate what God has made."]},reflectionPrompts:["Were students drawing on all four categories (landscape/texture/light/sound) or defaulting to colour and size only?","Did the anchor images help ESOL learners who may not have visited NZ landscapes?","Which setting descriptions were most vivid — worth sharing with the class or displaying?","Are students beginning to use setting words spontaneously in their own writing?"]},"Mohio"),

Tuesday:g("Pronouns — He, She, It, They","Writing — Grammar (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students learn that pronouns (he, she, it, they) replace naming words to avoid repetition, and begin using them correctly in their writing.",
{title:"I Do — Avoiding Repetition With Pronouns",instruction:"When we write, we use naming words (nouns) to introduce people, animals, and things. But if we repeat the naming word every sentence, it sounds clunky and repetitive. We can use a PRONOUN — a small word that replaces the naming word. Watch me clean up this passage.",example:"**The dog** ran across the field. **The dog** jumped over the fence. **The dog** barked at the birds. → **The dog** ran across the field. **It** jumped over the fence. **It** barked at the birds.",demonstration:"'The dog' is named once in the first sentence. After that, we know who we're talking about — so we can replace 'the dog' with **it**. If it were a person: **he** (for a boy or man) or **she** (for a girl or woman). For two or more people or things: **they**. This makes the writing flow much better.",tip:"Introduce the naming word FIRST. Then switch to the pronoun: he, she, it, or they. Match the pronoun to what it replaces: one male person = he, one female = she, one thing = it, more than one = they."},
{title:"We Do — Replace With a Pronoun",instruction:"Let's replace the repeated naming word with the right pronoun in each passage together.",sentences:["**Mia** ran to the door. **Mia** knocked loudly. **Mia** waited for an answer. → Replace 'Mia' with ___.","**The birds** sang all morning. **The birds** flew from branch to branch. **The birds** disappeared at noon. → Replace 'the birds' with ___.","**My brother** helped me carry the box. **My brother** was very kind. → Replace 'my brother' with ___."],prompt:"Is it one person (he/she) or more than one (they)? Is it a thing (it)? Replace the repeated naming word."},
{title:"You Do — Your Turn",instruction:"Rewrite each passage, replacing the repeated naming word with the correct pronoun (he, she, it, or they) in the second and third sentences.",tasks:["**The cat** sat on the mat. **The cat** yawned slowly. **The cat** fell asleep.","**Noah** and **Levi** walked to school together. **Noah** and **Levi** talked all the way. **Noah** and **Levi** arrived early.","**Mrs Patel** smiled at the class. **Mrs Patel** opened the book. **Mrs Patel** began to read aloud.","✦ Bonus: Write 3 sentences introducing a character (person or animal) and then using a pronoun in the second and third sentences."]},
[{code:"Writing — Grammar (Knowledge)",label:"Pronouns: he, she, it, they",detail:"NZC Phase 1: students learn that pronouns replace naming words to avoid repetition, and that the correct pronoun must match the noun it replaces (he for male, she for female, it for a thing, they for plural)."},{code:"Writing — Grammar (Practice)",label:"Applying pronouns to avoid repetition",detail:"NZC Phase 1: students replace repeated naming words with correct pronouns in passage editing and original writing contexts, beginning to write with greater flow and variety."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"32 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Grammar: pronouns (he, she, it, they) replace naming words to avoid repetition.","Grammar: pronoun must agree with the noun it replaces (singular/plural; male/female/thing).","Writing Process: using pronouns is a revision strategy — a way of improving flow in a passage.","Metacognition: ask 'does the reader already know who/what I am talking about?' before switching to a pronoun."],walt:["We are learning that pronouns (he, she, it, they) replace naming words so we don't repeat them.","We are learning to choose the right pronoun for what it replaces.","We are learning that using pronouns makes our writing flow better."],successCriteria:["I can identify when a naming word is repeated too many times.","I can replace a repeated naming word with the correct pronoun.","My pronoun matches what it replaces: he/she/it/they."],timing:[{time:"0-7m",title:"Clunky vs Smooth",phase:"I Do",description:"Teacher reads a clunky passage (noun repeated every sentence) and asks: 'does this sound right? Why not?' Then demonstrates replacing with pronouns and re-reads the improved version. Differentiation: before/after comparison written on board."},{time:"7-14m",title:"Replace Together",phase:"We Do",description:"Whole class replaces repeated naming words with pronouns in 3 passages. Discuss: which pronoun fits — he, she, it, or they?"},{time:"14-22m",title:"My Pronoun Replacements",phase:"You Do",description:"Students rewrite 3 passages replacing the repeated noun with the correct pronoun. Noun-to-pronoun reference card for emerging writers; bonus writing task for confident writers."},{time:"22-28m",title:"Read & Compare",phase:"Reflect",description:"Students read the original clunky version, then their improved pronoun version. Close: good writing flows like a conversation — pronouns help our writing do that."}],resources:["Before/after passage comparison on board","Pronoun reference card (he = male person, she = female person, it = thing, they = more than one)","Worksheet with 3 passages for pronoun replacement","Large lined paper for bonus task"],assessment:["Formative: accuracy of pronoun selection (he/she/it/they) during shared practice","Work sample: 3 passages with correct pronoun replacement","Focus: correct pronoun matched to replaced noun; pronoun not used before noun is introduced"],differentiation:[{label:"ESOL learners",note:"Pronoun reference card with images; oral rehearsal of the improved passage; buddy pairing."},{label:"Emerging writers",note:"First noun highlighted and pronoun options offered (circle the right one)."},{label:"Confident writers",note:"Bonus: write 3 original sentences introducing a character, then using a pronoun correctly."},{label:"Diverse learners",note:"Read-aloud comparison of clunky vs smooth passage is powerful for auditory learners."}],valuesIntegration:{heading:"Aroha — Love",notes:["Choosing the right pronoun for a person — he or she — is a small but real way of seeing and honouring them as an individual. It matters.","Using pronouns correctly is also about care for our reader: smooth, flowing writing shows we respect the person who will read our words."]},reflectionPrompts:["Were students correctly matching pronouns to the noun they replaced (singular/plural; male/female/thing)?","Did students understand that the noun must be introduced first before switching to a pronoun?","Are students using pronouns in their own writing to avoid repetition?","Is the class ready to learn 'his' and 'her' as possessive pronouns (a natural next step in Phase 2)?"]},"Aroha"),

Wednesday:g("Combining Ideas with 'But'","Writing — Sentence Structure (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students learn to join two related but contrasting ideas using the conjunction 'but', extending Week 5's 'and' joining work to introduce contrast.",
{title:"I Do — 'And' Adds, 'But' Contrasts",instruction:"Last month we joined two sentences with 'and' to add ideas together. Today we learn 'but' — a joining word that shows a CONTRAST or a surprise. Watch me compare them.",example:"'And' adds: The sun shone **and** the birds sang. → 'But' contrasts: The sun shone **but** the wind was cold.",demonstration:"'The sun shone AND the birds sang' — both things are similar and positive, they add to each other. 'The sun shone BUT the wind was cold' — now there is a surprise! We expected warmth, but we got cold wind. 'But' tells the reader: something unexpected or opposite is coming. It creates tension and interest.",tip:"'And' adds similar ideas. 'But' joins opposite or surprising ideas. Ask: does the second idea add to the first, or contrast with it? If it contrasts — use 'but'."},
{title:"We Do — Choose 'And' or 'But'",instruction:"Let's decide which joining word fits each pair of sentences — 'and' or 'but'. Think: do these ideas add together or contrast with each other?",sentences:["The sky was dark ___ the stars were beautiful. ('and' or 'but'?)","I tried to open the door ___ it was locked. ('and' or 'but'?)","Mia laughed ___ Levi laughed too. ('and' or 'but'?)"],prompt:"Do these ideas add together, or does the second one surprise us or contrast with the first?"},
{title:"You Do — Your Turn",instruction:"Join each pair of sentences using 'but'. Make sure the second idea contrasts with or surprises the first.",tasks:["The food smelled delicious. It tasted awful. → join with 'but'","I wanted to stay. It was time to go. → join with 'but'","The path looked easy. It was actually very steep. → join with 'but'","✦ Bonus: Write your own pair of contrasting ideas joined with 'but'. Try to include a vivid setting word or a precise feeling word too!"]},
[{code:"Writing — Sentence Structure (Knowledge)",label:"Joining with 'but' (contrast)",detail:"NZC Phase 1: students learn that 'but' joins two contrasting or surprising ideas, extending their understanding of conjunction use beyond 'and' to include contrast as a sentence-level structural tool."},{code:"Writing — Sentence Structure (Practice)",label:"Constructing contrasting joined sentences",detail:"NZC Phase 1: students produce joined sentences using 'but', ensuring correct punctuation (one capital, one full stop) and real contrast between the two joined ideas."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"33 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Sentence Structure: join two contrasting ideas using 'but' as a conjunction.","Sentence Structure: distinguish between 'and' (adding) and 'but' (contrasting).","Punctuation: joined sentences with 'but' have one capital and one full stop.","Writing Process: contrast creates interest — 'but' is a tool for building tension and surprise in writing."],walt:["We are learning that 'but' joins two ideas that contrast or surprise.","We are learning the difference between 'and' (adding) and 'but' (contrasting).","We are learning to write a joined sentence using 'but' with correct punctuation."],successCriteria:["I can explain that 'and' adds ideas and 'but' contrasts them.","I can join two contrasting ideas with 'but'.","My joined sentence has one capital at the start and one full stop at the end."],timing:[{time:"0-7m",title:"'And' vs 'But'",phase:"I Do",description:"Teacher writes an 'and' sentence and a 'but' sentence side by side, asking students to feel the difference. 'And' = same direction, 'but' = change of direction. Use a visual arrow metaphor: 'and' = straight arrow, 'but' = a U-turn."},{time:"7-14m",title:"Choose Together",phase:"We Do",description:"Whole class decides whether 'and' or 'but' fits 3 sentence pairs. Discuss: does the second idea add to or contrast with the first? Arrow visual on display."},{time:"14-22m",title:"My 'But' Sentences",phase:"You Do",description:"Students join 3 sentence pairs using 'but'. Arrow visual on display; sentence-pair cards for emerging writers; bonus original sentence for confident writers."},{time:"22-28m",title:"Share the Contrast",phase:"Reflect",description:"Students share their best 'but' sentence. Class identifies where the contrast is. Close: life is full of contrasts — the world is beautiful but broken, we are small but known by God — and 'but' helps us write honestly about that."}],resources:["Arrow metaphor visual ('and' = straight, 'but' = U-turn)","Sentence-pair cards for physical joining","Worksheet with 3 sentence pairs for 'but' joining","Large lined paper for bonus task"],assessment:["Formative: accuracy of 'and' vs 'but' selection during shared practice","Work sample: 3 correctly joined contrasting sentences","Focus: real contrast between the two ideas; one full stop at the end; no full stop before 'but'"],differentiation:[{label:"ESOL learners",note:"Arrow visual metaphor; sentence-pair cards with images showing the contrast; oral rehearsal."},{label:"Emerging writers",note:"Pre-written sentence pairs; student adds only the joining word 'but' and checks punctuation."},{label:"Confident writers",note:"Bonus: write an original 'but' sentence including a vivid setting word or a precise feeling word."},{label:"Diverse learners",note:"Arrow visual and U-turn metaphor is memorable and kinaesthetic; dramatic read-aloud of the contrast is engaging."}],valuesIntegration:{heading:"Panga — Impact",notes:["'But' is one of the most honest words in writing — it acknowledges that things are not always what we expect, and that contrast is real. This connects to Panga: bringing God's kingdom into a world that is really complex and full of contrast.","The closing reflection — 'the world is beautiful but broken, we are small but known by God' — is a powerful, age-appropriate window into a Christian worldview."]},reflectionPrompts:["Were students generating real contrasts, or just adding 'but' between any two sentences?","Did students understand the difference between 'and' (adding) and 'but' (contrasting) with confidence?","Which 'but' sentences were most interesting — worth displaying?","Are students ready to add 'so' as a third conjunction next week?"]},"Panga"),

Thursday:g("Read-Aloud Check — Does It Flow?","Writing — Writing Process (Practice), NZC Phase 1 (Yrs 0-3): students apply the read-aloud check with a specific focus on FLOW — listening for choppy, repetitive, or awkward-sounding writing and identifying how to improve it using pronouns, joining words, and vivid vocabulary.",
{title:"I Do — Checking for Flow, Not Just Correctness",instruction:"So far our read-aloud check has focused on correctness: capitals, full stops, proper nouns. Today we add a new question: does it FLOW? Does it sound like real, interesting writing when read aloud? Watch me check this passage for both correctness AND flow.",example:"the dog ran. the dog was tired. the dog sat down. the dog was happy.",demonstration:"I read it aloud. Correct? Mostly not — missing capitals, no proper flow. But even if it were correct, it doesn't FLOW. Four short sentences all starting with 'the dog' — clunky and repetitive. How to fix: (1) Add pronoun: 'The dog ran. It was tired.' (2) Join: 'The dog ran but it was tired.' (3) Upgrade: 'The dog **dashed** across the field but was **exhausted** when it **flopped** down.' MUCH better.",tip:"Read aloud and ask: (1) Is it correct? (2) Does it FLOW? (3) Is anything repeated too many times? (4) Could a pronoun, a joining word, or a better vocabulary choice make it flow better?"},
{title:"We Do — Fix for Correctness AND Flow",instruction:"Let's read these passages aloud and fix them for both correctness AND flow. Look for repetition, short choppy sentences, and places where a pronoun or joining word would help.",sentences:["the bird sang. the bird flew. the bird was beautiful. the bird disappeared.","mia walked to church. mia sat down. mia prayed. mia felt peaceful.","the mountain was tall. the mountain was grey. the mountain was cold. the mountain was quiet."],prompt:"Is it correct? Does it flow? Where is the repetition? How could a pronoun or 'and'/'but' improve it?"},
{title:"You Do — Your Turn",instruction:"Fix each passage for both correctness AND flow. Use pronouns, joining words, and better vocabulary where they help.",tasks:["the cat sat. the cat looked around. the cat yawned. the cat slept.","noah helped his friend. noah was kind. noah smiled. noah felt good.","the sea was blue. the sea was wide. the sea was loud. the sea was cold.","✦ Bonus: Rewrite one of the above passages as a single flowing 2-sentence description — use a joining word, a pronoun, and at least one vivid setting or feeling word!"]},
[{code:"Writing — Writing Process (Practice)",label:"Read-aloud check for flow and correctness",detail:"NZC Phase 1: students extend the read-aloud checking routine to include a flow check — listening for choppiness, repetition, and awkwardness, and using pronouns, conjunctions, and vocabulary upgrades as revision tools."},{code:"Writing — Grammar & Vocabulary (Practice)",label:"Pronouns and conjunctions as revision tools",detail:"NZC Phase 1: students apply pronoun replacement and conjunction joining as active revision strategies to improve the flow of a passage, consolidating the grammar learning of Weeks 5-7 in an applied editing context."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"34 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Writing Process: extend the read-aloud check to include flow — listening for choppiness and repetition.","Grammar: use pronoun replacement as a revision strategy.","Sentence Structure: use conjunctions ('and', 'but') as revision tools to join choppy sentences.","Vocabulary: identify opportunities to upgrade plain or repeated words during the flow check."],walt:["We are learning to read our writing aloud and listen for whether it FLOWS.","We are learning to fix choppy, repetitive writing using pronouns and joining words.","We are learning that good writing sounds smooth and interesting when read aloud."],successCriteria:["I can hear when a passage sounds choppy or repetitive.","I can use a pronoun to remove repetition.","I can use 'and' or 'but' to join choppy sentences and improve flow."],timing:[{time:"0-7m",title:"Choppy vs Smooth",phase:"I Do",description:"Teacher reads a choppy passage dramatically, then reads the improved version. Students feel the difference. Model how to fix: pronoun first, then joining word, then vocabulary upgrade."},{time:"7-14m",title:"Fix for Flow Together",phase:"We Do",description:"Whole class reads 3 passages and improves them for flow — identifying repetition, choosing pronouns, adding joining words, upgrading vocabulary."},{time:"14-22m",title:"My Flow Check",phase:"You Do",description:"Students fix 3 passages for both correctness and flow. Pronoun reference card and conjunction card ('and' / 'but') available; bonus 2-sentence rewrite for confident writers."},{time:"22-28m",title:"Read & Appreciate",phase:"Reflect",description:"Students read their best flow-fixed passage aloud. Class listens with eyes closed. Close: writing that flows well is a joy to read — and a gift to your reader."}],resources:["Before/after flow comparison on board","Pronoun reference card (he/she/it/they)","Conjunction card (and/but)","Vocabulary upgrade bank (setting words, feeling words, movement words)","Worksheet with 3 choppy passages"],assessment:["Formative: quality of flow improvements during shared practice","Work sample: 3 corrected and improved passages","Focus: repetition removed using pronouns; choppy sentences joined; vocabulary upgraded where possible"],differentiation:[{label:"ESOL learners",note:"Dramatic read-aloud of choppy vs smooth is powerful; pronoun and conjunction reference cards; buddy pairing."},{label:"Emerging writers",note:"Focus on removing one type of repetition (noun repetition) using pronouns; 'and'/'but' joining optional."},{label:"Confident writers",note:"Bonus: rewrite one passage as a single flowing 2-sentence description using pronoun + joining word + vocabulary upgrade."},{label:"Diverse learners",note:"Eyes-closed listening in reflect stage is inclusive and focuses students on what they can HEAR in good writing."}],valuesIntegration:{heading:"Aroha & Manaaki",notes:["Writing that flows well is a gift to our reader — it shows we care enough to make our writing easy and enjoyable to read. This is both Aroha (love for the reader) and Manaaki (serving them with our words).","The eyes-closed listening in the reflect stage is a small moment of gratitude and appreciation for good writing."]},reflectionPrompts:["Were students hearing the difference between choppy and flowing writing when read aloud?","Did students independently reach for pronouns and conjunctions as revision tools?","Which passages were most dramatically improved — worth sharing?","Are students applying the flow check to their own independent writing?"]},"Aroha"),

Friday:g("Quiz Day — Week 7 Review","Writing — Vocabulary, Grammar & Sentence Structure (Practice), NZC Phase 1 (Yrs 0-3): consolidate setting words, pronouns, joining with 'but', and the flow check through a team quiz.",
{title:"I Do — What We Learned This Week",instruction:"Before the quiz, let's quickly remind ourselves of the four things we worked on this week.",example:"**Setting words** (light, texture, sound) · **Pronouns** (he, she, it, they) · **Joining with 'but'** · **Flow check**",demonstration:"A great sentence combining this week: 'The **wide**, **golden** beach gleamed in the sun, but **it** felt cold underfoot.' — vivid setting words, pronoun 'it', contrast with 'but', and it flows beautifully when read aloud.",tip:"This week: describe places with light/texture/sound words. Replace repeated nouns with he/she/it/they. Use 'but' for contrast. Read aloud to check flow."},
{title:"We Do — Quick Review Together",instruction:"Let's build one brilliant sentence using everything from this week.",sentences:["The **jagged**, **shadowy** cliffs rose from the sea, **but** **they** looked magical in the golden light.","The **mossy**, **quiet** forest was beautiful, **but** **it** felt eerie after dark.","**Aroha** sang **and** **she** closed her eyes, **but** the words felt too beautiful to finish."],prompt:"Can you find the setting words, the pronoun, the joining word 'but', and check the flow?"},
{title:"You Do — Quiz Time!",instruction:"Time to show what you know! Good luck Team Tui and Team Kiwi!",tasks:["Listen carefully to each question.","Your team earns a point for each correct answer.","Be encouraging — cheer for great answers from both teams!","✦ Seven weeks in — your writing is growing stronger every single week!"]},
[{code:"Writing — Vocabulary (Practice)",label:"Setting words in context",detail:"NZC Phase 1: students demonstrate knowledge of vivid place and setting vocabulary in a quiz context."},{code:"Writing — Grammar (Practice)",label:"Pronouns in context",detail:"NZC Phase 1: students identify and apply the correct pronoun (he, she, it, they) to replace a repeated naming word."},{code:"Writing — Sentence Structure (Practice)",label:"Joining with 'but'",detail:"NZC Phase 1: students identify and construct correctly joined contrasting sentences using 'but'."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"35 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"30-35 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Vocabulary: vivid setting words (landscape, texture, light, sound).","Grammar: pronouns he/she/it/they replacing repeated nouns.","Sentence Structure: joining contrasting ideas with 'but'.","Writing Process: flow check — listening for choppiness and repetition.","Communication: team quiz with sportsmanship and encouragement."],walt:["We are learning to show what we know from the whole week.","We are learning to identify setting words, pronouns, and contrasting joining sentences.","We are learning to be kind, encouraging team members."],successCriteria:["I can identify vivid setting words and choose the right pronoun.","I can identify a correctly joined contrasting sentence using 'but'.","I can be an encouraging and kind team member."],timing:[{time:"0-5m",title:"Week 7 Review",phase:"I Do",description:"Quick recap of this week's four skills."},{time:"5-10m",title:"Quick Practice",phase:"We Do",description:"One example question as a class."},{time:"10-30m",title:"Team Quiz",phase:"You Do",description:"16 questions on setting words, pronouns, joining with 'but', and flow check."},{time:"30-35m",title:"Celebrate & Reflect",phase:"Reflect",description:"Final scores, applause for both teams. Seven weeks — acknowledge the journey!"}],resources:["Quiz questions on screen","Scoreboard"],assessment:["Formative: observe which question types the class finds hardest","Note: are pronouns or setting words the weaker area? Plan for Week 10 spiral review."],differentiation:[{label:"ESOL learners",note:"Questions read aloud clearly; team conferral time."},{label:"All learners",note:"Team format; all contribute at their level."}],valuesIntegration:{heading:"All Four Values",notes:["Aroha: describing beautiful places with care is a form of love for God's creation.","Mohio: knowing how to describe our world precisely helps us understand and tell God's story.","Manaaki: pronouns that honour people (he/she) show care and respect for individuals.","Panga: 'but' helps us write honestly about a world that is beautiful and broken at the same time."]},reflectionPrompts:["Which question types did the class find hardest?","Is the pronoun concept secure? Were students matching he/she/it/they correctly?","How was team spirit? Are there students who need extra encouragement heading into Weeks 8-10?"]},"Mohio")
};

const quiz7=[
{q:"Which type of word BEST helps a reader PICTURE a place?",opts:["A joining word like 'and'","A sequencing word like 'first'","A vivid setting word like 'jagged' or 'golden'","A pronoun like 'it'"],ans:2,explanation:"A vivid setting word like 'jagged' or 'golden' helps the reader picture a place — it adds sensory detail about what a place looks, feels, or sounds like. Joining words, sequencing words, and pronouns all have different jobs."},
{q:"Which sentence uses the MOST vivid setting words?",opts:["A nice beach with nice waves.","A wide, golden beach with thundering waves and jagged black rocks.","A big beach with big waves.","A beach with some rocks."],ans:1,explanation:"'A wide, golden beach with thundering waves and jagged black rocks' is the most vivid — it uses words for size (wide), colour (golden), sound (thundering), and texture (jagged). The reader can see, hear, and feel this place."},
{q:"Which pronoun should replace 'the dog' in this sentence? 'The dog ran across the field. ___ was very fast.'",opts:["He","She","It","They"],ans:2,explanation:"'It' replaces 'the dog' — we use 'it' for animals and things (when we don't know their gender or they are referred to as an animal). 'He' and 'she' are for people, and 'they' is for more than one."},
{q:"Which pronoun should replace 'Mia' in this sentence? 'Mia sang a song. ___ closed her eyes.'",opts:["He","She","It","They"],ans:1,explanation:"'She' replaces 'Mia' — we use 'she' for a female person. 'He' is for a male person, 'it' is for a thing or animal, and 'they' is for more than one person or thing."},
{q:"Which joining word shows a CONTRAST or a surprise?",opts:["and","first","but","finally"],ans:2,explanation:"'But' shows a contrast or a surprise — for example, 'The sun shone but the wind was cold.' The second idea is unexpected or opposite to the first. 'And' adds ideas together; 'first' and 'finally' are sequencing words."},
{q:"Which sentence uses 'but' CORRECTLY to show a contrast?",opts:["The sun shone but the birds sang.","I tried to open the door but it was locked.","First I walked in but then I sat down.","She felt happy but she also felt happy."],ans:1,explanation:"'I tried to open the door but it was locked.' is correct — the second part (it was locked) contrasts with and surprises the first part (trying to open it). The door being locked is unexpected."},
{q:"Which pronoun should replace 'Noah and Levi' in the second sentence? 'Noah and Levi walked to school. ___ talked all the way.'",opts:["He","She","It","They"],ans:3,explanation:"'They' replaces 'Noah and Levi' — we use 'they' for more than one person or thing. 'He' and 'she' are for a single person, and 'it' is for a thing or animal."},
{q:"Which word from the following list is a SETTING WORD (describes a place)?",opts:["walked","grateful","mossy","because"],ans:2,explanation:"'Mossy' is a setting word — it describes the texture of a place (moss-covered rocks, mossy walls). 'Walked' is a verb, 'grateful' is a feeling word, and 'because' is a connecting word."},
{q:"Which passage has BETTER FLOW?",opts:["The cat sat. The cat yawned. The cat slept. The cat was cozy.","The cat sat and yawned, then it curled up and slept."],ans:1,explanation:"'The cat sat and yawned, then it curled up and slept.' flows much better — it uses a conjunction ('and'), a sequencing word ('then'), and a pronoun ('it') to remove the choppy repetition of 'the cat' at the start of every sentence."},
{q:"Which word BEST describes what you HEAR in a place?",opts:["golden","jagged","thundering","mossy"],ans:2,explanation:"'Thundering' is a sound word — it tells us what we can HEAR (thundering waves, a thundering waterfall). 'Golden' and 'jagged' are sight/texture words, and 'mossy' is a texture word."},
{q:"Which sentence uses a pronoun INCORRECTLY?",opts:["The bird sang. It flew away.","Mrs Patel smiled. She opened the book.","The boys ran. She was fast.","Mia and Levi laughed. They were happy."],ans:2,explanation:"'The boys ran. She was fast.' is incorrect — 'she' is a singular female pronoun, but it is being used to replace 'the boys' (plural and male). The correct pronoun would be 'they'."},
{q:"Which word BEST describes what you SEE in a place — the LIGHT?",opts:["thundering","dappled","mossy","jagged"],ans:1,explanation:"'Dappled' describes light — specifically the way light falls in patches through leaves (dappled sunlight). It is a word about what you SEE. 'Thundering' is a sound word, 'mossy' and 'jagged' are texture words."},
{q:"What does the reading-aloud check help you listen for?",opts:["Whether a word is a proper noun","Whether the writing flows smoothly and sounds interesting","Whether a verb is in the past tense","Whether a sentence has an adjective"],ans:1,explanation:"Reading aloud helps you listen for whether the writing flows smoothly and sounds interesting. Your ear catches things your eye misses — choppiness, repetition, awkward phrasing. It's one of the best revision tools a writer has."},
{q:"Which sentence uses 'but' to show the BIGGEST contrast?",opts:["I walked to school but I also ran.","The food looked amazing but it was delicious.","The path looked easy but it was actually very steep.","She was happy but she was also happy."],ans:2,explanation:"'The path looked easy but it was actually very steep.' has the strongest contrast — 'looked easy' sets up an expectation that is dramatically reversed by 'actually very steep'. The 'but' creates a real surprise."},
{q:"Which passage uses a PRONOUN correctly to avoid repetition?",opts:["The dog ran. The dog barked. The dog was happy.","The dog ran. It barked. It was happy.","The dog ran. He barked. She was happy.","The dog ran. They barked. It was happy."],ans:1,explanation:"'The dog ran. It barked. It was happy.' is correct — 'the dog' is introduced once, then replaced with 'it' (the correct pronoun for an animal) in the following sentences. No repetition, clear and flowing."},
{q:"Which sentence uses EVERYTHING from Week 7 — a setting word, a pronoun, and 'but' for contrast?",opts:["The beach was nice and it was good.","The jagged cliffs rose from the sea, but they looked beautiful in the golden light.","First I walked to the beach but then I left.","She went to the place but the place was cold."],ans:1,explanation:"'The jagged cliffs rose from the sea, but they looked beautiful in the golden light.' has it all: 'jagged' and 'golden' are vivid setting words, 'they' is a correct pronoun replacing 'the cliffs', and 'but' creates a contrast — the cliffs are dramatic but also beautiful."}
];


/* ===== WEEK 8 ===== */
const week8={
Monday:g("Comparing Words — Bigger, Smaller, Taller","Writing — Vocabulary (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students build a bank of comparing words (comparative adjectives) and learn how they help a reader understand size, degree, and quality by measuring one thing against another.",
{title:"I Do — Words That Compare Two Things",instruction:"Describing words (adjectives) tell us what something is like. But COMPARING words do something extra — they measure one thing AGAINST another. Watch me show the difference.",example:"The **tall** mountain. vs The mountain is **taller** than the hill. The **fast** bird. vs The eagle is **faster** than the sparrow. The **kind** person. vs She is **kinder** than anyone I know.",demonstration:"'Tall' describes the mountain on its own. But 'taller THAN the hill' — now we are comparing! Comparing words usually end in **-er** and are almost always followed by the word 'than'. They show a difference in degree between two things.",tip:"When you use a comparing word, you almost always need 'than' after it: taller THAN, faster THAN, kinder THAN. If you can't find the 'than', check whether you really need a comparing word."},
{title:"We Do — Find and Use the Comparing Word",instruction:"Let's identify the comparing word in each sentence together, then build our own comparison using that pattern.",sentences:["The pohutukawa is **taller** than the flax bush.","The falcon is **faster** than the sparrow.","This rock is **smoother** than that one."],prompt:"What is being compared? Which word is the comparing word? Can you spot the word 'than'?"},
{title:"You Do — Your Turn",instruction:"Add a comparing word to each sentence by turning the plain adjective into a comparative (-er form) and adding 'than'.",tasks:["The mountain is **high** ___ the hill. (make 'high' into a comparing word)","My friend is **kind** ___ anyone I know. (make 'kind' into a comparing word)","The sea is **deep** ___ the river. (make 'deep' into a comparing word)","✦ Bonus: Write your own comparison sentence about two things in God's creation. Include a comparing word AND a vivid setting word from Week 7!"]},
[{code:"Writing — Vocabulary (Knowledge)",label:"Comparative adjectives as comparing tools",detail:"NZC Phase 1: students learn that comparative adjectives (formed with -er) compare two things by measuring one against the other, and that they are almost always followed by 'than' in a sentence."},{code:"Writing — Vocabulary (Practice)",label:"Using comparing words in sentences",detail:"NZC Phase 1: students apply comparative adjectives in sentence contexts, practising the adjective + than construction and building the habit of noticing and describing relative qualities."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"36 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Vocabulary: comparative adjectives (-er forms) as tools for comparing two things.","Sentence Structure: comparative adjectives are almost always followed by 'than'.","Communication: share comparison sentences aloud and discuss whether the comparison is fair and accurate.","Metacognition: ask 'am I comparing two things?' before choosing a comparing word."],walt:["We are learning that comparing words measure one thing against another.","We are learning that comparing words usually end in -er.","We are learning that comparing words are almost always followed by 'than'."],successCriteria:["I can identify a comparing word in a sentence.","I can turn a plain adjective into a comparing word by adding -er.","I can write a comparison sentence using a comparing word and 'than'."],timing:[{time:"0-7m",title:"Plain vs Comparing",phase:"I Do",description:"Teacher builds a two-column table: plain adjective vs comparative. Shows the -er pattern and the 'than' companion. Uses NZ examples (pohutukawa / flax, falcon / sparrow, kauri / ponga) to make it culturally grounded."},{time:"7-14m",title:"Find and Build",phase:"We Do",description:"Whole class identifies the comparing word in 3 sentences, then builds their own comparison using the same word. Comparative word bank on display."},{time:"14-22m",title:"My Comparisons",phase:"You Do",description:"Students turn plain adjectives into comparative forms and complete comparison sentences. Word bank available for emerging writers; bonus original comparison for confident writers."},{time:"22-28m",title:"Share Kindly",phase:"Reflect",description:"Students share a comparison sentence. Close: when we compare things in nature or in life, we are noticing the variety and range of what God made — no two things are exactly the same."}],resources:["Plain-to-comparative adjective table (tall/taller, fast/faster, deep/deeper, kind/kinder, smooth/smoother)","NZ nature image pairs for comparison (mountain/hill, pohutukawa/flax, falcon/sparrow)","Worksheet with 3 sentences for comparative completion","Large lined paper for bonus task"],assessment:["Formative: accuracy of comparative adjective formation and 'than' usage","Work sample: 3 comparison sentences","Focus: -er ending applied correctly; 'than' used after the comparative; real comparison made"],differentiation:[{label:"ESOL learners",note:"Image pairs for comparison; plain-to-comparative table with visual support; oral rehearsal of the full comparison sentence before writing."},{label:"Emerging writers",note:"Sentence frames: 'The ___ is ___er than the ___.'; comparative word bank."},{label:"Confident writers",note:"Bonus: write a comparison sentence using a vivid setting word AND a comparative adjective."},{label:"Diverse learners",note:"Physical comparison: hold up two objects of different sizes and ask 'which is bigger?' before writing the sentence."}],valuesIntegration:{heading:"Aroha — Love",notes:["When we compare things in God's creation, we are noticing the beautiful variety He made. No two mountains, birds, or trees are exactly alike — and comparing words help us describe that difference with care.","Comparing people and things kindly — noticing what is taller, faster, or kinder without being unkind — is a form of Aroha."]},reflectionPrompts:["Were students correctly adding -er to form comparatives (not 'more tall' instead of 'taller')?","Did students remember to use 'than' after the comparative?","Which comparison sentences were most vivid or unexpected?","Are students ready to learn superlatives (-est forms) as a natural next step in Phase 2?"]},"Aroha"),

Tuesday:g("Comparative Adjectives — The -er Rule","Writing — Grammar (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students learn the -er rule for forming comparative adjectives, including the spelling patterns for short adjectives (adding -er, doubling the final consonant, and changing -y to -i before -er).",
{title:"I Do — Three Patterns for Making Comparing Words",instruction:"Most short adjectives follow one of three patterns when we add -er to make them comparative. Watch me show all three.",example:"Pattern 1 — just add -er: **tall** → **taller**, **fast** → **faster**, **kind** → **kinder**. Pattern 2 — double the last letter then add -er: **big** → **bigger**, **hot** → **hotter**, **sad** → **sadder**. Pattern 3 — change -y to -i then add -er: **happy** → **happier**, **funny** → **funnier**, **cloudy** → **cloudier**.",demonstration:"Pattern 1: 'tall' ends in two consonants or a vowel + consonant — just add -er. Pattern 2: 'big' ends in one vowel + one consonant — double the consonant before -er (biGGer). Pattern 3: 'happy' ends in -y — change the y to i and add -er (happi-er). Say it aloud — 'biggier' sounds wrong, 'bigger' sounds right!",tip:"Look at the last TWO letters of the adjective: two consonants or ends in -y? Check the pattern. One vowel + one consonant? Double it before -er. Ends in -y? Change to -i + er."},
{title:"We Do — Spot the Pattern and Add -er",instruction:"Let's decide which pattern each adjective follows, then make it comparative.",sentences:["**warm** → ___ (just add -er? double? change -y?)","**thin** → ___ (just add -er? double? change -y?)","**noisy** → ___ (just add -er? double? change -y?)"],prompt:"What are the last two letters? Which pattern does this adjective follow?"},
{title:"You Do — Your Turn",instruction:"Turn each adjective into a comparative using the right pattern. Check your spelling aloud.",tasks:["**cold** → ___ (which pattern?)","**wet** → ___ (which pattern?)","**lazy** → ___ (which pattern?)","✦ Bonus: Write 2 comparison sentences — one using a doubled-consonant comparative and one using a -y to -i comparative."]},
[{code:"Writing — Grammar (Knowledge)",label:"Comparative adjective spelling patterns",detail:"NZC Phase 1: students learn the three spelling patterns for forming comparative adjectives with short words: adding -er directly, doubling the final consonant before -er (for CVC adjectives), and changing -y to -i before -er (for adjectives ending in -y)."},{code:"Writing — Grammar (Practice)",label:"Applying comparative spelling patterns",detail:"NZC Phase 1: students apply the three comparative spelling patterns to new adjectives, using visual inspection of the final letters and oral rehearsal as checking strategies."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"37 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Grammar: three spelling patterns for -er comparatives: add -er / double consonant + -er / change -y to -i + er.","Spelling: apply letter-pattern knowledge (CVC doubling, y-to-i) to word formation.","Metacognition: look at the last two letters and decide which pattern before applying -er."],walt:["We are learning three patterns for adding -er to make a comparing word.","We are learning to look at the last two letters before deciding which pattern to use.","We are learning to check our comparative spelling aloud."],successCriteria:["I can add -er directly to adjectives like tall, fast, kind.","I can double the last consonant before -er in words like big, hot, sad.","I can change -y to -i before adding -er in words like happy, noisy, cloudy."],timing:[{time:"0-7m",title:"Three Patterns",phase:"I Do",description:"Teacher builds a three-column table on the board: just add -er / double + -er / -y to -i + -er. Shows 3 examples in each column. Say-aloud check demonstrated for each pattern."},{time:"7-14m",title:"Spot and Apply",phase:"We Do",description:"Whole class identifies the pattern for 3 adjectives and applies the right -er form. Three-column table stays on the board throughout."},{time:"14-22m",title:"My Comparative Spellings",phase:"You Do",description:"Students form the comparative of 3 adjectives using the right pattern. Pattern reference card available for all; bonus sentences for confident writers."},{time:"22-28m",title:"Check Aloud",phase:"Reflect",description:"Students read their comparative words aloud to a partner. Close: noticing letter patterns in words is a form of paying attention — the same careful attention we bring to noticing the world God made."}],resources:["Three-pattern comparative table (just add -er / double + -er / -y to -i + -er)","Adjective pattern reference card","Worksheet with 3 adjectives for comparative formation","Large lined paper for bonus task"],assessment:["Formative: accuracy of pattern identification and comparative formation","Work sample: 3 correctly formed comparatives","Focus: correct pattern selected; spelling accurate; say-aloud check used"],differentiation:[{label:"ESOL learners",note:"Three-column table stays visible throughout; oral rehearsal of each form; buddy pairing."},{label:"Emerging writers",note:"Focus on Pattern 1 only (just add -er) as a secure foundation; Patterns 2 and 3 as extension."},{label:"Confident writers",note:"Bonus: write 2 sentences, one using a doubled-consonant comparative and one using a -y to -i comparative."},{label:"Diverse learners",note:"Say-aloud check is multi-sensory and suits auditory learners; physical letter-manipulation with magnetic letters for kinaesthetic learners."}],valuesIntegration:{heading:"Mohio — Know",notes:["Noticing letter patterns in words is a form of Mohio — knowing and understanding the world at a detailed level. The same careful attention we bring to words is the attention we want to bring to knowing God and His story.","Taking care with spelling — getting comparative endings right — is also a form of respect for language and for our reader."]},reflectionPrompts:["Were students correctly identifying which pattern to apply?","Was doubling (Pattern 2) or -y to -i (Pattern 3) the harder pattern?","Did the say-aloud check help students self-correct?","Are students ready to learn superlatives (-est) as the natural extension of this lesson?"]},"Mohio"),

Wednesday:g("Writing a Comparison Sentence","Writing — Sentence Structure & Vocabulary (Practice), NZC Phase 1 (Yrs 0-3): students write fully formed comparison sentences that use a comparative adjective, 'than', and additional detail — combining this week's Monday and Tuesday learning with vocabulary and sentence-expansion skills from earlier in the term.",
{title:"I Do — A Comparison Sentence Has Three Parts",instruction:"A good comparison sentence has three parts: what is being compared, the comparing word (-er), and what it is being compared TO (using 'than'). Watch me build one step by step — then make it even better by adding detail.",example:"Basic: The kauri is **taller** than the ponga. Better: The ancient, towering kauri is **taller** than the delicate ponga that grows in its shade.",demonstration:"Step 1: Choose two things to compare — a kauri tree and a ponga fern. Step 2: Comparative adjective — 'taller'. Step 3: Add 'than' and the second thing. Basic sentence done. Step 4: Add vivid adjectives and a WHERE or WHEN phrase to make it richer: 'The ancient, towering kauri is **taller** than the delicate ponga that grows in its shade.'",tip:"Build your comparison in order: Thing 1 + [describing word] + is/are + comparative + than + Thing 2 + [extra detail]. Then read it aloud — does it sound complete and vivid?"},
{title:"We Do — Build a Comparison Together",instruction:"Let's build a full comparison sentence for each pair of things together. Start simple, then add detail.",sentences:["a **mountain** and a **hill** (compare their height)","a **cheetah** and a **tortoise** (compare their speed)","a **gentle** stream and a **raging** river (compare their sound or force)"],prompt:"What comparing word fits? Add 'than'. Now add a describing word or a WHERE phrase to make it more vivid."},
{title:"You Do — Your Turn",instruction:"Write a full comparison sentence for each pair. Use a comparative adjective, 'than', and at least one piece of extra detail.",tasks:["Compare a **kiwi** and an **eagle** (size or speed).","Compare a **sunny day** and a **stormy day** (brightness or warmth).","Compare your **school** and your **home** (size, noise, or busyness).","✦ Bonus: Write a KIND comparison sentence about two people you know — use a feeling or character word as the comparative!"]},
[{code:"Writing — Sentence Structure (Practice)",label:"Constructing full comparison sentences",detail:"NZC Phase 1: students write fully formed comparison sentences combining a comparative adjective, 'than', and additional descriptive detail — integrating this week's grammar with vocabulary and sentence-expansion learning from earlier in the term."},{code:"Writing — Vocabulary (Practice)",label:"Comparative adjectives with descriptive detail",detail:"NZC Phase 1: students enrich comparison sentences with descriptive detail (adjectives, WHERE/WHEN phrases, vivid verbs), applying the sentence-expansion strategies learned across the term to a new sentence type."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"38 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Sentence Structure: a comparison sentence follows the pattern: Thing 1 + comparative + than + Thing 2.","Vocabulary: enrich comparison sentences with adjectives, WHERE/WHEN phrases, and vivid verbs.","Writing Process: build a comparison sentence in steps: basic first, then add detail.","Metacognition: ask 'is this comparison fair and specific?' and 'can I add detail to make it richer?'"],walt:["We are learning to write a complete comparison sentence with a comparing word and 'than'.","We are learning to add detail to make our comparison sentence more vivid.","We are learning to compare things fairly and specifically."],successCriteria:["I can write a comparison sentence with a comparative adjective and 'than'.","I can add at least one piece of detail to enrich my comparison sentence.","My comparison is fair and specific — it actually compares two measurable or observable things."],timing:[{time:"0-7m",title:"Three-Part Build",phase:"I Do",description:"Teacher builds a comparison sentence in three visible steps on the board: (1) basic comparison, (2) add adjective to Thing 1, (3) add detail to Thing 2. Shows how each step makes the sentence richer."},{time:"7-14m",title:"Build Together",phase:"We Do",description:"Whole class builds 3 comparison sentences from pairs of things, starting basic and adding detail at each step. Comparative word bank and sentence pattern on display."},{time:"14-22m",title:"My Comparison Sentences",phase:"You Do",description:"Students write full comparison sentences for 3 pairs of things. Sentence frame for emerging writers; bonus kind character comparison for confident writers."},{time:"22-28m",title:"Read & Appreciate",phase:"Reflect",description:"Students read their best comparison sentence to a partner. Close: noticing differences between things — and describing them with care — is a way of appreciating the extraordinary variety of what God made."}],resources:["Three-step build model on board","Comparison sentence frame: 'The [adj] ___ is ___er than the [adj] ___.'","Comparative word bank","Large lined paper"],assessment:["Formative: completeness and richness of comparison sentences during shared practice","Work sample: 3 full comparison sentences","Focus: comparative adjective used correctly; 'than' present; at least one piece of detail added"],differentiation:[{label:"ESOL learners",note:"Image pairs for comparison; sentence frame on display; oral rehearsal of the full sentence before writing."},{label:"Emerging writers",note:"Sentence frame with blanks: 'The ___ is ___er than the ___.' Focus on basic comparison first."},{label:"Confident writers",note:"Bonus: write a kind character comparison using a feeling or character word as the comparative."},{label:"Diverse learners",note:"Physical comparison of real objects before writing; oral sentence construction with a buddy before writing independently."}],valuesIntegration:{heading:"Aroha — Love",notes:["The bonus task — writing a KIND comparison about two people — connects directly to Aroha. Comparing people can be hurtful or affirming depending on how we do it. Kind comparisons celebrate what is good, not what is lacking.","Noticing and appreciating differences between people and things reflects the Aroha we are called to show to God's world."]},reflectionPrompts:["Were students writing real comparisons or just using comparative adjectives without the 'than' structure?","Did students add meaningful detail, or default to very plain additions?","How was the bonus kind character comparison received? Any standout examples?","Are students integrating comparative sentences into their own independent writing?"]},"Aroha"),

Thursday:g("Fix-It — Comparing Word Accuracy","Writing — Grammar & Writing Process (Practice), NZC Phase 1 (Yrs 0-3): students identify and fix errors in comparative adjective usage — wrong spelling patterns, missing 'than', and confusion between plain and comparative adjective forms.",
{title:"I Do — Common Comparison Mistakes and How to Fix Them",instruction:"Comparison sentences have a few common mistakes. Watch me find and fix each one in this passage.",example:"The mountain is more taller than the hill. The eagle is more fast than the sparrow. The river is loudder than the stream. She is happyer than her friend.",demonstration:"Mistake 1: 'more taller' — we NEVER use 'more' AND '-er' together. It is just 'taller'. Mistake 2: 'more fast' — for short adjectives we use -er, not 'more': 'faster'. Mistake 3: 'loudder' — wrong doubling: 'loud' ends in two consonants (ld), so just add -er: 'louder'. Mistake 4: 'happyer' — wrong -y pattern: change y to i THEN add -er: 'happier'. Fixed: 'The mountain is taller than the hill. The eagle is faster than the sparrow. The river is louder than the stream. She is happier than her friend.'",tip:"Check: (1) No 'more' AND '-er' together. (2) Short adjectives use -er not 'more'. (3) CVC adjectives: double. (4) -y adjectives: change to -i then -er."},
{title:"We Do — Find and Fix Together",instruction:"Let's find and fix every comparative error in these sentences together.",sentences:["The sky is more bluer than the sea on a clear day.","She felt more happyer after helping her friend.","The river is loudder and more faster after the rain."],prompt:"What type of error is this — 'more + -er', wrong doubling, or wrong -y pattern? Fix it!"},
{title:"You Do — Your Turn",instruction:"Find and fix the comparative errors in each sentence. Write the corrected version.",tasks:["The kauri tree is more taller than the ponga.","My brother is more sadder today than yesterday.","The wind feels coldder near the mountain.","✦ Bonus: Write 3 correct comparison sentences about things in your school or community — check each one using the four-point list before you finish!"]},
[{code:"Writing — Grammar (Practice)",label:"Fixing comparative adjective errors",detail:"NZC Phase 1: students identify and correct the three most common comparative adjective errors: double marking (more + -er), wrong spelling pattern (doubling or -y conversion errors), and missing 'than' — building accuracy and self-editing skills."},{code:"Writing — Writing Process (Practice)",label:"Self-checking comparison sentences",detail:"NZC Phase 1: students apply a four-point check to comparison sentences (no more+-er / -er not more / correct doubling / correct -y to -i), extending the multi-item checking habit to include grammar accuracy as well as punctuation."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"39 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Grammar: avoid double marking (more + -er); apply correct spelling patterns for -er comparatives.","Writing Process: apply a grammar-focused check to comparison sentences alongside the punctuation checklist.","Metacognition: use the four-point comparison check as a self-editing strategy."],walt:["We are learning to spot and fix common mistakes in comparison sentences.","We are learning that we never use 'more' AND '-er' together.","We are learning to check our comparative spelling using the four-point list."],successCriteria:["I can spot when 'more' and '-er' are used together (and fix it).","I can fix an incorrectly spelled comparative adjective.","I can check a comparison sentence using the four-point list."],timing:[{time:"0-7m",title:"Common Mistakes",phase:"I Do",description:"Teacher presents the four common comparative errors on the board, with examples of each and the correct fix. Four-point check list displayed."},{time:"7-14m",title:"Find and Fix Together",phase:"We Do",description:"Whole class finds and fixes comparative errors in 3 sentences. Students identify the type of error before fixing it."},{time:"14-22m",title:"My Fix-It Comparisons",phase:"You Do",description:"Students fix comparative errors in 3 sentences independently. Four-point check list on display for all; bonus original sentences for confident writers."},{time:"22-28m",title:"Partner Check",phase:"Reflect",description:"Students swap sentences with a partner and apply the four-point check to each other's work. Close: checking our work carefully — especially for the tricky stuff — is a gift to our reader."}],resources:["Four-point comparison check list (no more+-er / -er for short adj / check doubling / check -y to -i)","Sentences with comparative errors on board or worksheet","Large lined paper for bonus task"],assessment:["Formative: accuracy of error identification and correction during shared practice","Work sample: 3 corrected sentences","Focus: all four error types identified and fixed correctly"],differentiation:[{label:"ESOL learners",note:"Error type cards (one per common mistake) to match with the sentence error; oral check after fixing."},{label:"Emerging writers",note:"Error type pre-identified in the sentence (underlined or labelled); student fixes only."},{label:"Confident writers",note:"Bonus: write 3 correct comparison sentences and apply the four-point check independently."},{label:"Diverse learners",note:"Say-aloud check for each correction — hearing 'louder' vs 'loudder' is the most natural way to catch doubling errors."}],valuesIntegration:{heading:"Manaaki — Serve",notes:["Checking our comparison sentences carefully — and helping a partner check theirs — is an act of Manaaki. We are giving our reader the gift of accurate, clear comparisons.","The partner check reminds us that we serve each other best when we give honest, kind attention to each other's work."]},reflectionPrompts:["Which error type was most common — double marking, wrong doubling, or wrong -y pattern?","Did students use the four-point check independently or still needed prompting?","Were students applying accurate comparative forms in their own free writing?","Is the class ready to learn superlatives (-est) as the natural Phase 2 next step?"]},"Manaaki"),

Friday:g("Quiz Day — Week 8 Review","Writing — Vocabulary, Grammar & Sentence Structure (Practice), NZC Phase 1 (Yrs 0-3): consolidate comparing words, the -er spelling patterns, full comparison sentences, and comparison accuracy through a team quiz.",
{title:"I Do — What We Learned This Week",instruction:"Before the quiz, let's quickly remind ourselves of the four things we worked on this week.",example:"**Comparing words** (taller, faster, kinder) · **-er spelling patterns** (just add / double / -y to -i) · **Full comparison sentences** · **Fixing comparison errors**",demonstration:"A great comparison sentence: 'The ancient kauri is taller than the delicate ponga that grows in its shade.' — comparative adjective (taller), 'than', vivid detail, correct -er spelling, no 'more + -er' error.",tip:"This week: -er + than = comparison. Three spelling patterns. Never 'more taller'. Check your spelling aloud."},
{title:"We Do — Quick Review Together",instruction:"Let's build one brilliant comparison sentence using everything from this week.",sentences:["The **wider**, **wilder** Waikato River is **faster** than the **gentle** stream that runs through our valley.","The **ancient** totara is **taller** than the **young** manuka that grew up beside it.","The **stormy** sea was **louder** and **darker** than the **calm** harbour we had left that morning."],prompt:"Can you find the comparative adjective, the 'than', the spelling pattern, and check for 'more + -er' errors?"},
{title:"You Do — Quiz Time!",instruction:"Time to show what you know! Good luck Team Tui and Team Kiwi!",tasks:["Listen carefully to each question.","Your team earns a point for each correct answer.","Be encouraging — cheer for great answers from both teams!","✦ Eight weeks in! You are becoming serious writers — be proud of how far you have come!"]},
[{code:"Writing — Vocabulary (Practice)",label:"Comparative adjectives in context",detail:"NZC Phase 1: students demonstrate knowledge of comparative adjective usage and formation in a quiz context."},{code:"Writing — Grammar (Practice)",label:"Comparative spelling patterns",detail:"NZC Phase 1: students identify and apply the three -er spelling patterns (direct / CVC doubling / -y to -i) in quiz questions."},{code:"Writing — Sentence Structure (Practice)",label:"Full comparison sentences",detail:"NZC Phase 1: students identify correctly and incorrectly formed comparison sentences in a quiz context."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"40 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"30-35 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Vocabulary: comparative adjectives as comparing tools.","Grammar: three -er spelling patterns; avoid double marking.","Sentence Structure: full comparison sentence pattern.","Writing Process: four-point comparison check.","Communication: team quiz with encouragement and sportsmanship."],walt:["We are learning to show what we know from the whole week.","We are learning to identify and apply comparative adjective patterns.","We are learning to be kind, encouraging team members."],successCriteria:["I can form comparative adjectives using the right spelling pattern.","I can identify errors in comparison sentences.","I can be an encouraging and kind team member."],timing:[{time:"0-5m",title:"Week 8 Review",phase:"I Do",description:"Quick recap of this week's four skills."},{time:"5-10m",title:"Quick Practice",phase:"We Do",description:"One example question as a class."},{time:"10-30m",title:"Team Quiz",phase:"You Do",description:"16 questions on comparing words, -er spelling patterns, full comparison sentences, and error correction."},{time:"30-35m",title:"Celebrate & Reflect",phase:"Reflect",description:"Final scores, applause for both teams. Eight weeks — what a journey!"}],resources:["Quiz questions on screen","Scoreboard"],assessment:["Formative: observe which question types the class finds hardest","Note: are -er spelling patterns secure? Plan for spiral revisit in Week 10."],differentiation:[{label:"ESOL learners",note:"Questions read aloud clearly; team conferral time."},{label:"All learners",note:"Team format; all contribute at their level."}],valuesIntegration:{heading:"All Four Values",notes:["Aroha: comparing things kindly — especially people — is a form of love.","Mohio: knowing how comparison works in language helps us describe and understand the world God made.","Manaaki: checking our comparisons carefully serves our reader with accuracy and care.","Panga: vivid, accurate comparisons make an impact — they help the reader see and feel the difference between two things."]},reflectionPrompts:["Which question types did the class find hardest?","Are -er spelling patterns secure enough for Phase 2 work?","How was team spirit? Only two weeks left in Term 1!"]},"Aroha")
};

const quiz8=[
{q:"What do COMPARING WORDS (comparative adjectives) do?",opts:["They name a thing","They tell us what something is like on its own","They measure one thing against another","They show the order of events"],ans:2,explanation:"Comparing words measure one thing against another — for example, 'The mountain is TALLER than the hill.' They show a difference in degree between two things, and they are almost always followed by 'than'."},
{q:"What word almost always comes AFTER a comparing word?",opts:["and","but","than","first"],ans:2,explanation:"'Than' almost always follows a comparative adjective: 'taller THAN', 'faster THAN', 'kinder THAN'. If you use a comparing word without 'than', the comparison is usually incomplete."},
{q:"What is the correct COMPARATIVE form of 'tall'?",opts:["more tall","taller","tallier","most tall"],ans:1,explanation:"'Taller' is correct — for short adjectives like 'tall', we just add -er. We NEVER say 'more taller' (that is double marking). 'Most tall' is a superlative, not a comparative."},
{q:"What is the correct COMPARATIVE form of 'big'?",opts:["biger","bigger","more big","bigier"],ans:1,explanation:"'Bigger' is correct — 'big' follows Pattern 2: it ends in one vowel + one consonant (CVC), so we double the final consonant before adding -er: biGGer. 'Biger' forgets to double, and 'more big' is wrong for short adjectives."},
{q:"What is the correct COMPARATIVE form of 'happy'?",opts:["happyer","more happy","happier","happyier"],ans:2,explanation:"'Happier' is correct — 'happy' follows Pattern 3: it ends in -y, so we change the y to i before adding -er: happi+er = happier. 'Happyer' forgets the y-to-i change."},
{q:"Which sentence uses a comparing word CORRECTLY?",opts:["The kauri is more taller than the ponga.","The kauri is tallest than the ponga.","The kauri is taller than the ponga.","The kauri is more tall than the ponga."],ans:2,explanation:"'The kauri is taller than the ponga.' is correct — 'taller' is the comparative form (just add -er) and 'than' follows it. 'More taller' and 'more tall' are wrong for short adjectives (double marking). 'Tallest' is a superlative."},
{q:"Which word is the COMPARATIVE ADJECTIVE in 'The falcon is faster than the sparrow.'?",opts:["falcon","faster","sparrow","than"],ans:1,explanation:"'Faster' is the comparative adjective — it is the comparing word that measures the falcon against the sparrow. 'Than' is the connector, and 'falcon' and 'sparrow' are the nouns being compared."},
{q:"What is the correct COMPARATIVE form of 'hot'?",opts:["hoter","hotter","more hot","hotier"],ans:1,explanation:"'Hotter' is correct — 'hot' follows Pattern 2: h-o-t ends in one vowel + one consonant (CVC), so we double the t before adding -er: hotTer. 'Hoter' forgets to double the consonant."},
{q:"What is the correct COMPARATIVE form of 'noisy'?",opts:["noisyer","more noisier","noisier","noisiyer"],ans:2,explanation:"'Noisier' is correct — 'noisy' follows Pattern 3: it ends in -y, so we change the y to i before adding -er: noisi+er = noisier. 'Noisyer' forgets the y-to-i change."},
{q:"Which sentence has a DOUBLE MARKING ERROR (more + -er used together)?",opts:["The river is louder than the stream.","The mountain is more higher than the hill.","The eagle is faster than the sparrow.","The sea is deeper than the lake."],ans:1,explanation:"'The mountain is more higher than the hill.' has a double marking error — it uses BOTH 'more' AND the -er ending ('higher'). We should use EITHER 'more' OR '-er', never both. The correct version is 'The mountain is higher than the hill.'"},
{q:"Which sentence is a COMPLETE and CORRECT comparison sentence?",opts:["The kauri is taller.","The kauri is taller the ponga.","The kauri is taller than the ponga.","The kauri is more tall than the ponga."],ans:2,explanation:"'The kauri is taller than the ponga.' is complete and correct — it has the comparative adjective ('taller'), the connector ('than'), and both things being compared. Missing 'than' or using 'more tall' both make it wrong."},
{q:"What is the correct COMPARATIVE form of 'sad'?",opts:["sader","sadder","more sad","sadier"],ans:1,explanation:"'Sadder' is correct — 'sad' follows Pattern 2: s-a-d ends in one vowel + one consonant (CVC), so we double the d before adding -er: sadDer. 'Sader' forgets to double."},
{q:"Which PATTERN does the adjective 'warm' follow to make its comparative?",opts:["Double the last consonant: warmmer","Change -y to -i: warmier","Just add -er: warmer","Use 'more': more warm"],ans:2,explanation:"'Warm' follows Pattern 1 — just add -er: warmer. 'Warm' ends in two consonants (r-m), so there is no doubling needed. 'Warmmer' incorrectly doubles the m, and 'more warm' is wrong for short adjectives."},
{q:"Which sentence adds the BEST DETAIL to enrich a comparison?",opts:["The river is louder than the stream.","The river is louder.","The roaring, wild river is louder than the gentle stream that trickles through the valley.","The river is more louder than the stream."],ans:2,explanation:"'The roaring, wild river is louder than the gentle stream that trickles through the valley.' is the richest — it has vivid adjectives (roaring, wild, gentle) and a WHERE phrase (that trickles through the valley) adding real detail. It also avoids 'more louder' (double marking)."},
{q:"What is the correct COMPARATIVE form of 'cloudy'?",opts:["cloudyer","cloudier","more cloudier","more cloudy"],ans:1,explanation:"'Cloudier' is correct — 'cloudy' follows Pattern 3: it ends in -y, so we change the y to i before adding -er: cloudi+er = cloudier. 'Cloudyer' forgets the y-to-i change, and 'more cloudier' is double marking."},
{q:"Which sentence uses EVERYTHING from Week 8 correctly — a comparative adjective, 'than', correct spelling, no double marking, and vivid detail?",opts:["The mountain is more taller.","The ancient kauri is taller than the young ponga growing in its shade.","The river is loudder than the stream.","She is more happier than her friend."],ans:1,explanation:"'The ancient kauri is taller than the young ponga growing in its shade.' is correct — 'taller' uses Pattern 1 (-er, no doubling needed), 'than' connects the comparison, no 'more' double marking, and 'ancient' and 'young' add vivid detail."}
];


/* ===== WEEK 9 ===== */
const week9={
Monday:g("Said Upgrade #2 — Shouted, Whispered, Sighed","Writing — Vocabulary (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students revisit and deepen the 'said' upgrade work from Week 3, expanding their bank of speech verbs into three feeling groups: loud/forceful, quiet/secretive, and heavy/sad.",
{title:"I Do — Said Upgrades: Three Feeling Groups",instruction:"In Week 3 we started upgrading 'said'. This week we go deeper — we learn speech verbs that belong to three different feeling groups: LOUD, QUIET, and HEAVY. Each group paints a different emotional picture for the reader.",example:"LOUD/FORCEFUL: **shouted**, **bellowed**, **commanded**, **insisted**, **snapped**. QUIET/SECRETIVE: **whispered**, **breathed**, **murmured**, **hissed**, **confided**. HEAVY/SAD: **sighed**, **groaned**, **sobbed**, **choked**, **admitted**.",demonstration:'"Said" appears in almost every story ever written — but it tells us almost nothing. "She whispered she was scared" — quiet, perhaps in the dark. "She sobbed she was scared" — the fear overwhelmed her. The same meaning, completely different emotional picture. The speech verb IS the emotion.',tip:"Before you choose a speech verb, ask: how LOUD was it? Was it emotional? Was it SECRET? The answer tells you which group to look in."},
{title:"We Do — Match the Speech Verb to the Moment",instruction:"Let's choose the right speech verb for each moment from our three feeling groups.",sentences:["The captain ___ the order to turn the ship. (loud and commanding)","The child ___ her prayer in the dark. (quiet and private)","He ___ that he had made a terrible mistake. (heavy and sad)"],prompt:"Which group fits — LOUD, QUIET, or HEAVY? Which specific verb captures the moment best?"},
{title:"You Do — Your Turn",instruction:"Replace 'said' with a speech verb from the right feeling group. Think carefully about how the character was feeling AND how loudly they spoke.",tasks:["My little brother **said** he was frightened of the dark. (quiet and scared)","The coach **said** we had to run faster. (loud and urgent)","She **said** she missed her grandmother. (heavy and longing)","✦ Bonus: Write your own sentence using a speech verb so specific and expressive that the reader knows both HOW and WHY the character spoke — without being told!"]},
[{code:"Writing — Vocabulary (Knowledge)",label:"Speech verb feeling groups",detail:"NZC Phase 1: students extend their bank of speech verbs into three distinct feeling groups (loud/forceful, quiet/secretive, heavy/sad), developing the understanding that speech verbs convey both manner and emotion simultaneously."},{code:"Writing — Vocabulary (Practice)",label:"Applying speech verbs with emotional precision",detail:"NZC Phase 1: students select speech verbs with emotional precision in sentence contexts, moving beyond mere replacement of 'said' to deliberate characterisation through speech verb choice."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"41 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Vocabulary: extend the speech verb bank into three feeling groups (loud/forceful, quiet/secretive, heavy/sad).","Vocabulary: understand that speech verbs convey both manner of speaking and emotional state simultaneously.","Communication: share said-upgrade sentences aloud with appropriate expression to test whether the verb fits.","Metacognition: ask 'how loud?' and 'what emotion?' before selecting a speech verb."],walt:["We are learning that speech verbs belong to different feeling groups.","We are learning to choose a speech verb that shows HOW and WHY a character spoke.","We are learning that the speech verb IS the emotion in a piece of dialogue."],successCriteria:["I can sort speech verbs into loud, quiet, and heavy groups.","I can match a speech verb to the emotional moment in a sentence.","My speech verb tells the reader both the manner and the emotion of how someone spoke."],timing:[{time:"0-7m",title:"Three Groups",phase:"I Do",description:"Teacher introduces the three groups on the board with examples. Class mimes each group as a physical memory anchor."},{time:"7-14m",title:"Match the Verb to the Moment",phase:"We Do",description:"Whole class matches 3 dramatic moments to speech verbs from the right group. Three-group bank on display."},{time:"14-22m",title:"My Speech Verbs",phase:"You Do",description:"Students replace 'said' with a speech verb from the right group in 3 sentences."},{time:"22-28m",title:"Read With Expression",phase:"Reflect",description:"Students read their sentence aloud with the expression the speech verb implies. Close: when we write with speech verbs this precisely, we give our characters real emotional life."}],resources:["Three-group speech verb bank (LOUD: shouted/bellowed/commanded; QUIET: whispered/murmured/confided; HEAVY: sighed/groaned/sobbed)","Worksheet with 3 sentences","Large lined paper for bonus task"],assessment:["Formative: accuracy of group matching and appropriateness of verb choice","Work sample: 3 sentences with emotionally precise speech verbs","Focus: speech verb from correct group; real emotional precision"],differentiation:[{label:"ESOL learners",note:"Three-group mime anchors; bank with facial expression images; buddy pairing."},{label:"Emerging writers",note:"Group pre-identified; student selects from a short list within the correct group."},{label:"Confident writers",note:"Bonus: write a sentence where the speech verb reveals character without any other description needed."},{label:"Diverse learners",note:"Read-aloud with expression in the reflect stage is inclusive and multi-sensory."}],valuesIntegration:{heading:"Aroha — Love",notes:["Choosing the right word for HOW a character spoke — especially when frightened, grieving, or longing — is an act of empathy. We are entering into how they felt. This is a form of Aroha.","The heavy group — sighed, groaned, admitted — connects to the Christian call to sit with people in their sorrow, not just their joy."]},reflectionPrompts:["Were students selecting verbs with real emotional precision or just picking a synonym at random?","Did the mime anchors help students grasp the three groups?","Which speech verbs were most unexpected or creative?","Are students using emotionally precise speech verbs in their own writing?"]},"Aroha"),

Tuesday:g("Speech Basics — Who Is Talking?","Writing — Grammar & Punctuation (Knowledge & Practice), NZC Phase 1 (Yrs 0-3): students learn the basic conventions for writing speech — speech marks around spoken words and a clear speech tag so the reader always knows WHO is talking.",
{title:"I Do — Making It Clear Who is Talking",instruction:"When we write what a character SAYS, the reader needs to know two things: WHAT they said (the spoken words) and WHO said it. Watch me show you the basic pattern.",example:'Aroha said, **"I love the mountains."** Her brother replied, **"Me too."** Their mother whispered, **"God made them for us to enjoy."**',demonstration:'The spoken words go inside SPEECH MARKS: **"like this"**. Then we say WHO spoke: Aroha said / Her brother replied / Their mother whispered. The speech verb comes between the name and the speech marks, followed by a COMMA. Pattern: Name + speech verb + COMMA + OPEN speech mark + spoken words + CLOSE speech mark.',tip:"Pattern: [Name] [speech verb], [COMMA] [OPEN SPEECH MARK] [spoken words] [CLOSE SPEECH MARK]. The comma comes BEFORE the speech marks open."},
{title:"We Do — Add the Speech Marks",instruction:"Let's add speech marks to each sentence so the reader can see exactly what was said.",sentences:["Mia said, I am so proud of you.","Dad whispered, God is always with us.","The teacher announced, Today we will write about something we love."],prompt:"Where do the speech marks open and close? What was actually spoken?"},
{title:"You Do — Your Turn",instruction:"Add speech marks to each sentence in the right place. Check: speech marks surround only the spoken words, not the name or speech verb.",tasks:["Noah said, I want to help.","She whispered, Be careful.","Grandma announced, Dinner is ready!","✦ Bonus: Write your own line of dialogue using a character's name, a speech verb from Monday's bank, and correct speech marks."]},
[{code:"Writing — Punctuation (Knowledge)",label:"Speech marks for direct speech",detail:"NZC Phase 1: students learn that speech marks surround the spoken words in direct speech, and that the pattern is: name + speech verb + comma + open speech mark + spoken words + close speech mark."},{code:"Writing — Grammar (Knowledge)",label:"The speech tag: name + speech verb",detail:"NZC Phase 1: students learn that every line of dialogue needs a speech tag — the name of the speaker and the speech verb — to make clear WHO is talking."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"42 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Punctuation: speech marks surround spoken words in direct speech.","Grammar: the speech tag (name + speech verb + comma) identifies who is speaking.","Sentence Structure: the basic dialogue line pattern.","Metacognition: ask 'what was actually spoken?' before placing speech marks."],walt:["We are learning that speech marks go around the spoken words.","We are learning that every line of dialogue tells us WHO is speaking.","We are learning the pattern: Name + speech verb + comma + speech marks + spoken words."],successCriteria:["I can identify the spoken words in a sentence.","I can place speech marks around the spoken words correctly.","I can write a basic speech tag (name + speech verb) before the speech marks."],timing:[{time:"0-7m",title:"The Dialogue Pattern",phase:"I Do",description:"Teacher writes a line of dialogue with and without speech marks, showing what changes. Uses a physical gesture: arms out wide = speech marks opening and closing."},{time:"7-14m",title:"Add the Speech Marks",phase:"We Do",description:"Whole class adds speech marks to 3 sentences, identifying the spoken words first."},{time:"14-22m",title:"My Speech Marks",phase:"You Do",description:"Students add speech marks to 3 sentences independently."},{time:"22-28m",title:"Share and Check",phase:"Reflect",description:"Students read their dialogue line to a partner using a different voice for the spoken words."}],resources:["Dialogue pattern on board","Speech mark gesture visual","Worksheet with 3 sentences","Large lined paper for bonus task"],assessment:["Formative: accuracy of speech mark placement","Work sample: 3 sentences with correctly placed speech marks","Focus: speech marks surround spoken words only; comma before open speech mark"],differentiation:[{label:"ESOL learners",note:"Physical arm gesture; dialogue pattern card; spoken words highlighted before adding marks."},{label:"Emerging writers",note:"Spoken words pre-underlined; student adds speech marks around underlined words only."},{label:"Confident writers",note:"Bonus: write an original dialogue line using a speech verb from Monday's bank."},{label:"Diverse learners",note:"Physical arm gesture is inclusive; speaking words in a different voice engages auditory learners."}],valuesIntegration:{heading:"Mohio — Know",notes:["Writing dialogue that makes clear WHO is speaking reflects the understanding that every individual voice matters — every person's words deserve to be heard and attributed correctly.","Learning to write speech accurately is also Mohio: knowing how language works, and using that knowledge to tell stories and truths more precisely."]},reflectionPrompts:["Were students correctly placing speech marks around the spoken words only?","Did students remember the comma before the speech marks open?","Were students using speech verbs from Monday's bank in their dialogue tags?","Is the class ready to write a two-line dialogue exchange next week?"]},"Mohio"),

Wednesday:g("Writing One Line of Dialogue","Writing — Sentence Structure & Punctuation (Practice), NZC Phase 1 (Yrs 0-3): students write a complete original line of dialogue combining a speech tag (name + precise speech verb), correct speech mark placement, and spoken words that fit the emotional moment.",
{title:"I Do — Building a Dialogue Line From Scratch",instruction:"Today we put everything together: a character, a speech verb from the right feeling group, correct speech marks, and spoken words that actually fit the moment. Watch me build a dialogue line step by step.",example:'Step 1 — who speaks and what emotion: Mia, feeling grateful. Step 2 — choose a speech verb: breathed (quiet/emotional). Step 3 — speech tag: Mia breathed, Step 4 — add speech marks and spoken words: Mia breathed, **"I am so thankful for this."**',demonstration:'The speech verb tells us HOW Mia spoke (quietly, emotionally). The spoken words tell us WHAT she said. The speech tag tells us WHO spoke. Together they create a complete picture of a moment.',tip:"Build it in order: WHO spoke + HOW they spoke (speech verb) + COMMA + OPEN speech mark + WHAT they said + CLOSE speech mark. Then read it aloud — does it sound right?"},
{title:"We Do — Build a Dialogue Line Together",instruction:"Let's build a complete dialogue line for each character and moment together.",sentences:["A child seeing the sea for the first time (wonder and joy)","A teacher correcting a student kindly (firm but gentle)","A grandparent sharing a memory of God's faithfulness (quiet and moved)"],prompt:"Who speaks? What emotion? Which speech verb fits? What do they say? Now put it all together with speech marks."},
{title:"You Do — Your Turn",instruction:"Write a complete, original line of dialogue for each moment. Include a speech tag, speech marks, and spoken words that fit the emotion.",tasks:["Someone who has just seen something beautiful in nature.","Someone who is gently encouraging a nervous friend.","Someone who is sharing something they are grateful to God for.","✦ Bonus: Write TWO connected lines of dialogue — two different characters responding to each other, each speech verb matching the character's emotion!"]},
[{code:"Writing — Sentence Structure (Practice)",label:"Writing complete dialogue lines",detail:"NZC Phase 1: students write original lines of dialogue combining a speech tag, speech marks, and spoken words — integrating Monday and Tuesday's learning into a complete piece of original writing."},{code:"Writing — Punctuation (Practice)",label:"Applying speech marks in original writing",detail:"NZC Phase 1: students apply speech mark conventions in original dialogue writing, moving from correcting given sentences to generating their own correctly punctuated dialogue."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"43 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Sentence Structure: write original complete dialogue lines using the speech tag + speech marks pattern.","Punctuation: apply speech mark conventions independently in original writing.","Vocabulary: integrate emotionally precise speech verbs into original dialogue.","Writing Process: build a dialogue line in four steps."],walt:["We are learning to write a complete original line of dialogue.","We are learning to choose a speech verb that matches the emotion of the moment.","We are learning to place speech marks correctly in our own writing."],successCriteria:["I can write an original speech tag (name + speech verb + comma).","I can place speech marks correctly around my spoken words.","My speech verb matches the emotion of the character in that moment."],timing:[{time:"0-7m",title:"Four-Step Build",phase:"I Do",description:"Teacher builds a dialogue line in four steps, thinking aloud at each stage."},{time:"7-14m",title:"Build Together",phase:"We Do",description:"Whole class builds 3 dialogue lines together, one step at a time."},{time:"14-22m",title:"My Dialogue Lines",phase:"You Do",description:"Students write 3 original dialogue lines independently."},{time:"22-28m",title:"Read and Perform",phase:"Reflect",description:"Students read one dialogue line to a partner — the partner reads the spoken words in character."}],resources:["Four-step dialogue model on board","Three-group speech verb bank","Large lined paper"],assessment:["Formative: completeness and emotional accuracy of dialogue lines","Work sample: 3 original dialogue lines","Focus: speech tag complete; speech marks correctly placed; speech verb emotionally appropriate"],differentiation:[{label:"ESOL learners",note:"Four-step model on display; speech verb bank with group images; oral rehearsal before writing."},{label:"Emerging writers",note:"Pre-written speech tag options to choose from; student adds spoken words and speech marks only."},{label:"Confident writers",note:"Bonus: write two connected dialogue lines with two different characters and emotionally precise speech verbs."},{label:"Diverse learners",note:"Partner reading-in-character is inclusive and engaging for auditory and dramatic learners."}],valuesIntegration:{heading:"Aroha — Love",notes:["Writing a character sharing gratitude to God — quietly, emotionally, specifically — is a beautiful intersection of faith and craft. It gives students a way to express their own faith through a character's voice.","Giving characters voices that are emotionally real and precise treats the character as worthy of specific, careful attention. This is Aroha."]},reflectionPrompts:["Were students choosing speech verbs with real emotional precision?","Were speech marks placed correctly in original writing?","Which dialogue lines were most evocative — worth sharing?","Are students ready to write a two-line dialogue exchange independently?"]},"Aroha"),

Thursday:g("Check — Capitals, Full Stops, and Dialogue","Writing — Writing Process & Punctuation (Practice), NZC Phase 1 (Yrs 0-3): students apply the full punctuation checklist to passages that include dialogue, adding speech mark accuracy and speech tag completeness to their established checking routine.",
{title:"I Do — Checking Dialogue for All the Details",instruction:"Dialogue adds new punctuation items to our full check. Watch me go through this passage and check everything — the usual five items PLUS speech marks and speech tags.",example:"mia said i love the mountains. her brother replied me too. their mother whispered god made them for us.",demonstration:'Running the full check: capital M for Mia. Capital I for the pronoun. Speech tag needs a comma: Mia said,. Spoken words need speech marks: "I love the mountains." Same for each line. Fixed: Mia said, "I love the mountains." Her brother replied, "Me too." Their mother whispered, "God made them for us."',tip:"For dialogue passages, check SEVEN things: (1) capitals at sentence starts, (2) full stops or ? at ends, (3) proper noun capitals, (4) question marks for questions, (5) correct plurals, (6) speech marks around spoken words, (7) comma after the speech tag."},
{title:"We Do — Full Check on These Dialogue Passages",instruction:"Let's read these passages together and fix everything — the full seven-item check including speech marks and speech tags.",sentences:["noah said i want to help the teacher. she replied that is very kind of you. he answered i will start right away.","aroha whispered look at the stars. her friend levi breathed i have never seen so many. aroha sighed god made every single one.","mrs patel announced we are going to write about our favourite place. the children cheered we love writing. she laughed i know you do."],prompt:"Work through the checklist one item at a time. Where are the speech marks needed? Are there commas after the speech tags?"},
{title:"You Do — Your Turn",instruction:"Fix each dialogue passage using the full seven-item checklist. Read aloud first, then fix one item at a time.",tasks:["mia said thank you for helping me. her mother replied i am always here for you. mia breathed i know mum.","the teacher announced today is a special day. noah asked what is special about it. the teacher grinned you will see.","god made the world said the child. it is so beautiful whispered her friend. they both smiled at the sea.","✦ Bonus: Write your own 3-line dialogue passage — then swap with a partner and apply the full seven-item check!"]},
[{code:"Writing — Punctuation (Practice)",label:"Seven-item check including dialogue punctuation",detail:"NZC Phase 1: students apply an extended comprehensive check that now includes speech mark placement and speech tag punctuation alongside the five established punctuation items."},{code:"Writing — Writing Process (Practice)",label:"Editing dialogue passages",detail:"NZC Phase 1: students edit short dialogue passages for the full range of punctuation errors, applying the checking habit to a new and more complex text type."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"44 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Punctuation: seven-item check including speech marks and comma after speech tag.","Writing Process: apply comprehensive editing to dialogue passages.","Metacognition: work through a mental checklist one item at a time for complex text."],walt:["We are learning to check a dialogue passage for speech marks and speech tag commas.","We are learning to apply our full seven-item punctuation checklist to dialogue writing.","We are learning to read dialogue aloud to hear where punctuation is needed."],successCriteria:["I can find and add missing speech marks in a dialogue passage.","I can find and add missing commas after speech tags.","I can apply the full seven-item checklist to a dialogue passage."],timing:[{time:"0-7m",title:"The Seven-Item Check",phase:"I Do",description:"Teacher adds Items 6 (speech marks) and 7 (comma after speech tag) to the five-item checklist. Models the full check on one dialogue passage."},{time:"7-14m",title:"Check Together",phase:"We Do",description:"Whole class reads 3 dialogue passages, working through all seven checklist items."},{time:"14-22m",title:"My Full Check",phase:"You Do",description:"Students fix 3 dialogue passages independently. Seven-item checklist card for all."},{time:"22-28m",title:"Partner Swap",phase:"Reflect",description:"Students swap passages and check each other's using the full seven-item list."}],resources:["Seven-item checklist card (capitals / full stops or ? / proper noun caps / question marks / correct plurals / speech marks / comma after speech tag)","Dialogue passages with multiple error types","Large lined paper for bonus task"],assessment:["Formative: accuracy of the seven-item check","Work sample: 3 corrected dialogue passages","Focus: speech marks correctly placed; comma after speech tag; all other items addressed"],differentiation:[{label:"ESOL learners",note:"Speech tags pre-underlined; seven-item checklist with icons; buddy support."},{label:"Emerging writers",note:"Focus on speech marks (Item 6) first; comma after speech tag (Item 7) as extension."},{label:"Confident writers",note:"Write own 3-line dialogue passage and swap with a partner for the full seven-item check."},{label:"Diverse learners",note:"Read-aloud of the dialogue passage helps auditory learners hear where punctuation is needed."}],valuesIntegration:{heading:"Manaaki — Serve",notes:["Taking such care with dialogue punctuation — making sure every character's voice is clearly marked and attributed — is a form of Manaaki. We are serving both our characters and our reader.","The partner swap in the reflect stage is a concrete act of serving one another with our attention and care."]},reflectionPrompts:["Were students correctly placing both speech marks AND the comma after the speech tag?","Which of the seven items was most commonly missed?","Did the partner swap produce helpful, specific feedback?","Is the class well-prepared for Week 10's comprehensive spiral review?"]},"Manaaki"),

Friday:g("Quiz Day — Week 9 Review","Writing — Vocabulary, Grammar, Punctuation & Sentence Structure (Practice), NZC Phase 1 (Yrs 0-3): consolidate speech verb feeling groups, speech mark conventions, original dialogue writing, and the full seven-item check through a team quiz.",
{title:"I Do — What We Learned This Week",instruction:"Before the quiz, let's quickly remind ourselves of the four things we worked on this week.",example:"**Speech verb groups** (loud/quiet/heavy) · **Speech marks** (around spoken words) · **Writing dialogue** · **Seven-item check**",demonstration:'A perfect dialogue line: Aroha breathed, "I have never seen so many stars." — quiet group, comma after speech tag, speech marks around spoken words, capital inside the marks, full stop before closing marks.',tip:"This week: LOUD, QUIET, or HEAVY group? Name + verb + COMMA + OPEN marks + words + CLOSE marks. Seven-item check on the way out."},
{title:"We Do — Quick Review Together",instruction:"Let's build one brilliant dialogue line using everything from this week.",sentences:['Mia **whispered**, **"God made every star in that sky."**','Noah **groaned**, **"I cannot believe how beautiful it is."**','Their teacher **announced**, **"Now write it down — every last detail."**'],prompt:"Can you find the speech verb group, the comma, the speech marks, and the capital inside the marks?"},
{title:"You Do — Quiz Time!",instruction:"Time to show what you know! Good luck Team Tui and Team Kiwi!",tasks:["Listen carefully to each question.","Your team earns a point for each correct answer.","Be encouraging — cheer for great answers from both teams!","✦ Nine weeks of hard work — you are nearly at the end of Term 1. Be incredibly proud!"]},
[{code:"Writing — Vocabulary (Practice)",label:"Speech verb groups in context",detail:"NZC Phase 1: students demonstrate knowledge of speech verb feeling groups in a quiz context."},{code:"Writing — Punctuation (Practice)",label:"Speech mark conventions",detail:"NZC Phase 1: students identify and apply correct speech mark placement and speech tag punctuation."},{code:"Writing — Sentence Structure (Practice)",label:"Complete dialogue lines",detail:"NZC Phase 1: students identify correctly and incorrectly formed dialogue lines in a quiz context."}],
{context:{unit:"Word Choice Foundations",lessonNumber:"45 of 40",yearGroup:"Years 3-4 (ages 7-9)",duration:"30-35 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Vocabulary: speech verb feeling groups.","Punctuation: speech mark conventions and comma after speech tag.","Sentence Structure: complete dialogue line pattern.","Writing Process: seven-item comprehensive check.","Communication: team quiz with encouragement and sportsmanship."],walt:["We are learning to show what we know from the whole week.","We are learning to identify speech verb groups and correct dialogue punctuation.","We are learning to be kind, encouraging team members."],successCriteria:["I can identify speech verb groups and correct dialogue punctuation.","I can spot errors in dialogue lines.","I can be an encouraging and kind team member."],timing:[{time:"0-5m",title:"Week 9 Review",phase:"I Do",description:"Quick recap of this week's four skills."},{time:"5-10m",title:"Quick Practice",phase:"We Do",description:"One example question as a class."},{time:"10-30m",title:"Team Quiz",phase:"You Do",description:"16 questions on speech verb groups, speech marks, dialogue line structure, and error checking."},{time:"30-35m",title:"Celebrate & Reflect",phase:"Reflect",description:"Final scores, applause for both teams. One week to go in Term 1!"}],resources:["Quiz questions on screen","Scoreboard"],assessment:["Formative: observe which question types the class finds hardest","Note: is speech mark placement secure? Plan for Week 10 spiral."],differentiation:[{label:"ESOL learners",note:"Questions read aloud clearly; team conferral time."},{label:"All learners",note:"Team format; all contribute at their level."}],valuesIntegration:{heading:"All Four Values",notes:["Aroha: speech verbs that carry emotion show we care about how people feel, not just what they say.","Mohio: knowing how dialogue works helps us tell God's story and our own with greater depth and clarity.","Manaaki: correct speech punctuation is a gift to our reader — it makes every character's voice clear and respected.","Panga: dialogue that carries emotional truth has real impact on our reader and on the stories we tell."]},reflectionPrompts:["Which question types did the class find hardest?","Is speech mark placement secure heading into Week 10?","How was team spirit with only one week of Term 1 left?"]},"Aroha")
};

const quiz9=[
{q:"Which speech verb belongs to the LOUD/FORCEFUL group?",opts:["whispered","sighed","bellowed","murmured"],ans:2,explanation:"'Bellowed' belongs to the loud/forceful group — it describes someone speaking very loudly, perhaps forcefully or with authority. 'Whispered' and 'murmured' are quiet, and 'sighed' is heavy/sad."},
{q:"Which speech verb belongs to the QUIET/SECRETIVE group?",opts:["shouted","groaned","confided","commanded"],ans:2,explanation:"'Confided' belongs to the quiet/secretive group — it means sharing something private or secret in a quiet, trusting way. 'Shouted' and 'commanded' are loud, and 'groaned' is heavy/sad."},
{q:"Which speech verb belongs to the HEAVY/SAD group?",opts:["announced","hissed","sobbed","insisted"],ans:2,explanation:"'Sobbed' belongs to the heavy/sad group — it describes someone speaking while crying, overwhelmed by emotion. 'Announced' and 'insisted' are more neutral/loud, and 'hissed' is secretive."},
{q:"Where do SPEECH MARKS go in a dialogue sentence?",opts:["Around the whole sentence","Around the speaker's name","Around the spoken words only","Before the speech tag"],ans:2,explanation:"Speech marks go around the SPOKEN WORDS only — the actual words the character says. For example: Mia said, \"I love the mountains.\" — only 'I love the mountains.' is inside the speech marks."},
{q:"Which dialogue sentence is punctuated CORRECTLY?",opts:["Mia said \"I love the mountains.\"","Mia said, I love the mountains.","Mia said, \"I love the mountains.\"","\"Mia said,\" I love the mountains."],ans:2,explanation:"'Mia said, \"I love the mountains.\"' is correct — the speech tag is followed by a comma, then speech marks open, the spoken words are inside the marks, and the marks close after the full stop."},
{q:"What punctuation comes AFTER the speech tag BEFORE the speech marks open?",opts:["A full stop","A question mark","A comma","Nothing"],ans:2,explanation:"A COMMA comes after the speech tag before the speech marks open: 'Mia said, \"...\"'. The comma signals that what follows is the spoken words."},
{q:"Which speech verb BEST fits this moment: a character sharing a secret quietly?",opts:["shouted","commanded","murmured","bellowed"],ans:2,explanation:"'Murmured' best fits sharing something quietly — it describes speaking very softly, almost under one's breath. 'Shouted', 'commanded', and 'bellowed' are all loud and forceful."},
{q:"Which dialogue sentence has a speech mark error?",opts:["Aroha whispered, \"Look at the stars.\"","Noah groaned, \"I am so tired.\"","Levi announced \"Today is a great day.\"","She confided, \"I have something to tell you.\""],ans:2,explanation:"'Levi announced \"Today is a great day.\"' is missing the comma after 'announced'. The correct version is: 'Levi announced, \"Today is a great day.\"'"},
{q:"What does a SPEECH TAG tell the reader?",opts:["What the character is thinking","Who is speaking and how they spoke","Where the character is","When the story happens"],ans:1,explanation:"A speech tag tells the reader WHO is speaking and HOW they spoke (through the speech verb). For example, in 'Mia whispered,' we know Mia is speaking and that she spoke quietly."},
{q:"Which sentence uses a speech verb from the correct FEELING GROUP for someone who is very sad?",opts:["The child shouted that she missed her grandmother.","The child commanded that she missed her grandmother.","The child sobbed that she missed her grandmother.","The child bellowed that she missed her grandmother."],ans:2,explanation:"'Sobbed' is from the heavy/sad group — it perfectly matches a child who is very sad. 'Shouted', 'commanded', and 'bellowed' are all loud/forceful, the wrong group for sadness."},
{q:"In 'Noah said, \"I want to help.\"' — what are the SPOKEN WORDS?",opts:["Noah said","I want to help.","Noah said, \"I want to help.\"","said,"],ans:1,explanation:"'I want to help.' are the spoken words — the actual words Noah said. The speech marks surround them. 'Noah said' is the speech tag, not the spoken words."},
{q:"Which dialogue sentence is COMPLETE and CORRECTLY punctuated?",opts:["whispered, \"Look at the sky.\"","Mia whispered Look at the sky.","Mia whispered, \"Look at the sky.\"","Mia, whispered \"Look at the sky.\""],ans:2,explanation:"'Mia whispered, \"Look at the sky.\"' is complete and correct — it has the speaker's name, the speech verb, a comma after the speech tag, speech marks around the spoken words, and a full stop before closing."},
{q:"What is the CORRECT ORDER for writing a dialogue line?",opts:["Speech marks + spoken words + speech tag","Spoken words + comma + speech tag","Name + speech verb + comma + speech marks + spoken words + speech marks","Speech marks + speech tag + spoken words"],ans:2,explanation:"The correct order is: Name + speech verb + comma + open speech mark + spoken words + close speech mark. For example: 'Aroha breathed, \"I am so grateful.\"'"},
{q:"Which speech verb BEST fits someone bravely acknowledging a mistake?",opts:["whispered","murmured","admitted","sobbed"],ans:2,explanation:"'Admitted' best fits someone bravely acknowledging a mistake — it belongs to the heavy/honest group, suggesting something difficult to say. 'Whispered' and 'murmured' are too quiet and secretive."},
{q:"How many items are on the FULL checking routine for a dialogue passage?",opts:["Four items","Five items","Six items","Seven items"],ans:3,explanation:"The full checking routine for dialogue passages has SEVEN items: (1) capitals at sentence starts, (2) full stops or ? at ends, (3) proper noun capitals, (4) question marks for questions, (5) correct plurals, (6) speech marks around spoken words, (7) comma after the speech tag."},
{q:"Which dialogue line uses EVERYTHING from Week 9 correctly?",opts:["Aroha said I love the mountains.","Aroha whispered \"I love the mountains.\"","Aroha breathed, \"I have never seen anything so beautiful.\"","Aroha, breathed \"I have never seen anything so beautiful.\""],ans:2,explanation:"'Aroha breathed, \"I have never seen anything so beautiful.\"' is perfect — 'breathed' is from the quiet/feeling group, there is a comma after the speech tag, speech marks surround only the spoken words, and the capital inside the marks is correct."}
];


/* ===== WEEK 10 — SPIRAL REVIEW & TERM 1 CELEBRATION ===== */
const week10={
Monday:g("Spiral Review — Term 1 Vocabulary","Writing — Vocabulary (Review & Practice), NZC Phase 1 (Yrs 0-3): students revisit and consolidate the full range of vocabulary skills learned in Term 1.",
{title:"I Do — Everything We Have Learned: Words",instruction:"In Term 1 we built five big word banks. Today we celebrate and revisit ALL of them. Watch me use one word from each bank in a single rich sentence.",example:"**Naming word**: mountain. **Describing word**: towering. **Movement word**: soared. **Feeling word**: overjoyed. **Said upgrade**: breathed. **Comparing word**: taller.",demonstration:"A rich sentence draws on many word types at once: 'The **towering**, **golden** mountain made me feel **overjoyed** — it is **taller** than any hill I have seen,' she **breathed**. Five vocabulary banks in one sentence!",tip:"Think: NAMING word? DESCRIBING word? MOVEMENT word? FEELING word? COMPARING word? SAID word? The richer your word choice, the more vivid your writing."},
{title:"We Do — One From Each Bank",instruction:"Let's build sentences together that draw on as many of our Term 1 vocabulary banks as possible.",sentences:["Write a sentence about a bird in flight — use a movement word AND a setting word.","Write a sentence about a character who is relieved — use a feeling word AND a said upgrade.","Write a sentence comparing two things in NZ nature — use a comparing word AND a describing word."],prompt:"Which bank does each word come from? Can you use TWO banks in one sentence? THREE?"},
{title:"You Do — Your Turn",instruction:"Write one sentence for each prompt, drawing on as many Term 1 vocabulary banks as you can.",tasks:["Describe a moment in nature using a movement word and a setting word.","Write about a character feeling grateful — use a feeling word and a said upgrade from the quiet group.","Compare two things you love using a comparing word and at least one describing word.","✦ Bonus: Write the most vocabulary-rich sentence you can — aim to use words from at least FOUR of our six Term 1 banks in a single sentence!"]},
[{code:"Writing — Vocabulary (Review)",label:"Consolidating Term 1 vocabulary banks",detail:"NZC Phase 1: students revisit and integrate the six vocabulary banks built across Term 1 in a celebratory spiral review session."},{code:"Writing — Vocabulary (Practice)",label:"Using multiple word types in rich sentences",detail:"NZC Phase 1: students practise drawing on multiple vocabulary banks simultaneously, building the habit of layered, vivid word choice expected in Phase 2."}],
{context:{unit:"Spiral Review — Term 1",lessonNumber:"Review 1 of 4",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Vocabulary: consolidate all six Term 1 vocabulary banks.","Vocabulary: practise drawing on multiple word banks simultaneously.","Communication: share rich sentences and celebrate vocabulary growth.","Metacognition: ask 'which vocabulary bank can I draw from here?' as a self-prompting strategy."],walt:["We are learning to bring together all the vocabulary we have built this term.","We are learning to use words from more than one vocabulary bank in a single sentence.","We are celebrating how far our word choices have come since Week 1."],successCriteria:["I can identify words from at least four of our six Term 1 vocabulary banks.","I can write a sentence that uses words from at least two different vocabulary banks.","I can celebrate how much my vocabulary has grown this term."],timing:[{time:"0-7m",title:"Six Banks — Quick Fire",phase:"I Do",description:"Teacher runs a quick-fire recall: holds up a category card and class shouts out a word from that bank. Builds six mini word lists on the board."},{time:"7-14m",title:"Build Together",phase:"We Do",description:"Whole class builds 3 vocabulary-rich sentences, deliberately drawing from multiple banks. Circle which bank each word comes from."},{time:"14-22m",title:"My Rich Sentences",phase:"You Do",description:"Students write 3 sentences drawing on multiple vocabulary banks. All six bank lists stay on the board."},{time:"22-28m",title:"Celebrate & Count",phase:"Reflect",description:"Students count how many different vocabulary banks they used. Share the most vocabulary-rich sentence."}],resources:["Six vocabulary bank category cards","Term 1 vocabulary word wall","Large lined paper"],assessment:["Formative: range and precision of vocabulary across the six banks","Work sample: 3 vocabulary-rich sentences","Focus: real use of multiple banks; precision and appropriateness"],differentiation:[{label:"ESOL learners",note:"Six bank word lists on display with images; oral rehearsal before writing; buddy pairing."},{label:"Emerging writers",note:"Focus on two banks per sentence as a secure target."},{label:"Confident writers",note:"Bonus: write a single sentence using words from at least four banks."},{label:"Diverse learners",note:"Quick-fire recall game is inclusive and energising."}],valuesIntegration:{heading:"All Four Values",notes:["Aroha: vocabulary built to love our reader better — feeling words, setting words, said upgrades — all serve to give the reader a vivid, honest picture.","Mohio: every word learned is a tool for knowing and describing God's world more precisely.","Manaaki: rich vocabulary is a gift to our reader.","Panga: vivid, precise language has impact — our words can change how a reader feels."]},reflectionPrompts:["Which vocabulary bank felt most secure? Which felt rustiest?","Which bank produced the most creative word choices?","Is there vocabulary from earlier in the term really incorporated into students' own writing?","What vocabulary highlights are worth adding to the class word wall?"]},"Mohio"),

Tuesday:g("Spiral Review — Grammar & Punctuation","Writing — Grammar & Punctuation (Review & Practice), NZC Phase 1 (Yrs 0-3): students revisit and consolidate the full range of grammar and punctuation skills from Term 1 in a fast-paced spiral review.",
{title:"I Do — Everything We Have Learned: Grammar & Punctuation",instruction:"Let me run through the seven punctuation items and the key grammar rules we have learned this term. Watch me apply them all to one passage.",example:"my friend lily asked me what was your favourite moment this term. i told her it was writing a dialogue line. she smiled and said mine too.",demonstration:'Seven-item check applied: capital M for My. Capital L for Lily (proper noun). The question needs a question mark. Capital I for pronoun. Past tense: told, smiled, said correct. Speech tags need commas. Speech marks around spoken words. Fixed: My friend Lily asked me, "What was your favourite moment this term?" I told her it was writing a dialogue line. She smiled and said, "Mine too."',tip:"Grammar quick-check: noun or pronoun? Past tense? Plural correct? Comparative right? Then seven punctuation items: capitals / full stops / proper nouns / question marks / plurals / speech marks / speech tag comma."},
{title:"We Do — Full Grammar & Punctuation Check",instruction:"Let's run the full grammar and punctuation check on these passages together.",sentences:["last tuesday mrs chen said lets write about what we love. the childrens all cheered. she whispered now write it down.","my brother is more taller than me but he run slower. i asked him why are you always so much more lazier","first we walked to the church. then aroha and i sat with our familys. finally we all prayed together."],prompt:"Check all seven punctuation items PLUS: past tense verbs, plural accuracy, comparative accuracy, pronoun use."},
{title:"You Do — Your Turn",instruction:"Apply the full grammar and punctuation review to each passage. Fix every error you can find.",tasks:["yesterday noah and i went to the librarys. he whispered look at all these books. i felt more happier than i had in days.","the teacher asked what is your favourite story. the childrens all said different answers. finally mia admitted it is hard to choose just one.","first god made the light. then he made the mountains and the seas. finally he looked at everything and breathed it is good.","✦ Bonus: Write a 3-sentence passage about a favourite moment from this term — check it using every grammar and punctuation rule we have learned!"]},
[{code:"Writing — Grammar (Review)",label:"Consolidating Term 1 grammar rules",detail:"NZC Phase 1: students revisit all Term 1 grammar knowledge in a spiral review context: nouns/proper nouns, pronouns, past tense -ed, plurals (-s/-es), comparative adjectives, question words, and dialogue speech tags."},{code:"Writing — Punctuation (Review)",label:"Consolidating the seven-item check",detail:"NZC Phase 1: students apply the full seven-item punctuation checklist to complex passages in a spiral review, demonstrating mastery of all punctuation skills learned across Term 1."}],
{context:{unit:"Spiral Review — Term 1",lessonNumber:"Review 2 of 4",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Grammar: consolidate nouns, pronouns, past tense, plurals, comparative adjectives, question words, dialogue speech tags.","Punctuation: apply the full seven-item check to complex passages.","Writing Process: demonstrate increasing independence in multi-item passage editing.","Metacognition: use a comprehensive mental checklist across both grammar and punctuation categories."],walt:["We are learning to apply everything we know about grammar and punctuation to a complex passage.","We are learning to work through our full checklist independently.","We are celebrating how much grammar and punctuation we have learned this term."],successCriteria:["I can identify and fix at least five different types of error in a passage.","I can apply the full seven-item punctuation check alongside grammar checks.","I can edit a complex passage independently using my full checklist."],timing:[{time:"0-7m",title:"Grammar & Punctuation Wall",phase:"I Do",description:"Teacher builds a quick term summary wall: all grammar rules and all seven punctuation items listed. Models applying them to one passage."},{time:"7-14m",title:"Full Check Together",phase:"We Do",description:"Whole class applies the full grammar and punctuation review to 3 complex passages."},{time:"14-22m",title:"My Full Review",phase:"You Do",description:"Students independently fix 3 complex passages. Full checklist card available."},{time:"22-28m",title:"Partner Check",phase:"Reflect",description:"Students swap passages and check each other's using the full checklist."}],resources:["Term 1 grammar and punctuation summary wall","Full seven-item checklist card plus grammar rules","Complex passages with multiple error types","Large lined paper"],assessment:["Formative: range and accuracy of error identification and correction","Work sample: 3 fully corrected complex passages","Focus: all grammar and punctuation item types addressed"],differentiation:[{label:"ESOL learners",note:"Summary wall stays on display; focus on 5 of the 9 item types; buddy support."},{label:"Emerging writers",note:"Errors pre-categorised; student fixes only."},{label:"Confident writers",note:"Write own 3-sentence passage with deliberate errors for a partner to find."},{label:"Diverse learners",note:"Read-aloud of the fixed passage confirms corrections."}],valuesIntegration:{heading:"Mohio — Know",notes:["Knowing how grammar and punctuation work is a form of Mohio. We are not just following rules; we are understanding the structure of language.","A thorough checking routine honours our reader: it says we care enough about them to get things right."]},reflectionPrompts:["Which grammar or punctuation items still showed weaknesses?","Were students editing with real independence?","What does this review session tell you about readiness for Phase 2 work in Term 2?"]},"Mohio"),

Wednesday:g("Spiral Review — Building & Joining Sentences","Writing — Sentence Structure (Review & Practice), NZC Phase 1 (Yrs 0-3): students revisit and consolidate all sentence-building skills from Term 1 in an integrated writing review.",
{title:"I Do — Everything We Have Learned: Sentences",instruction:"We have learned a lot about sentences this term. Let me show you how all those skills fit together in one rich, well-built piece of writing.",example:"**First**, at sunrise, the **tiny** bird **soared** above the **jagged** cliffs. **Then**, it **dipped** below the waves **but** quickly **rose** again. **Finally**, it **perched** on a **mossy** rock and **breathed**, 'This is where I belong.'",demonstration:"That piece uses: WHO + DID WHAT (bird/soared), WHERE phrase (above the jagged cliffs), WHEN phrase (at sunrise), sequencing words (First/Then/Finally), joining with 'but', setting words (mossy/jagged), movement words (soared/dipped/rose/perched), AND a dialogue line. Every sentence skill from Term 1 in one short paragraph.",tip:"When you write, you now have a whole toolkit: WHO did WHAT, plus WHERE, plus WHEN, joined with 'and' or 'but', ordered with sequencing words. Use as many tools as you can!"},
{title:"We Do — Build a Rich Sequence Together",instruction:"Let's build a 3-sentence sequence together that uses as many of our Term 1 sentence skills as possible.",sentences:["Sentence 1: FIRST + WHEN phrase + WHO + vivid verb + WHERE phrase","Sentence 2: THEN + WHO + did WHAT + joined with 'but' + contrasting idea","Sentence 3: FINALLY + dialogue line with speech tag + speech marks"],prompt:"Which sentence skill fits each slot? Can you combine WHERE and WHEN in the same sentence? Can you add a describing or feeling word too?"},
{title:"You Do — Your Turn",instruction:"Write a 3-sentence sequence about something from God's creation. Use as many Term 1 sentence skills as possible.",tasks:["Sentence 1: Use FIRST + a WHEN phrase + a vivid movement word.","Sentence 2: Use THEN + two ideas joined with 'and' or 'but'.","Sentence 3: Use FINALLY + a dialogue line with a speech tag and speech marks.","✦ Bonus: Add FOUR or more sentence skills to a single sentence — then read it aloud to check it still flows!"]},
[{code:"Writing — Sentence Structure (Review)",label:"Integrating all Term 1 sentence skills",detail:"NZC Phase 1: students integrate all sentence-building skills from Term 1 in a single piece of writing, demonstrating the capacity to combine multiple sentence-level tools simultaneously."},{code:"Writing — Text Structure (Review)",label:"Sequential text with rich sentence structure",detail:"NZC Phase 1: students write a three-sentence sequential text that integrates vocabulary, grammar, sentence structure, and punctuation skills from across Term 1."}],
{context:{unit:"Spiral Review — Term 1",lessonNumber:"Review 3 of 4",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Sentence Structure: integrate subject + verb, WHERE/WHEN phrases, conjunctions, sequencing connectives, and dialogue into a single piece.","Text Structure: write a three-sentence sequential text demonstrating mastery of Term 1 sentence skills.","Writing Process: plan before writing — what skill fits each sentence slot?","Metacognition: ask 'how many sentence skills can I fit in while keeping it fluent?'"],walt:["We are learning to combine all our sentence-building skills in one piece of writing.","We are learning to write a sequence that flows using all our Term 1 tools.","We are celebrating how far our sentence writing has come since Week 1."],successCriteria:["I can write a sentence with WHO + DID WHAT + WHERE + WHEN.","I can join two ideas with 'and' or 'but' in a sequence.","I can write a dialogue line with a speech tag and speech marks."],timing:[{time:"0-7m",title:"The Sentence Toolkit",phase:"I Do",description:"Teacher lists all Term 1 sentence tools on the board and shows how they all appear in a single 3-sentence model passage. Students count how many tools they can spot."},{time:"7-14m",title:"Build the Rich Sequence",phase:"We Do",description:"Whole class builds a 3-sentence sequence together, deliberately slotting a different sentence skill into each slot."},{time:"14-22m",title:"My Rich Sequence",phase:"You Do",description:"Students write an original 3-sentence sequence about creation, using as many sentence tools as possible."},{time:"22-28m",title:"Read, Count, Celebrate",phase:"Reflect",description:"Students read their sequence aloud and count the sentence skills they used. Share the most skill-rich sentence."}],resources:["Term 1 sentence skills summary list on board","Sentence slot guide for the writing task","Large lined paper"],assessment:["Formative: range of sentence skills integrated in student writing","Work sample: 3-sentence sequence","Focus: real integration of multiple skills; writing still flows when read aloud"],differentiation:[{label:"ESOL learners",note:"Sentence slot guide provides scaffold; oral rehearsal before writing; buddy pairing."},{label:"Emerging writers",note:"Three sentence frames provided; student chooses which skills to add."},{label:"Confident writers",note:"Bonus: write a single sentence integrating four or more sentence skills."},{label:"Diverse learners",note:"Read-aloud in the reflect stage reveals how well the integration works."}],valuesIntegration:{heading:"Panga — Impact",notes:["A sentence that uses multiple skills — vivid words, clear structure, honest emotion — makes a real impact on its reader. This is Panga: bringing something of God's kingdom into the world through craft.","Every skill we have learned this term is a tool for impact. Together, they add up to something powerful."]},reflectionPrompts:["Were students integrating skills fluently, or did the writing feel mechanical?","Which skill combinations produced the most vivid results?","Is the class ready to begin Phase 2 sentence work in Term 2?","What does this review session tell you about the class's overall writing development this term?"]},"Panga"),

Thursday:g("Spiral Review — Full Checking Routine","Writing — Writing Process (Review & Practice), NZC Phase 1 (Yrs 0-3): students apply the full integrated checking routine to complex passages drawing on all Term 1 grammar, punctuation, vocabulary, and sentence structure skills.",
{title:"I Do — The Full Term 1 Check",instruction:"Today is our biggest editing session of the term. We apply EVERYTHING: vocabulary precision, grammar accuracy, seven-item punctuation, AND flow. Watch me model the full routine on this passage.",example:"first aroha and i walked slowly to the mountain. then she said i have never saw anything so beautiful but the mountain is more taller than i thought. finally we both breathed god made this for us",demonstration:'Full four-stage check: (1) Vocabulary — any boring words to upgrade? (2) Grammar — past tense: "saw" should be "seen"; comparative: "more taller" should be "taller". (3) Punctuation: capital for Aroha, capital I for pronoun, speech tags need commas and speech marks, full stop at end. (4) Flow: reads well. Fixed passage displayed on board.',tip:"Final check order: (1) Vocabulary — any words to upgrade? (2) Grammar — past tense, plurals, pronouns, comparatives? (3) Seven punctuation items. (4) Flow — read aloud, does it flow?"},
{title:"We Do — The Full Term 1 Check Together",instruction:"Let's apply the full Term 1 review check to each passage. Look for vocabulary, grammar, punctuation, AND flow.",sentences:["yesterday noah and i went to the librarys. the building was more bigger than any place i had seen. noah whispered this is better than anything i have ever experienced.","first mrs lee asked us what is your favourite part of gods creation. the childrens all answered different things. finally she sighed you have all learned to see the world so beautifully this term.","at sunrise on saturday aroha and i walked to the churchs garden. she said look how the flowers has grown since last week. we both felt more happier than words could say."],prompt:"Check in order: vocabulary, grammar, all seven punctuation items, flow. What type is each error?"},
{title:"You Do — Your Turn",instruction:"Apply the full Term 1 check to each passage. This is your biggest editing task of the entire term.",tasks:["last friday the class celebrated what they had learned this term. mrs chen said i am so proud of you. the childrens all cheered and we felt more happier than ever.","first god made the light and he called it good. then he made the mountains and the seas and breathed they are beautiful. finally he made people and he sighed they are my greatest joy.","at sunset my friend levi whispered look at the stars. there was more stars than i could count. i breathed god made every single one of these.","✦ Bonus: Write your own 3-sentence passage about a favourite moment from this term — apply the full Term 1 check before you hand it in!"]},
[{code:"Writing — Writing Process (Review)",label:"Full integrated Term 1 checking routine",detail:"NZC Phase 1: students apply the full integrated checking routine — vocabulary, grammar, seven-item punctuation, and flow — to complex passages, demonstrating the comprehensive editing habit built across Term 1."},{code:"Writing — Grammar & Punctuation (Review)",label:"Identifying all Term 1 error types",detail:"NZC Phase 1: students identify and correct all Term 1 error types in complex passage editing."}],
{context:{unit:"Spiral Review — Term 1",lessonNumber:"Review 4 of 4",yearGroup:"Years 3-4 (ages 7-9)",duration:"25-30 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["Writing Process: apply the full integrated Term 1 checking routine (vocabulary + grammar + seven-item punctuation + flow).","Grammar: identify and correct all Term 1 grammar error types in complex passages.","Punctuation: apply the full seven-item checklist to the most complex passages of the term.","Metacognition: work through a four-stage checking process with increasing independence."],walt:["We are learning to apply our full Term 1 checking routine to a complex passage.","We are learning to check for vocabulary, grammar, punctuation, AND flow in one editing pass.","We are celebrating how much we have grown as editors this term."],successCriteria:["I can identify and fix errors from at least five different categories in a passage.","I can work through the four-stage checking process with increasing independence.","I can apply the full seven-item punctuation check alongside grammar and vocabulary checks."],timing:[{time:"0-7m",title:"The Four-Stage Check",phase:"I Do",description:"Teacher presents the four-stage checking order: (1) Vocabulary, (2) Grammar, (3) Seven-item punctuation, (4) Flow. Models all four stages on one complex passage."},{time:"7-14m",title:"Full Check Together",phase:"We Do",description:"Whole class applies the four-stage check to 3 complex passages, working through each stage systematically."},{time:"14-22m",title:"My Final Review Check",phase:"You Do",description:"Students apply the four-stage check to 3 passages independently."},{time:"22-28m",title:"Celebrate the Editors",phase:"Reflect",description:"Partner swap of the bonus final pieces. Celebrate: in Week 1, we checked for capitals and full stops. Now we check for FOURTEEN different things. That is growth."}],resources:["Four-stage checking order on board","Full term summary checklist card","Complex passages with multiple error types","Large lined paper for bonus final term piece"],assessment:["Formative: range and independence of error identification across all four checking stages","Work sample: 3 fully corrected complex passages plus bonus final piece","Focus: all four checking stages addressed; real independence in multi-item editing"],differentiation:[{label:"ESOL learners",note:"Four-stage check card with icons; focus on Stages 2-3 as a secure target; buddy support."},{label:"Emerging writers",note:"Errors pre-categorised by stage; student works through one stage at a time."},{label:"Confident writers",note:"Bonus final Term 1 piece: original writing plus full four-stage check applied independently."},{label:"Diverse learners",note:"Read-aloud for the flow check (Stage 4) is multi-sensory and inclusive."}],valuesIntegration:{heading:"Manaaki — Serve",notes:["The checking routine we have built this term is ultimately an act of Manaaki — serving our reader with the most accurate, vivid, and carefully crafted writing we can produce.","Checking fourteen things before we hand in our writing says: I care about the person who will read this. That is Manaaki in action."]},reflectionPrompts:["Were students working through all four checking stages or defaulting to punctuation only?","Which category of error was most persistently missed across the class?","What does the quality of this final review session tell you about Term 2 priorities?","How has the checking routine grown from Week 1 (capitals and full stops) to Week 10 (fourteen items)?"]},"Manaaki"),

Friday:g("End of Term 1 Celebration Quiz","Writing — All Skills (Review & Celebration), NZC Phase 1 (Yrs 0-3): students celebrate the completion of Term 1 with a Greatest Hits quiz covering all nine weeks of learning.",
{title:"I Do — Term 1: What We Have Learned",instruction:"Before the final quiz, let's celebrate everything we have learned in Term 1. This is the biggest quiz of the term — it covers ALL nine weeks.",example:"**Vocabulary** (naming, describing, movement, feeling, comparing, said upgrades) · **Grammar** (verbs, pronouns, plurals, past tense, comparatives, question words) · **Punctuation** (all seven items) · **Sentences** (WHO + WHERE + WHEN, joining, sequencing, dialogue)",demonstration:"In Week 1, we wrote: 'I saw a good dog.' By Week 9, we can write: 'At sunrise, the tiny dog bolted across the golden field but it stopped and breathed, \"This is where I belong.\"' That is one term of growth. That is YOUR growth.",tip:"This quiz covers all nine weeks. Take your time. Trust what you know. You have learned so much."},
{title:"We Do — Final Review Together",instruction:"Let's build one final sentence together that uses as many Term 1 skills as possible.",sentences:["**First**, at sunrise, the **tiny** bird **soared** above the **jagged** cliffs.","**Then**, it **dipped** below the waves **but** quickly **rose** again.","**Finally**, it **perched** on a **mossy** rock and **whispered**, 'This is where I belong.'"],prompt:"Count the skills: movement words, setting words, WHEN phrase, WHERE phrase, sequencing words, joining word, said upgrade, dialogue. How many can you find?"},
{title:"You Do — Quiz Time!",instruction:"Time for the Term 1 Greatest Hits Quiz! Good luck Team Tui and Team Kiwi!",tasks:["Listen carefully — these questions cover all nine weeks!","Your team earns a point for each correct answer.","Be encouraging — cheer for great answers from both teams!","✦ TEN WEEKS of incredible work! You are now Year 3-4 writers. Be incredibly proud!"]},
[{code:"Writing — All Skills (Review)",label:"Term 1 Greatest Hits — comprehensive review",detail:"NZC Phase 1: students demonstrate mastery of all Term 1 writing skills in a team quiz format."},{code:"Writing — Communication",label:"Team quiz with celebration",detail:"NZC Phase 1: students participate in a collaborative team celebration quiz that honours the community of learning built across Term 1."}],
{context:{unit:"Spiral Review — Term 1",lessonNumber:"Term 1 Final",yearGroup:"Years 3-4 (ages 7-9)",duration:"35-40 minutes",classSize:"~24 students",schoolType:"Christian school, mixed-level, incl. ESOL"},curriculumAlignment:["All Phase 1 (Years 0-3) Writing outcomes addressed across Term 1.","Communication: participate in a collaborative celebration honouring ten weeks of communal learning."],walt:["We are learning to show everything we know from Term 1.","We are celebrating ten weeks of hard work and real growth as writers.","We are ending the term with gratitude, joy, and pride in our community."],successCriteria:["I can answer questions from across all nine weeks of Term 1.","I can be a generous, encouraging team member in the final quiz.","I can celebrate what I have learned and how far I have come."],timing:[{time:"0-7m",title:"Term 1 Celebration Wall",phase:"I Do",description:"Teacher displays the full Term 1 skills list. Students see the full scope of what they have learned. A moment of real celebration before the quiz."},{time:"7-10m",title:"Final Review Question",phase:"We Do",description:"One practice question as a class, drawing on a skill from Week 1 to show how far the class has come."},{time:"10-38m",title:"Term 1 Greatest Hits Quiz",phase:"You Do",description:"16 questions drawn from all nine weeks of Term 1. Teams alternate. Full celebration energy."},{time:"38-42m",title:"Term 1 Finale",phase:"Reflect",description:"Final scores. Celebrate both teams. Ten weeks ago, we wrote plain sentences. Now we write vivid, correct, flowing prose. See you in Term 2."}],resources:["Quiz questions on screen","Scoreboard","Optional: Term 1 certificate for each student"],assessment:["Summative celebration: observe overall class performance across all nine weeks","Note: which content areas remain weakest? Use for Term 2 spiral planning.","This quiz is a celebration, not a formal assessment — keep it joyful."],differentiation:[{label:"ESOL learners",note:"Questions read aloud clearly; team conferral time."},{label:"All learners",note:"Team format; every student contributes; the celebration is for everyone."}],valuesIntegration:{heading:"All Four Values — Term 1 Celebration",notes:["Aroha: the care we have brought to our words — feeling words, setting words, said upgrades — is love for our reader and for the world we describe.","Mohio: knowing how language works, how sentences are built, how punctuation serves the reader — this is knowing our world more fully.","Manaaki: ten weeks of helping each other, checking each other's writing, cheering in the quizzes — this is serving one another faithfully with our gifts.","Panga: writing that is vivid, correct, and honest makes a real impact on its reader. Every sentence we write can change how someone sees the world."]},reflectionPrompts:["How did the class perform across the full Term 1 range?","Which areas showed the most growth from Week 1 to Week 10?","Which areas need the most attention in Term 2?","What will you carry into Term 2 as your key teaching priorities?","Which student growth stories from this term are worth celebrating?"]},"Mohio")
};

const quiz10=[
{q:"Which of these is a MOVEMENT WORD that shows fast, joyful movement?",opts:["trudged","whispered","bounded","sighed"],ans:2,explanation:"'Bounded' is a movement word showing fast, joyful, leaping movement — from Week 5. 'Trudged' is slow and heavy, 'whispered' is a speech verb, and 'sighed' is a feeling/speech verb."},
{q:"Which speech verb belongs to the QUIET/SECRETIVE group?",opts:["bellowed","commanded","confided","snapped"],ans:2,explanation:"'Confided' belongs to the quiet/secretive group — it means sharing something private and trusting. 'Bellowed', 'commanded', and 'snapped' all belong to the loud/forceful group."},
{q:"Which sentence uses a CORRECT comparative adjective?",opts:["The mountain is more taller than the hill.","The mountain is tallest than the hill.","The mountain is taller than the hill.","The mountain is more tall than the hill."],ans:2,explanation:"'The mountain is taller than the hill.' is correct — 'taller' is the comparative form (just add -er), followed by 'than'. 'More taller' and 'more tall' are double marking errors."},
{q:"Which pronoun CORRECTLY replaces 'the birds' in 'The birds sang all morning. ___ flew away at noon.'?",opts:["He","She","It","They"],ans:3,explanation:"'They' replaces 'the birds' — we use 'they' for more than one person or thing. 'He' and 'she' are for a single person, and 'it' is for a single thing or animal."},
{q:"Which sentence uses SEQUENCING WORDS in the correct order?",opts:["Finally I packed my bag. First I went to school. Then I said goodbye.","First I packed my bag. Then I went to school. Finally I said goodbye.","Then I went to school. First I packed my bag. Finally I said goodbye.","First I said goodbye. Finally I packed my bag. Then I went to school."],ans:1,explanation:"'First I packed my bag. Then I went to school. Finally I said goodbye.' is in the right order. FIRST starts, THEN continues, FINALLY ends."},
{q:"What is the correct PLURAL of 'church'?",opts:["churchs","churchies","churches","church's"],ans:2,explanation:"'Churches' is correct — 'church' ends in -ch, so it needs -es. The -es rule applies to words ending in -s, -sh, -ch, or -x."},
{q:"Which dialogue sentence is CORRECTLY punctuated?",opts:["Mia said \"I love the mountains.\"","Mia said, I love the mountains.","Mia said, \"I love the mountains.\"","\"Mia said,\" I love the mountains."],ans:2,explanation:"'Mia said, \"I love the mountains.\"' is correct — speech tag followed by a comma, speech marks open, spoken words inside, marks close after the full stop."},
{q:"Which sentence is written in the PAST TENSE?",opts:["I walk to school today.","I am walking to school.","I walked to school yesterday.","I will walk to school tomorrow."],ans:2,explanation:"'I walked to school yesterday' is past tense — 'walked' has -ed added. This is the -ed past tense pattern from Week 6."},
{q:"Which FEELING WORD shows the STRONGEST gratitude?",opts:["okay","glad","grateful","fine"],ans:2,explanation:"'Grateful' is the most specific and meaningful feeling word here — it describes a deep feeling of thankfulness. 'Okay' and 'fine' are actually less vivid than 'glad'!"},
{q:"Which sentence has a WHERE phrase AND a WHEN phrase?",opts:["The bird sang.","The bird sang in the morning.","At sunrise, the bird sang above the cliffs.","The bird sang and flew away."],ans:2,explanation:"'At sunrise, the bird sang above the cliffs.' has both: 'At sunrise' is a WHEN phrase and 'above the cliffs' is a WHERE phrase. Both used in the same sentence!"},
{q:"Which sentence CORRECTLY joins two contrasting ideas with 'but'?",opts:["The sun shone but the birds sang.","I tried to open the door but it was locked.","First I walked in but finally I sat down.","She felt happy but she also felt happy."],ans:1,explanation:"'I tried to open the door but it was locked.' is correct — the second part really contrasts with and surprises the first. 'But' connects contrasting or surprising ideas."},
{q:"Which passage has the CORRECT sequence order with past tense verbs?",opts:["Finally I helped him. Then I noticed he was sad. First I asked what was wrong.","First I noticed he was sad. Finally I asked what was wrong. Then I helped him.","First I noticed he was sad. Then I asked what was wrong. Finally I helped him.","Then I helped him. First I noticed he was sad. Finally I asked what was wrong."],ans:2,explanation:"'First I noticed he was sad. Then I asked what was wrong. Finally I helped him.' is correct — the right order and all verbs (noticed, asked, helped) are in the past tense."},
{q:"Which word is a VIVID SETTING WORD that describes SOUND?",opts:["golden","jagged","thundering","mossy"],ans:2,explanation:"'Thundering' is a sound word — it tells us what we can HEAR. 'Golden' is a light/colour word, 'jagged' and 'mossy' are texture words."},
{q:"What is the correct COMPARATIVE form of 'happy'?",opts:["happyer","more happy","happier","happyier"],ans:2,explanation:"'Happier' is correct — 'happy' follows Pattern 3: change the y to i before adding -er: happi+er = happier. 'Happyer' forgets the y-to-i change."},
{q:"Which question word asks about a REASON?",opts:["Who","Where","Why","What"],ans:2,explanation:"'Why' asks for a reason. Each of the six question words (who, what, where, when, why, how) asks for a different type of information."},
{q:"Which sentence uses the MOST skills from Term 1?",opts:["I was happy.","At sunrise, I felt overjoyed as Aroha breathed, \"God made this just for us.\"","The bird went and she said something.","first i walked and then i said i was good."],ans:1,explanation:"'At sunrise, I felt overjoyed as Aroha breathed, \"God made this just for us.\"' uses it all: WHEN phrase, precise feeling word, vivid speech verb in quiet group, correct speech marks, comma after speech tag, and capital inside the marks. A perfect Term 1 sentence!"}
];


