const TERM1={1:{data:week1,quiz:quiz1},2:{data:week2,quiz:quiz2},3:{data:week3,quiz:quiz3},4:{data:week4,quiz:quiz4},5:{data:week5,quiz:quiz5},6:{data:week6,quiz:quiz6},7:{data:week7,quiz:quiz7},8:{data:week8,quiz:quiz8},9:{data:week9,quiz:quiz9},10:{data:week10,quiz:quiz10}};
